/* AUTO-GENERATED — Missouri Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["MO"] = {"code":"MO","name":"Missouri","agency":"Missouri DOR","agencyShort":"DOR","handbook":"https://dor.mo.gov/driver-license/issuance/commercial/","links":{},"en":[{"q":"What is the maximum width, including load, allowed for a vehicle operated on Missouri highways without a special permit?","options":["96 inches","100 inches","102 inches","108 inches"],"answer":2,"explanation":"Under RSMo 304.170, no vehicle (including its load) may exceed 102 inches in width on Missouri highways, except for safety devices such as clearance lights and mirrors. Exceeding this requires a MoDOT oversize permit. Source: Missouri Revised Statutes 304.170; Missouri Driver Guide Chapter 15.","handbook":"","hbref":""},{"q":"On Missouri Interstate and designated highways, what is the maximum vehicle height, including load, permitted without a permit?","options":["13 feet 6 inches","14 feet","14 feet 6 inches","15 feet"],"answer":1,"explanation":"RSMo 304.170 sets the maximum height on Interstate and designated highways at 14 feet, including load. Source: Missouri Revised Statutes 304.170.","handbook":"","hbref":""},{"q":"On Missouri highways OTHER than the Interstate and designated routes, what is the general maximum vehicle height, including load?","options":["13 feet","13 feet 6 inches","14 feet","15 feet"],"answer":1,"explanation":"RSMo 304.170 limits height to 13 feet 6 inches on all highways other than the Interstate and designated highways. Vehicles transporting automobiles may reach 14 feet as an exception. Source: Missouri Revised Statutes 304.170.","handbook":"","hbref":""},{"q":"What is the maximum length, including load, of a single motor vehicle (such as a straight truck) operated on Missouri highways?","options":["40 feet","45 feet","48 feet","53 feet"],"answer":1,"explanation":"RSMo 304.170 limits a single motor vehicle, including load, to 45 feet in length. Longer combinations and semitrailers are governed by separate provisions. Source: Missouri Revised Statutes 304.170.","handbook":"","hbref":""},{"q":"What is the maximum semitrailer length allowed on the national network (Interstate and designated highways) in Missouri?","options":["48 feet","50 feet","53 feet","57 feet"],"answer":2,"explanation":"A semitrailer in a truck-tractor/semitrailer combination may be up to 53 feet long on the national network of Interstate and designated highways in Missouri, consistent with RSMo 304.170 and federal standards. Source: Missouri Revised Statutes 304.170; Missouri Driver Guide Chapter 15.","handbook":"","hbref":""},{"q":"What is the maximum gross weight allowed on Missouri highways without an overweight permit (absent a lower posted bridge limit)?","options":["73,280 pounds","76,000 pounds","80,000 pounds","84,000 pounds"],"answer":2,"explanation":"RSMo 304.180 caps gross weight at 80,000 pounds on Missouri highways, except where a bridge or structure is posted for less. This matches the federal Interstate limit. Source: Missouri Revised Statutes 304.180.","handbook":"","hbref":""},{"q":"What is the maximum weight allowed on a single axle on Missouri's Interstate system?","options":["18,000 pounds","20,000 pounds","22,000 pounds","24,000 pounds"],"answer":1,"explanation":"RSMo 304.180 and the federal standard limit any single axle to 20,000 pounds on the Interstate system. Source: Missouri Revised Statutes 304.180.","handbook":"","hbref":""},{"q":"What is the maximum weight allowed on a tandem axle group on Missouri's Interstate system?","options":["30,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"answer":1,"explanation":"RSMo 304.180 and the federal standard limit a tandem axle group to 34,000 pounds on the Interstate system. Source: Missouri Revised Statutes 304.180.","handbook":"","hbref":""},{"q":"Under Missouri law, how is a 'tandem axle' defined by the spacing between the axles?","options":["Axles 40 inches or less apart","Axles more than 40 inches but not more than 96 inches apart","Axles more than 96 inches but not more than 120 inches apart","Any two axles regardless of spacing"],"answer":1,"explanation":"RSMo 304.180 defines a tandem axle as two or more axles arranged one behind another whose extremes are more than 40 inches and not more than 96 inches apart. Source: Missouri Revised Statutes 304.180.","handbook":"","hbref":""},{"q":"On Missouri highways that are NOT part of the Interstate system, by how much may a vehicle exceed the single- and tandem-axle weight limits, provided gross weight still does not exceed 80,000 pounds?","options":["By up to 1,000 pounds","By up to 2,000 pounds","By up to 4,000 pounds","There is no tolerance"],"answer":1,"explanation":"RSMo 304.180 permits vehicles on non-Interstate highways to exceed single- and tandem-axle limits by up to 2,000 pounds, but total gross weight may not exceed 80,000 pounds. Source: Missouri Revised Statutes 304.180.","handbook":"","hbref":""},{"q":"On Missouri's Interstate and designated highways, the maximum legal weight for a vehicle is determined primarily by what?","options":["The Federal Bridge Formula and table","The number of tires on the ground","The vehicle's registered GVWR","The driver's CDL class"],"answer":0,"explanation":"Maximum weights on the Interstate and designated highways are governed by the Federal Bridge Formula and table, which relates allowable gross weight to the number of axles and the distance between them, with an overall cap of 80,000 pounds. Source: Missouri Revised Statutes 304.180; FHWA Federal Bridge Formula.","handbook":"","hbref":""},{"q":"The Federal Bridge Formula used in Missouri limits the allowable gross weight based on which two factors?","options":["Tire pressure and load type","Engine horsepower and axle count","The number of axles and the distance between them","Vehicle age and registered weight"],"answer":2,"explanation":"The Federal Bridge Formula (Bridge Formula B) sets allowable weight on any group of consecutive axles using the number of axles in the group and the spacing between the outer axles, protecting bridges from overstress. Missouri applies it under RSMo 304.180. Source: Missouri Revised Statutes 304.180; FHWA.","handbook":"","hbref":""},{"q":"When is a MoDOT oversize/overweight permit required to operate on Missouri highways?","options":["Only when traveling at night","When the vehicle and load exceed legal size or weight limits","Only for vehicles registered out of state","Whenever a vehicle weighs more than 26,001 pounds"],"answer":1,"explanation":"A MoDOT oversize/overweight permit is required whenever a vehicle and its load exceed Missouri's legal limits for width, height, length, or weight. Loads that can be reasonably dismantled to fit legal limits generally are not permitted. Source: Missouri DOT Motor Carrier Services / OSOW; RSMo 304.170-304.200.","handbook":"","hbref":""},{"q":"A standard MoDOT single-trip oversize/overweight permit is valid for how long?","options":["24 hours","Seven consecutive days","30 days","One year"],"answer":1,"explanation":"MoDOT single-trip oversize/overweight permits are valid for seven consecutive days. Annual (blanket) permits are available for qualifying continuous operations. Source: Missouri DOT Oversize/Overweight permit regulations.","handbook":"","hbref":""},{"q":"How is the basic MoDOT single-trip OVERWEIGHT permit fee calculated?","options":["A flat $50 regardless of weight","$15 plus $20 for each 10,000 pounds over the legal gross weight","$100 plus $5 per axle","$25 per mile traveled"],"answer":1,"explanation":"MoDOT charges a base single-trip permit fee of $15 plus $20 for each 10,000 pounds (or fraction) above the legal gross weight; very heavy moves add a bridge and roadway analysis fee. Source: Missouri DOT Oversize/Overweight permit fee schedule.","handbook":"","hbref":""},{"q":"For most oversize loads in Missouri, daytime travel is generally restricted to what time window?","options":["Midnight to noon only","One-half hour before sunrise to one-half hour after sunset","8:00 a.m. to 4:00 p.m. only","Any time, 24 hours a day"],"answer":1,"explanation":"Permitted oversize loads in Missouri may generally travel from one-half hour before sunrise to one-half hour after sunset; loads that are only overweight (legal size) may move continuously. Source: Missouri DOT Oversize/Overweight permit regulations.","handbook":"","hbref":""},{"q":"Under Missouri's agricultural weight variance, what is the maximum gross weight for a vehicle hauling milk from a farm or hauling livestock on highways OTHER than the Interstate system?","options":["80,000 pounds","82,000 pounds","85,500 pounds","90,000 pounds"],"answer":2,"explanation":"RSMo 304.180 allows a vehicle hauling milk from a farm to processing, or hauling livestock, to reach up to 85,500 pounds gross on highways other than the Interstate system. This does not apply on the Interstate. Source: Missouri Revised Statutes 304.180; Missouri Dept. of Agriculture.","handbook":"","hbref":""},{"q":"Under Missouri's harvest-season variance, vehicles hauling grain or grain co-products during harvest may exceed the normal weight limits on non-Interstate highways by what amount?","options":["5 percent","10 percent","15 percent","2,000 pounds flat"],"answer":1,"explanation":"RSMo 304.180 allows grain and grain co-product haulers during times of harvest to exceed the maximum weight limits by up to 10 percent on highways other than the Interstate system. Source: Missouri Revised Statutes 304.180; Missouri Dept. of Agriculture.","handbook":"","hbref":""},{"q":"A livestock or grain hauler using Missouri's increased-weight agricultural variance must observe which restriction?","options":["Must not use the Interstate system or cross a bridge posted below the load's weight","Must travel only at night","Must carry two flag persons at all times","May only operate within 25 miles of the farm"],"answer":0,"explanation":"Under RSMo 304.180, haulers using the increased agricultural weight allowance may not use any portion of the Interstate highway system and may not cross any bridge posted for less than the gross weight of the vehicle and load. Source: Missouri Revised Statutes 304.180; Missouri Dept. of Agriculture.","handbook":"","hbref":""},{"q":"What is the maximum front and rear overhang generally allowed for auto-transporters under Missouri size rules?","options":["2 feet front, 3 feet rear","3 feet front, 4 feet rear","4 feet front, 6 feet rear","No overhang is permitted"],"answer":1,"explanation":"Missouri size rules under RSMo 304.170 allow auto-transporters a front overhang of no greater than 3 feet and a rear overhang of no greater than 4 feet. Source: Missouri Revised Statutes 304.170.","handbook":"","hbref":""},{"q":"In Missouri, which CDL class is required to operate any combination of vehicles with a Gross Combination Weight Rating (GCWR) of 26,001 or more pounds, provided the vehicle(s) being towed has a GVWR in excess of 10,000 pounds?","options":["Class A","Class B","Class C","Class E"],"answer":0,"explanation":"Missouri defines Class A as any combination of vehicles with a GCWR of 26,001 or more pounds where the towed unit's GVWR exceeds 10,000 pounds. Source: Missouri Commercial Driver License Manual, Section 1 (CDL Classifications).","handbook":"","hbref":""},{"q":"Under Missouri rules, what is the maximum GVWR of a vehicle being towed before a single power unit rated at 26,001+ pounds GVWR requires a Class A (rather than Class B) CDL?","options":["8,000 pounds","10,000 pounds","15,000 pounds","26,001 pounds"],"answer":1,"explanation":"A Class B CDL covers a single vehicle of 26,001+ lbs GVWR towing a unit NOT in excess of 10,000 lbs GVWR; if the towed unit exceeds 10,000 lbs GVWR, a Class A is required. Source: Missouri Commercial Driver License Manual, Section 1.","handbook":"","hbref":""},{"q":"Per the Missouri CDL Manual, a Class C CDL applies only to a vehicle under 26,001 pounds GVWR when it is placarded for hazardous materials OR is designed to transport how many persons?","options":["9 or more persons, not including the driver","12 or more persons, including the driver","15 or more persons, not including the driver","16 or more persons, including the operator"],"answer":3,"explanation":"Missouri's Class C covers a single vehicle under 26,001 lbs GVWR that is placarded for hazardous materials or designed to transport 16 or more persons, including the operator. Source: Missouri Commercial Driver License Manual, Section 1.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a Missouri CDL for INTRASTATE driving only (within Missouri)?","options":["16 years old","18 years old","19 years old","21 years old"],"answer":1,"explanation":"Missouri CDL eligibility lists age 18 for intrastate operation (until age 21) and 21 for interstate operation. Source: Missouri Commercial Driver License Manual, 'Missouri CDL Eligibility.'","handbook":"","hbref":""},{"q":"A Missouri driver wants to operate a commercial vehicle across state lines (interstate commerce). What is the minimum age to hold a CDL for interstate operation?","options":["18 years old","19 years old","20 years old","21 years old"],"answer":3,"explanation":"Missouri requires a driver to be 21 to operate in interstate commerce; 18-to-20-year-old CDL holders are restricted to intrastate operation. Source: Missouri Commercial Driver License Manual, 'Missouri CDL Eligibility.'","handbook":"","hbref":""},{"q":"Before taking the CDL skills (road) test in Missouri, an applicant must have held a Commercial Learner's Permit (CLP) for a minimum of how long?","options":["7 days","14 days","30 days","60 days"],"answer":1,"explanation":"Federal and Missouri rules require the CLP to be held a minimum of 14 days before the skills test may be taken. Source: Missouri DOR CDL Permit Rule Overview; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"How long is a Missouri Commercial Learner's Permit (CLP) valid, and can it be renewed?","options":["180 days, renewable once","360 days, non-renewable","1 year, renewable annually","2 years, non-renewable"],"answer":1,"explanation":"A Missouri CLP is issued for 360 days and is non-renewable; if it expires, the applicant must retake the required knowledge tests. Source: Missouri DOR CDL Permit Rule Overview.","handbook":"","hbref":""},{"q":"Which endorsement is required in Missouri to drive a commercial vehicle designed to carry 16 or more people, including the driver?","options":["S (School Bus) endorsement","P (Passenger) endorsement","N (Tanker) endorsement","T (Doubles/Triples) endorsement"],"answer":1,"explanation":"The P (Passenger) endorsement is required for vehicles designed to carry 16 or more people including the driver; it requires a knowledge test and a skills test in a passenger vehicle. Source: Missouri Commercial Driver License Manual, Endorsements section.","handbook":"","hbref":""},{"q":"In Missouri, the Tank Vehicle (N) endorsement is required for a vehicle transporting liquid or gas in a tank having an individual rated capacity of more than 119 gallons and an aggregate rated capacity of what amount?","options":["500 gallons or more","750 gallons or more","1,000 gallons or more","1,500 gallons or more"],"answer":2,"explanation":"The N endorsement applies to tanks with an individual rated capacity of more than 119 gallons and an aggregate rated capacity of 1,000 gallons or more. Source: Missouri Commercial Driver License Manual, Endorsements section; 49 CFR 383.5.","handbook":"","hbref":""},{"q":"Which endorsement do Class A drivers in Missouri need before they may pull double or triple trailers?","options":["N (Tanker) endorsement","T (Doubles/Triples) endorsement","X (Combination) endorsement","H (Hazardous Materials) endorsement"],"answer":1,"explanation":"The T (Doubles/Triples) endorsement requires passing a special knowledge examination; it applies to Class A drivers who wish to pull multiple trailers. Source: Missouri Commercial Driver License Manual, Endorsements section.","handbook":"","hbref":""},{"q":"Which of the following endorsements may NOT be added to a Missouri Commercial Learner's Permit (CLP)?","options":["P (Passenger)","S (School Bus)","N (Tanker)","T (Doubles/Triples)"],"answer":3,"explanation":"The only endorsements that may be added to a Missouri CLP are P (Passenger), S (School Bus), and N (Tanker). H, X, and T are prohibited on a CLP. Source: Missouri Commercial Driver License Manual; 49 CFR 383.153(b); Section 302.700, RSMo.","handbook":"","hbref":""},{"q":"Before the Hazardous Materials (H) endorsement can be added to a Missouri CDL, the applicant must pass the written test AND receive approval of what?","options":["A TSA security threat assessment (background check)","A vision specialist's waiver","A Missouri employer sponsorship letter","A DOT roadside inspection clearance"],"answer":0,"explanation":"In addition to the 30-question HazMat written test, applicants must complete fingerprinting and receive approval of a TSA security threat assessment before the H (or X) endorsement is added. Source: Missouri DOR HazMat Endorsement Requirements; 49 CFR 1572.","handbook":"","hbref":""},{"q":"A Missouri CDL carrying a Hazardous Materials (H or X) endorsement will expire no more than how many years after the TSA security threat assessment was completed?","options":["2 years","4 years","5 years","8 years"],"answer":2,"explanation":"Because the TSA background check is valid for five years, a CDL with an H or X endorsement expires no more than 5 years after the security threat assessment was completed. Source: Missouri DOR HazMat Endorsement / HME FAQs; 49 CFR 1572.","handbook":"","hbref":""},{"q":"In Missouri, the School Bus (S) endorsement requires which additional endorsement to also be obtained?","options":["N (Tanker) endorsement","P (Passenger) endorsement","H (Hazardous Materials) endorsement","T (Doubles/Triples) endorsement"],"answer":1,"explanation":"Under federal and Missouri rules, the School Bus (S) endorsement requires the Passenger (P) endorsement; the applicant must pass the school bus knowledge test and a skills test in a school bus. Source: Missouri Commercial Driver License Manual; 49 CFR 383.93.","handbook":"","hbref":""},{"q":"Before taking the CDL skills test in Missouri (effective February 7, 2022), an applicant must complete Entry-Level Driver Training (ELDT) from a provider listed where?","options":["The Missouri State Highway Patrol approved-school list","The FMCSA Training Provider Registry","The Missouri Department of Revenue vendor list","Any private CDL school of the applicant's choice"],"answer":1,"explanation":"ELDT must be completed through a provider listed on FMCSA's Training Provider Registry before the skills test for an initial CDL or certain endorsements. Source: Missouri DOR Commercial Drivers page; 49 CFR Part 380.","handbook":"","hbref":""},{"q":"When self-certifying medical status for a Missouri CDL, how many possible categories must a driver choose from?","options":["2 categories","3 categories","4 categories","6 categories"],"answer":2,"explanation":"Drivers self-certify into one of four categories: non-excepted interstate, excepted interstate, non-excepted intrastate, or excepted intrastate. Source: Missouri Commercial Driver License Manual, Medical Self-Certification; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"A Missouri CDL applicant who certifies as 'non-excepted interstate' must also do what?","options":["Provide and maintain a valid medical examiner's certificate (DOT medical card)","Submit a Missouri-only intrastate medical waiver","Provide nothing further; the certification alone is sufficient","Obtain an annual vision test from a Missouri optometrist"],"answer":0,"explanation":"A driver self-certifying as non-excepted interstate is subject to federal medical standards and must submit and keep current a valid medical examiner's certificate, or risk being downgraded. Source: Missouri Commercial Driver License Manual, Self-Certification; 49 CFR 391.41.","handbook":"","hbref":""},{"q":"To establish Missouri domicile when applying for a CDL, how many documents verifying the applicant's residence address are required?","options":["One document","Two documents","Three documents","No documents if a prior license exists"],"answer":1,"explanation":"Missouri requires two acceptable documents demonstrating Missouri residency/domicile, in addition to proof of identity, Social Security number, and lawful presence. Source: Missouri DOR Commercial Drivers page; Missouri CDL Manual, Eligibility.","handbook":"","hbref":""},{"q":"Which lawful-presence status does Missouri require of a CDL applicant?","options":["Any valid visa holder regardless of status","U.S. citizen or lawful permanent resident","U.S. citizen only","Any applicant with a Social Security number"],"answer":1,"explanation":"Missouri requires CDL applicants to be a U.S. citizen or a non-U.S. citizen with lawful permanent resident status. Source: Missouri DOR Commercial Drivers page; Missouri CDL Manual, Eligibility.","handbook":"","hbref":""},{"q":"What is the minimum passing score on each Missouri CDL knowledge (written) examination?","options":["70%","75%","80%","85%"],"answer":2,"explanation":"Missouri requires a score of 80% on each CDL written examination, administered at Highway Patrol testing locations (e.g., 50-question General Knowledge, 30-question HazMat, 20-question endorsement tests). Source: Missouri Commercial Driver License Manual, Section 14 (CDL Written Examinations).","handbook":"","hbref":""},{"q":"In Missouri, what is the maximum blood alcohol concentration (BAC) a driver may have while operating a commercial motor vehicle (CMV) before it is considered a major offense?","options":["0.04%","0.08%","0.02%","0.10%"],"answer":0,"explanation":"Missouri prohibits operating a CMV with a BAC of 0.04% or higher (half the 0.08% limit for non-commercial drivers). Source: Missouri DOR Form 5231, 'Commercial Motor Vehicle Operators and the Law'; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under Missouri's implied consent law, what happens if a CDL holder refuses to submit to a chemical (blood/breath) test when lawfully requested?","options":["The CDL is disqualified for 1 year, the same as a first DWI","Only a $500 fine with no disqualification","A 60-day CDL disqualification","No penalty because refusal cannot be used as evidence"],"answer":0,"explanation":"Refusing a blood and/or breath test as a CDL holder or while operating a CMV is treated as a major offense and results in a 1-year CDL disqualification, the same as a first DWI conviction. Source: Missouri DOR Form 5231; Missouri implied consent law (Chapter 577 RSMo); 49 CFR 383.51.","handbook":"","hbref":""},{"q":"How long is a CDL disqualified for a FIRST major offense (such as DWI in a CMV) when NOT transporting hazardous materials?","options":["1 year","3 years","60 days","Lifetime"],"answer":0,"explanation":"A first major offense, including driving under the influence, refusing a test, or leaving the scene of an accident, results in a 1-year CDL disqualification in Missouri. Source: Missouri DOR Form 5231; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A driver commits a first major offense while operating a vehicle that is placarded for hazardous materials. What is the disqualification period?","options":["3 years","1 year","5 years","Lifetime"],"answer":0,"explanation":"A first major offense committed while transporting placarded hazardous materials carries a 3-year CDL disqualification, instead of the standard 1 year. Source: Missouri DOR Form 5231; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the consequence of a SECOND major offense (for example, a second DWI) on a Missouri CDL?","options":["Lifetime disqualification","3-year disqualification","10-year disqualification","1-year disqualification"],"answer":0,"explanation":"A second conviction for any of the listed major offenses results in a lifetime CDL disqualification in Missouri (some drivers may be eligible for reinstatement after 10 years under federal guidelines). Source: Missouri DOR Form 5231; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"How many serious traffic violations within a 3-year period result in a 60-day CDL disqualification?","options":["2","3","4","1"],"answer":0,"explanation":"Two serious traffic convictions within three years (in a CMV) result in a 60-day CDL disqualification. Source: Missouri DOR Form 5231; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"How many serious traffic violations within 3 years lead to a 120-day CDL disqualification?","options":["3 or more","2","5 or more","4 or more"],"answer":0,"explanation":"Three or more serious traffic convictions within three years result in a 120-day CDL disqualification. Source: Missouri DOR Form 5231; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Which of the following is classified as a 'serious traffic violation' for a Missouri CDL holder?","options":["Speeding 15 mph or more over the posted limit","Speeding 5 mph over the posted limit","A parking violation","An equipment lighting violation"],"answer":0,"explanation":"Serious traffic violations include speeding 15 mph or more above the limit, reckless driving, improper or erratic lane changes, and following too closely. Minor speeding and parking violations are not 'serious.' Source: Missouri DOR Form 5231; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the disqualification period for a driver's FIRST railroad-highway grade crossing violation?","options":["60 days","30 days","120 days","1 year"],"answer":0,"explanation":"A first railroad-highway grade crossing violation results in a minimum 60-day CDL disqualification. Source: Missouri DOR Form 5231; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A CDL holder commits a SECOND railroad-highway grade crossing violation within 3 years. What is the disqualification period?","options":["120 days","60 days","1 year","180 days"],"answer":0,"explanation":"A second railroad-highway grade crossing violation within three years results in a minimum 120-day disqualification. Source: Missouri DOR Form 5231; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the disqualification period for a THIRD railroad-highway grade crossing violation within a 3-year period?","options":["1 year","120 days","180 days","60 days"],"answer":0,"explanation":"A third or subsequent railroad-highway grade crossing violation within three years results in a minimum 1-year disqualification. Source: Missouri DOR Form 5231; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Besides disqualification, what civil penalty range may a driver face for violating an out-of-service order?","options":["$1,000 to $2,500","$100 to $500","$250 to $750","$5,000 to $10,000"],"answer":0,"explanation":"A driver who violates an out-of-service order is subject to a civil penalty of not less than $1,000 and not more than $2,500, in addition to disqualification. Source: 49 CFR 383.53; Missouri DOR Form 5231.","handbook":"","hbref":""},{"q":"Under RSMo 304.822, what is the fine for a FIRST violation of the hands-free / texting prohibition?","options":["$150","$50","$250","$500"],"answer":0,"explanation":"Under Missouri's Siddens Bening Hands Free Law, the fine is $150 for a first violation, $250 for a second, and $500 for a third within a defined period. Source: Section 304.822 RSMo.","handbook":"","hbref":""},{"q":"A CDL holder is convicted of using a CMV to commit a felony involving the manufacture or distribution of a controlled substance. What is the disqualification?","options":["Lifetime disqualification with no reinstatement","1-year disqualification","3-year disqualification","10-year disqualification"],"answer":0,"explanation":"Using a CMV in the commission of a felony involving manufacturing, distributing, or dispensing a controlled substance results in a lifetime disqualification with no possibility of reinstatement. Source: Missouri DOR Form 5231; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Which of the following is a major offense that triggers a 1-year CDL disqualification on a first conviction?","options":["Leaving the scene of an accident involving a CMV","Following too closely","An improper lane change","Speeding 15 mph over the limit"],"answer":0,"explanation":"Leaving the scene of an accident involving a CMV is a major offense (1-year first-offense disqualification). Following too closely, improper lane changes, and 15+ mph speeding are 'serious' violations, not major offenses. Source: Missouri DOR Form 5231; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A driver causes a fatality through the negligent operation of a CMV (for example, vehicular manslaughter). How is this classified for CDL purposes?","options":["A major offense carrying a 1-year first-offense disqualification","A serious traffic violation carrying 60 days","A railroad-crossing violation carrying 120 days","An out-of-service violation carrying 90 days"],"answer":0,"explanation":"Causing a fatality through the negligent or criminal operation of a CMV is a major offense, resulting in a 1-year disqualification on a first conviction (3 years if hazmat-placarded; lifetime on a second major offense). Source: Missouri DOR Form 5231; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"On a Missouri rural interstate or freeway, what is the maximum posted speed limit that applies to a commercial motor vehicle (truck) where no lower limit is posted?","options":["70 mph","65 mph","60 mph","55 mph"],"answer":0,"explanation":"Missouri sets the maximum speed on rural interstates and freeways at 70 mph, and there is no separate, lower statewide truck speed limit, so trucks may run the same 70 mph unless a lower speed is posted. Source: RSMo 304.010.","handbook":"","hbref":""},{"q":"Under Missouri law, on which roadways are trucks registered for a gross weight of more than 48,000 pounds prohibited from driving in the far left-hand lane?","options":["Any two-lane state highway with a posted limit of 55 mph or higher","All rural interstates with two or more lanes in each direction","Any divided highway anywhere in the state regardless of number of lanes","Interstates, freeways, or expressways within urbanized areas having three or more lanes in the same direction"],"answer":3,"explanation":"Missouri bars trucks registered for more than 48,000 pounds gross weight from the far left-hand lane on interstate highways, freeways, or expressways within urbanized areas that have three or more lanes proceeding in the same direction. Source: RSMo 304.015.","handbook":"","hbref":""},{"q":"In Missouri, on a highway with two or more lanes of traffic proceeding in the same direction, where must a vehicle generally be driven?","options":["In whichever lane has the least traffic at the time","In the right-hand lane, except when passing, preparing for a left turn, or directed otherwise by signs/markings","In the left-hand lane to keep the right lane clear for entering traffic","In the center lane on any road having three lanes in the same direction"],"answer":1,"explanation":"Missouri requires all vehicles to be driven in the right-hand lane on highways with two or more lanes in the same direction, except when overtaking and passing, preparing for a proper left turn, or otherwise directed by traffic markings, signs, or signals. Source: RSMo 304.015.","handbook":"","hbref":""},{"q":"A bus or placarded hazardous-materials vehicle approaching a railroad crossing in Missouri must stop at what distance from the nearest rail?","options":["Within 100 feet but not less than 25 feet","Within 75 feet but not less than 10 feet","Within 50 feet but not less than 15 feet","Within 25 feet but not less than 5 feet"],"answer":2,"explanation":"Buses and placarded HazMat vehicles must stop within 50 feet but not less than 15 feet from the nearest rail, then look and listen before crossing. Source: Missouri CDL Manual; 49 CFR 392.10.","handbook":"","hbref":""},{"q":"On a Missouri highway, the driver of a vehicle meeting or overtaking a stopped school bus that is displaying its signal to stop must do what?","options":["Stop the vehicle before reaching the bus, whether traveling toward or behind the bus","Stop only if traveling in the same direction as the bus","Slow to 10 mph and pass with caution without stopping","Stop only if children are visibly present at the roadside"],"answer":0,"explanation":"Missouri requires a driver meeting or overtaking a school bus from either direction that is stopped and signaling to stop the vehicle before reaching the bus. The exception is for separate roadways or opposing traffic on four-or-more-lane highways. Source: RSMo 304.050.","handbook":"","hbref":""},{"q":"Which Missouri exception lets a driver NOT stop for a school bus loading or unloading children?","options":["The driver is traveling fewer than 25 mph at the time","The bus has its amber (yellow) lights flashing but not its red lights","The driver is more than 100 feet from the bus when it stops","The bus is on a different roadway, or is going the opposite direction on a highway with four or more lanes of traffic"],"answer":3,"explanation":"A driver on a highway with separate roadways need not stop for a school bus on a different roadway, or one proceeding in the opposite direction on a highway containing four or more lanes of traffic. Source: RSMo 304.050.","handbook":"","hbref":""},{"q":"Under Missouri's Move Over law, when a driver approaches a stationary emergency, tow, utility, or MoDOT vehicle displaying warning lights on a road with at least four lanes (two or more in the same direction), the driver should first do what?","options":["Come to a complete stop until the stationary vehicle departs","Make a lane change into a lane not adjacent to the stationary vehicle, if it can be done safely","Sound the horn continuously while passing the stationary vehicle","Pull onto the right shoulder and wait for an all-clear signal"],"answer":1,"explanation":"Missouri's Move Over law requires a driver, where the roadway has at least four lanes with two or more in the same direction, to change into a lane not adjacent to the stationary vehicle when it can be done safely. Source: RSMo 304.022.","handbook":"","hbref":""},{"q":"Under Missouri's Move Over law, if changing lanes away from a stationary emergency/utility vehicle is unsafe or impossible, the driver must do what instead?","options":["Stop completely in the current lane until traffic clears","Maintain the posted speed limit and continue straight ahead","Proceed with due caution and reduce speed, maintaining a safe speed for road conditions","Activate hazard flashers and accelerate quickly past the scene"],"answer":2,"explanation":"When a lane change cannot be made safely, Missouri requires the driver to proceed with due caution and reduce the vehicle's speed, maintaining a safe speed for road conditions. Source: RSMo 304.022.","handbook":"","hbref":""},{"q":"A Missouri commercial driver must carry warning devices for use when stopped on the highway. What does the standard requirement consist of?","options":["Three reflective triangles","Two reflective triangles and three flares","Four reflective triangles","One reflective triangle and two flags"],"answer":0,"explanation":"A CMV must be equipped with three reflective triangles (or approved equivalents) to deploy when stopped on or beside the roadway. Source: Missouri CDL Manual; 49 CFR 393.95 / 392.22.","handbook":"","hbref":""},{"q":"When a Missouri commercial vehicle is stopped on a divided or one-way roadway, where should the three warning triangles be placed?","options":["All three at 10 feet directly behind the vehicle","One 10 feet behind, one 100 feet behind, and one 100 feet in front","About 25, 50, and 100 feet behind the vehicle","About 10, 100, and 200 feet behind the vehicle, toward approaching traffic"],"answer":3,"explanation":"On a divided or one-way road, all three triangles are placed toward approaching traffic at about 10 feet, 100 feet, and 200 feet behind the stopped CMV. Source: Missouri CDL Manual; 49 CFR 392.22.","handbook":"","hbref":""},{"q":"When a Missouri commercial vehicle is stopped on a two-lane, two-way undivided road, where should the warning triangles be placed?","options":["One about 10 feet behind, one about 200 feet behind, and one about 200 feet in front","One about 10 feet behind, one about 100 feet behind, and one about 100 feet in front of the vehicle","All three behind the vehicle at 10, 100, and 200 feet","One on each side of the vehicle and one directly behind it"],"answer":1,"explanation":"On a two-lane, two-way road the driver places one triangle within 10 feet of the rear, one about 100 feet behind, and one about 100 feet ahead of the vehicle. Source: Missouri CDL Manual; 49 CFR 392.22.","handbook":"","hbref":""},{"q":"On a Missouri rural expressway (not an interstate or freeway), what is the maximum speed limit?","options":["70 mph","60 mph","65 mph","55 mph"],"answer":2,"explanation":"Missouri sets the maximum speed on rural expressways at 65 mph, below the 70 mph allowed on rural interstates and freeways. Source: RSMo 304.010.","handbook":"","hbref":""},{"q":"What is the maximum speed limit on a Missouri interstate, freeway, or expressway located within an urbanized area?","options":["60 mph","65 mph","70 mph","55 mph"],"answer":0,"explanation":"Within urbanized areas, Missouri caps interstates, freeways, and expressways at 60 mph unless a lower limit is posted. Source: RSMo 304.010.","handbook":"","hbref":""},{"q":"Which railroad crossing does NOT require a Missouri bus or placarded HazMat CMV to make the mandatory stop?","options":["Any crossing in a rural area with no flashing lights","Any crossing that has a crossbuck but no gate","Any crossing on a road posted below 45 mph","A streetcar crossing or industrial-switching track within a business district, or a crossing marked with an 'Exempt' sign"],"answer":3,"explanation":"The mandatory stop does not apply at streetcar crossings or industrial-switching tracks within a business district, abandoned crossings marked as such, or crossings marked with an authorized 'Exempt' sign. Source: Missouri CDL Manual; 49 CFR 392.10.","handbook":"","hbref":""},{"q":"What is the maximum legal vehicle width, including load, on Missouri highways before an oversize permit is required?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"answer":1,"explanation":"Missouri limits vehicle width, including load, to 102 inches (8 feet 6 inches); exceeding this requires an oversize permit. Source: RSMo 304.170; MoDOT Motor Carrier Services.","handbook":"","hbref":""},{"q":"What is the maximum legal vehicle height, including load, on the Missouri interstate highway system before an oversize permit is required?","options":["13 feet 6 inches","15 feet","14 feet","16 feet"],"answer":2,"explanation":"Missouri limits height, including load, to 14 feet on the interstate highway system (15 feet on certain other roads); over that requires a permit. Source: RSMo 304.170; MoDOT.","handbook":"","hbref":""},{"q":"Absent an overweight permit, what is the maximum gross vehicle weight generally allowed on Missouri's interstate highways?","options":["80,000 pounds","73,280 pounds","88,000 pounds","90,000 pounds"],"answer":0,"explanation":"Missouri follows the federal limit of 80,000 pounds maximum gross weight on the interstate system without an overweight permit. Source: MoDOT Oversize/Overweight regulations; RSMo Chapter 304.","handbook":"","hbref":""},{"q":"When may an oversize load generally be moved on Missouri highways under a standard single-trip permit?","options":["Only between midnight and 6:00 a.m.","At any hour of the day or night without restriction","Only on weekends and state holidays","From one-half hour before sunrise to one-half hour after sunset"],"answer":3,"explanation":"MoDOT generally restricts oversize-load movement to the period from one-half hour before sunrise to one-half hour after sunset, with added holiday and weekend restrictions. Source: MoDOT Oversize/Overweight permit regulations.","handbook":"","hbref":""},{"q":"What is the maximum length of a semitrailer operated on Missouri highways without a permit?","options":["48 feet","53 feet","57 feet","60 feet"],"answer":1,"explanation":"Missouri limits a semitrailer to 53 feet in length on the highway system before a permit is required. Source: RSMo 304.170.","handbook":"","hbref":""},{"q":"A Missouri school bus is required to be plainly visible to approaching drivers for what distance on a highway with no shoulder and a speed limit over 60 mph, so that traffic can stop?","options":["At least 300 feet in each direction","At least 200 feet in each direction","At least 500 feet in each direction","At least 1,000 feet in each direction"],"answer":2,"explanation":"On a highway with no shoulder and a speed limit greater than 60 mph, a stopping school bus must be plainly visible for at least 500 feet in each direction (300 feet on other highways). Source: RSMo 304.050.","handbook":"","hbref":""},{"q":"Which Missouri agency actually issues the Commercial Driver License (CDL) document?","options":["The Missouri Department of Revenue (DOR)","The Missouri State Highway Patrol","The Missouri Department of Transportation (MoDOT)","The Federal Motor Carrier Safety Administration (FMCSA)"],"answer":0,"explanation":"In Missouri the Department of Revenue (DOR) issues all driver licenses, including the CDL, while the Missouri State Highway Patrol administers the tests. Source: Missouri DOR Commercial Drivers page (dor.mo.gov/driver-license/issuance/commercial/).","handbook":"","hbref":""},{"q":"In Missouri, who administers the CDL knowledge (written) and skills tests?","options":["The Missouri State Highway Patrol","The Missouri Department of Revenue license offices","Private FMCSA-registered training providers","The Missouri Department of Transportation"],"answer":0,"explanation":"The Missouri State Highway Patrol conducts CDL written knowledge testing at its Driver Examination Stations and the skills test (by appointment) at designated CDL test sites; the DOR then issues the license. Source: Missouri DOR Commercial Drivers page and Missouri CDL Manual.","handbook":"","hbref":""},{"q":"For how long is a Missouri Commercial Learner's Permit (CLP) valid, and can it be renewed?","options":["360 days, and it is non-renewable","180 days, and it may be renewed once","1 year, and it may be renewed for a second year","2 years, matching the federal maximum"],"answer":0,"explanation":"Missouri issues the CLP for a period of 360 days and it is non-renewable; if it expires, the applicant must complete all required knowledge testing again. Source: Missouri DOR CDL Permit Rule Overview (dor.mo.gov/driver-license/issuance/commercial/cdl-permit.html).","handbook":"","hbref":""},{"q":"How long must a Missouri applicant hold a Commercial Learner's Permit before being eligible to take the CDL skills test?","options":["A minimum of 14 days","A minimum of 30 days","A minimum of 10 days","A minimum of 60 days"],"answer":0,"explanation":"Applicants for a CDL must hold a CLP for a minimum of 14 days before completing skills testing for a full CDL. Source: Missouri DOR CDL Permit Rule Overview and the federal CLP rule (49 CFR 383.25).","handbook":"","hbref":""},{"q":"Which training must a Missouri applicant complete BEFORE taking the skills test for a first-time Class A or Class B CDL?","options":["Entry-Level Driver Training (ELDT) from an FMCSA Training Provider Registry provider","A state-approved defensive-driving course at a DOR office","A Missouri State Highway Patrol classroom safety seminar","An employer-run on-the-job orientation only"],"answer":0,"explanation":"Before the CDL skills test (and for certain new endorsements), Missouri applicants must complete Entry-Level Driver Training (ELDT) from a provider listed on FMCSA's Training Provider Registry, in effect since February 7, 2022. Source: Missouri DOR Commercial Drivers page; FMCSA ELDT rule (49 CFR Part 380).","handbook":"","hbref":""},{"q":"The Missouri CDL skills test is made up of which three parts, in order?","options":["Vehicle (pre-trip) inspection, basic vehicle control, and on-road driving","Written knowledge, air-brake check, and on-road driving","Basic vehicle control, hazardous-materials check, and on-road driving","Vehicle inspection, knowledge re-test, and a defensive-driving evaluation"],"answer":0,"explanation":"Missouri's modernized CDL skills test has three components: the vehicle (pre-trip) inspection, the basic vehicle control skills test, and the on-road driving test. Source: Missouri CDL Manual and Missouri DOR Commercial Drivers page.","handbook":"","hbref":""},{"q":"What are the four self-certification categories a Missouri CDL applicant must choose from?","options":["Non-excepted interstate, excepted interstate, non-excepted intrastate, and excepted intrastate","Interstate, intrastate, regional, and local","Commercial, agricultural, emergency, and government","Class A, Class B, Class C, and hazmat"],"answer":0,"explanation":"Missouri CDL applicants must self-certify to one of four categories: non-excepted interstate (NI), excepted interstate (EI), non-excepted intrastate (NA), and excepted intrastate (EA). Source: Missouri DOR CDL Medical Certification Requirements page.","handbook":"","hbref":""},{"q":"Which self-certification category in Missouri requires the driver to be qualified under 49 CFR Part 391 and carry a DOT medical examiner's certificate?","options":["Non-excepted interstate (NI)","Excepted interstate (EI)","Excepted intrastate (EA)","Excepted interstate emergency (EE)"],"answer":0,"explanation":"A non-excepted interstate (NI) driver operates in interstate commerce, is subject to 49 CFR Part 391, and must obtain and maintain a DOT medical examiner's certificate. Excepted categories are not subject to that federal medical-certificate requirement. Source: Missouri DOR CDL Medical Certification page.","handbook":"","hbref":""},{"q":"How does the medical examiner's certificate information generally reach the Missouri Department of Revenue for a CDL holder's record?","options":["It is transmitted electronically from the National Registry of Certified Medical Examiners","The driver must always mail an original paper card to MoDOT","The driver's employer files it with the Highway Patrol","It is uploaded only through a third-party HAZMAT vendor"],"answer":0,"explanation":"Missouri receives electronically transmitted medical examiner certificate information from the National Registry of Certified Medical Examiners, so drivers must use a certified examiner on that registry. Source: Missouri DOR CDL Medical Certification Requirements page.","handbook":"","hbref":""},{"q":"What happens to a non-excepted Missouri CDL driver who fails to keep a current medical examiner's certificate on file?","options":["The CDL is downgraded and commercial driving privileges are lost","The CDL is suspended for exactly 24 hours, then restored","Nothing, because Missouri does not track medical status","The driver is automatically moved to the excepted intrastate category"],"answer":0,"explanation":"A non-excepted driver who lets the medical certification lapse is downgraded, losing CDL privileges until a current certificate is on file. Source: Missouri DOR CDL Medical Certification FAQ; federal medical-certification rule (49 CFR 383.71/383.73).","handbook":"","hbref":""},{"q":"What is the standard renewal cycle for a Missouri CDL held by a driver age 21 to 69?","options":["6 years","4 years","8 years","10 years"],"answer":0,"explanation":"A standard Missouri CDL is issued for a 6-year term for drivers age 21 to 69 (a 3-year term applies to drivers 18-20 and 70+). Source: Missouri DOR driver license issuance information.","handbook":"","hbref":""},{"q":"A Missouri CDL with a Hazardous Materials (H) endorsement is tied to which additional requirement that can shorten its validity?","options":["A TSA security threat assessment (background check)","An annual vision re-test at a DOR office","A separate Highway Patrol road test each year","A notarized employer sponsorship letter"],"answer":0,"explanation":"The HAZMAT endorsement requires a TSA security threat assessment; in Missouri the endorsement (and often the license term) is tied to that background-check cycle, so it is shorter than the standard 6-year term. Source: Missouri DOR Commercial Drivers page; federal HAZMAT/TSA rule (49 CFR 1572).","handbook":"","hbref":""},{"q":"What is the minimum age to apply for a Missouri CDL/CLP to drive a commercial motor vehicle ONLY within Missouri (intrastate)?","options":["18 years old","16 years old","21 years old","19 years old"],"answer":0,"explanation":"Missouri requires applicants to be at least 18 to obtain a CLP/CDL for intrastate commercial driving; 21 is required for interstate operation. Source: Missouri CDL Manual and Missouri DOR Commercial Drivers page.","handbook":"","hbref":""},{"q":"What is the minimum age required to operate a commercial motor vehicle in interstate commerce on a Missouri CDL?","options":["21 years old","18 years old","19 years old","25 years old"],"answer":0,"explanation":"Drivers must be at least 21 to operate in interstate commerce; an 18-20 year-old Missouri CDL holder is generally limited to intrastate driving. Source: Missouri CDL Manual; federal rule (49 CFR 391.11).","handbook":"","hbref":""},{"q":"Before a Missouri applicant can be issued a CLP, what driver license must they already hold or obtain?","options":["A valid Missouri base (non-commercial) driver license","A valid CDL from another state","Only a learner's permit from any U.S. state","No license is required to get a CLP"],"answer":0,"explanation":"An applicant must have or obtain a Missouri base driver license before a Missouri CLP can be issued. Source: Missouri DOR CDL Permit Rule Overview.","handbook":"","hbref":""},{"q":"When a Missouri CLP expires before the holder passes the skills test, what must the applicant do to get a new CLP?","options":["Complete all required knowledge testing again","Simply pay a small renewal surcharge with no re-testing","Wait 30 days and the CLP automatically reinstates","Take only the skills test, with no knowledge re-testing"],"answer":0,"explanation":"Because the 360-day CLP is non-renewable, when it expires the applicant must complete all required knowledge testing to obtain a new CLP. Source: Missouri DOR CDL Permit Rule Overview.","handbook":"","hbref":""},{"q":"Which endorsement IS allowed to be placed on a Missouri Commercial Learner's Permit (CLP)?","options":["School Bus (S)","Hazardous Materials (H)","Tank Vehicle (N) hauling product","Double/Triple Trailers (T)"],"answer":0,"explanation":"On a Missouri CLP, the School Bus (S) and Passenger (P) endorsements may be carried (with restrictions), but Hazardous Materials (H), Tank (X/N when loaded), and Double/Triple (T) endorsements are prohibited on a CLP. Source: Missouri DOR CDL Testing/CLP FAQ; federal CLP rule (49 CFR 383.25).","handbook":"","hbref":""},{"q":"Under Missouri's document-verification process, how many license-office employees must substantially participate in reviewing a CDL applicant's documents?","options":["At least two employees","Exactly one employee","At least four employees","No employee review is required if documents are scanned"],"answer":0,"explanation":"Missouri requires that at least two employees substantially participate in reviewing and verifying a commercial applicant's identity, residency, and test documents. Source: Missouri DOR CDL Testing/CLP FAQ.","handbook":"","hbref":""},{"q":"Which statement about an out-of-state license holder applying for a Missouri CLP is correct?","options":["They must establish Missouri residency and transfer to a Missouri base license first (which may occur the same day)","Missouri freely issues CLPs to non-residents holding any valid out-of-state license","They may keep their out-of-state license and never transfer it","They must wait 90 days as a Missouri resident before any CLP transaction"],"answer":0,"explanation":"Missouri does not issue a CLP to a non-resident; the applicant must establish Missouri residency and transfer their base license first, which can be done the same day as the CLP application. Source: Missouri DOR CDL Testing/CLP FAQ.","handbook":"","hbref":""},{"q":"What is the minimum passing score on the Missouri CDL knowledge (written) tests?","options":["80 percent","70 percent","75 percent","90 percent"],"answer":0,"explanation":"Missouri CDL knowledge tests require a minimum score of 80 percent to pass, consistent with the federal standard for CDL knowledge testing. Source: Missouri CDL Manual; federal knowledge-test standard (49 CFR 383.135).","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимальная ширина, включая груз, разрешённая для транспортного средства на автодорогах штата Миссури без специального разрешения?","options":["96 inches","100 inches","102 inches","108 inches"],"explanation":"Согласно RSMo 304.170, ни одно транспортное средство (включая его груз) не может превышать 102 inches в ширину на автодорогах Миссури, за исключением устройств безопасности, таких как габаритные огни и зеркала. Превышение требует получения разрешения MoDOT на негабаритный груз. Источник: Missouri Revised Statutes 304.170; Missouri Driver Guide Chapter 15."},"1":{"q":"На межштатных и установленных автодорогах Миссури какова максимальная высота транспортного средства, включая груз, разрешённая без специального разрешения?","options":["13 feet 6 inches","14 feet","14 feet 6 inches","15 feet"],"explanation":"RSMo 304.170 устанавливает максимальную высоту на межштатных и установленных автодорогах в 14 feet, включая груз. Источник: Missouri Revised Statutes 304.170."},"2":{"q":"На автодорогах Миссури, ОТЛИЧНЫХ от межштатных и установленных маршрутов, какова общая максимальная высота транспортного средства, включая груз?","options":["13 feet","13 feet 6 inches","14 feet","15 feet"],"explanation":"RSMo 304.170 ограничивает высоту до 13 feet 6 inches на всех автодорогах, кроме межштатных и установленных. Транспортные средства, перевозящие автомобили, в порядке исключения могут достигать 14 feet. Источник: Missouri Revised Statutes 304.170."},"3":{"q":"Какова максимальная длина, включая груз, одиночного транспортного средства (такого как грузовик без прицепа), эксплуатируемого на автодорогах Миссури?","options":["40 feet","45 feet","48 feet","53 feet"],"explanation":"RSMo 304.170 ограничивает одиночное транспортное средство, включая груз, длиной 45 feet. Более длинные составы и полуприцепы регулируются отдельными положениями. Источник: Missouri Revised Statutes 304.170."},"4":{"q":"Какова максимальная длина полуприцепа, разрешённая в национальной сети (межштатные и установленные автодороги) в Миссури?","options":["48 feet","50 feet","53 feet","57 feet"],"explanation":"Полуприцеп в составе «седельный тягач/полуприцеп» может иметь длину до 53 feet в национальной сети межштатных и установленных автодорог Миссури, в соответствии с RSMo 304.170 и федеральными стандартами. Источник: Missouri Revised Statutes 304.170; Missouri Driver Guide Chapter 15."},"5":{"q":"Какова максимальная полная масса, разрешённая на автодорогах Миссури без разрешения на перевес (при отсутствии более низкого установленного ограничения для моста)?","options":["73,280 pounds","76,000 pounds","80,000 pounds","84,000 pounds"],"explanation":"RSMo 304.180 ограничивает полную массу 80,000 pounds на автодорогах Миссури, за исключением случаев, когда для моста или сооружения установлено меньшее ограничение. Это соответствует федеральному лимиту для межштатных автодорог. Источник: Missouri Revised Statutes 304.180."},"6":{"q":"Какова максимальная нагрузка, разрешённая на одиночную ось в системе межштатных автодорог Миссури?","options":["18,000 pounds","20,000 pounds","22,000 pounds","24,000 pounds"],"explanation":"RSMo 304.180 и федеральный стандарт ограничивают нагрузку на любую одиночную ось до 20,000 pounds в системе межштатных автодорог. Источник: Missouri Revised Statutes 304.180."},"7":{"q":"Какова максимальная нагрузка, разрешённая на группу спаренных осей (тандем) в системе межштатных автодорог Миссури?","options":["30,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"RSMo 304.180 и федеральный стандарт ограничивают группу спаренных осей до 34,000 pounds в системе межштатных автодорог. Источник: Missouri Revised Statutes 304.180."},"8":{"q":"Как по законодательству Миссури определяется «спаренная ось» (тандем) по расстоянию между осями?","options":["Оси на расстоянии 40 inches или менее друг от друга","Оси на расстоянии более 40 inches, но не более 96 inches друг от друга","Оси на расстоянии более 96 inches, но не более 120 inches друг от друга","Любые две оси независимо от расстояния"],"explanation":"RSMo 304.180 определяет спаренную ось как две или более оси, расположенные одна за другой, крайние точки которых находятся на расстоянии более 40 inches и не более 96 inches друг от друга. Источник: Missouri Revised Statutes 304.180."},"9":{"q":"На автодорогах Миссури, которые НЕ являются частью системы межштатных автодорог, насколько транспортное средство может превышать лимиты нагрузки на одиночную и спаренную ось, при условии, что полная масса всё же не превышает 80,000 pounds?","options":["До 1,000 pounds","До 2,000 pounds","До 4,000 pounds","Допуска нет"],"explanation":"RSMo 304.180 разрешает транспортным средствам на немежштатных автодорогах превышать лимиты нагрузки на одиночную и спаренную ось до 2,000 pounds, но общая полная масса не может превышать 80,000 pounds. Источник: Missouri Revised Statutes 304.180."},"10":{"q":"На межштатных и установленных автодорогах Миссури максимальная допустимая масса транспортного средства определяется в первую очередь чем?","options":["Федеральной мостовой формулой и таблицей (Federal Bridge Formula)","Количеством шин на дороге","Зарегистрированной полной массой (GVWR) транспортного средства","Классом CDL водителя"],"explanation":"Максимальная масса на межштатных и установленных автодорогах регулируется Федеральной мостовой формулой и таблицей (Federal Bridge Formula), которая связывает допустимую полную массу с количеством осей и расстоянием между ними, при общем пределе 80,000 pounds. Источник: Missouri Revised Statutes 304.180; FHWA Federal Bridge Formula."},"11":{"q":"Федеральная мостовая формула (Federal Bridge Formula), применяемая в Миссури, ограничивает допустимую полную массу на основании каких двух факторов?","options":["Давления в шинах и типа груза","Мощности двигателя и количества осей","Количества осей и расстояния между ними","Возраста транспортного средства и зарегистрированной массы"],"explanation":"Федеральная мостовая формула (Bridge Formula B) устанавливает допустимую массу для любой группы последовательных осей, используя количество осей в группе и расстояние между крайними осями, защищая мосты от перегрузки. Миссури применяет её согласно RSMo 304.180. Источник: Missouri Revised Statutes 304.180; FHWA."},"12":{"q":"Когда требуется разрешение MoDOT на негабаритный/перевесный груз для движения по автодорогам Миссури?","options":["Только при движении ночью","Когда транспортное средство и груз превышают законные пределы по размеру или массе","Только для транспортных средств, зарегистрированных в другом штате","Всякий раз, когда транспортное средство весит более 26,001 pounds"],"explanation":"Разрешение MoDOT на негабаритный/перевесный груз требуется всякий раз, когда транспортное средство и его груз превышают законные пределы Миссури по ширине, высоте, длине или массе. Грузы, которые можно разумно разобрать, чтобы уложиться в законные пределы, как правило, разрешения не получают. Источник: Missouri DOT Motor Carrier Services / OSOW; RSMo 304.170-304.200."},"13":{"q":"В течение какого срока действует стандартное одноразовое разрешение MoDOT на негабаритный/перевесный груз?","options":["24 hours","Семь дней подряд","30 days","Один год"],"explanation":"Одноразовые разрешения MoDOT на негабаритный/перевесный груз действуют семь дней подряд. Для соответствующих непрерывных перевозок доступны годовые (общие) разрешения. Источник: Missouri DOT Oversize/Overweight permit regulations."},"14":{"q":"Как рассчитывается базовый сбор за одноразовое разрешение MoDOT на ПЕРЕВЕС?","options":["Фиксированно $50 независимо от массы","$15 плюс $20 за каждые 10,000 pounds сверх законной полной массы","$100 плюс $5 за ось","$25 за пройденную милю"],"explanation":"MoDOT взимает базовый сбор за одноразовое разрешение в размере $15 плюс $20 за каждые 10,000 pounds (или их часть) сверх законной полной массы; для очень тяжёлых перевозок добавляется сбор за анализ моста и дорожного полотна. Источник: Missouri DOT Oversize/Overweight permit fee schedule."},"15":{"q":"Для большинства негабаритных грузов в Миссури движение в дневное время, как правило, ограничено каким временным интервалом?","options":["Только с полуночи до полудня","С получаса до восхода солнца до получаса после заката","Только с 8:00 a.m. до 4:00 p.m.","В любое время, 24 часа в сутки"],"explanation":"Разрешённые негабаритные грузы в Миссури, как правило, могут перемещаться с получаса до восхода солнца до получаса после заката; грузы, которые только перевесные (законного размера), могут перемещаться непрерывно. Источник: Missouri DOT Oversize/Overweight permit regulations."},"16":{"q":"Согласно сельскохозяйственному отклонению по массе в Миссури, какова максимальная полная масса для транспортного средства, перевозящего молоко с фермы или перевозящего скот по автодорогам, ОТЛИЧНЫМ от системы межштатных автодорог?","options":["80,000 pounds","82,000 pounds","85,500 pounds","90,000 pounds"],"explanation":"RSMo 304.180 разрешает транспортному средству, перевозящему молоко с фермы на переработку или перевозящему скот, достигать до 85,500 pounds полной массы на автодорогах, отличных от системы межштатных автодорог. Это не применяется на межштатных автодорогах. Источник: Missouri Revised Statutes 304.180; Missouri Dept. of Agriculture."},"17":{"q":"Согласно отклонению на период сбора урожая в Миссури, транспортные средства, перевозящие зерно или продукты переработки зерна в период сбора урожая, могут превышать обычные лимиты массы на немежштатных автодорогах на какую величину?","options":["5 percent","10 percent","15 percent","На 2,000 pounds фиксированно"],"explanation":"RSMo 304.180 разрешает перевозчикам зерна и продуктов его переработки в период сбора урожая превышать максимальные лимиты массы до 10 percent на автодорогах, отличных от системы межштатных автодорог. Источник: Missouri Revised Statutes 304.180; Missouri Dept. of Agriculture."},"18":{"q":"Перевозчик скота или зерна, использующий сельскохозяйственное отклонение Миссури с повышенной массой, должен соблюдать какое ограничение?","options":["Нельзя использовать систему межштатных автодорог или пересекать мост с установленным ограничением ниже массы груза","Должен перемещаться только ночью","Должен постоянно иметь двух сигнальщиков с флажками","Может работать только в пределах 25 миль от фермы"],"explanation":"Согласно RSMo 304.180, перевозчики, использующие повышенный сельскохозяйственный допуск по массе, не могут использовать никакую часть системы межштатных автодорог и не могут пересекать никакой мост с установленным ограничением ниже полной массы транспортного средства и груза. Источник: Missouri Revised Statutes 304.180; Missouri Dept. of Agriculture."},"19":{"q":"Какой максимальный передний и задний свес обычно разрешён для автовозов согласно правилам Миссури по габаритам?","options":["2 feet спереди, 3 feet сзади","3 feet спереди, 4 feet сзади","4 feet спереди, 6 feet сзади","Свес не разрешён"],"explanation":"Правила Миссури по габаритам согласно RSMo 304.170 разрешают автовозам передний свес не более 3 feet и задний свес не более 4 feet. Источник: Missouri Revised Statutes 304.170."},"20":{"q":"В Миссури какой класс CDL требуется для управления любым составом транспортных средств с полной массой состава (GCWR) 26,001 pounds или более, при условии, что буксируемое транспортное средство имеет GVWR свыше 10,000 pounds?","options":["Class A","Class B","Class C","Class E"],"explanation":"Миссури определяет Class A как любой состав транспортных средств с GCWR 26,001 pounds или более, где GVWR буксируемого звена превышает 10,000 pounds. Источник: Missouri Commercial Driver License Manual, Section 1 (CDL Classifications)."},"21":{"q":"Согласно правилам Миссури, какова максимальная GVWR буксируемого транспортного средства, прежде чем одиночное тяговое звено с GVWR 26,001+ pounds потребует CDL Class A (а не Class B)?","options":["8,000 pounds","10,000 pounds","15,000 pounds","26,001 pounds"],"explanation":"CDL Class B охватывает одиночное транспортное средство с GVWR 26,001+ lbs, буксирующее звено с GVWR НЕ свыше 10,000 lbs; если GVWR буксируемого звена превышает 10,000 lbs, требуется Class A. Источник: Missouri Commercial Driver License Manual, Section 1."},"22":{"q":"Согласно Missouri CDL Manual, CDL Class C применяется только к транспортному средству с GVWR менее 26,001 pounds, когда оно имеет таблички (placard) об опасных грузах ИЛИ предназначено для перевозки скольких человек?","options":["9 или более человек, не считая водителя","12 или более человек, включая водителя","15 или более человек, не считая водителя","16 или более человек, включая водителя"],"explanation":"Class C в Миссури охватывает одиночное транспортное средство с GVWR менее 26,001 lbs, которое имеет таблички об опасных грузах или предназначено для перевозки 16 или более человек, включая водителя. Источник: Missouri Commercial Driver License Manual, Section 1."},"23":{"q":"Каков минимальный возраст для получения CDL в Миссури только для ВНУТРИШТАТНОГО вождения (в пределах Миссури)?","options":["16 лет","18 лет","19 лет","21 год"],"explanation":"Условия получения CDL в Миссури предусматривают возраст 18 лет для внутриштатной работы (до 21 года) и 21 год для межштатной работы. Источник: Missouri Commercial Driver License Manual, 'Missouri CDL Eligibility.'"},"24":{"q":"Водитель из Миссури хочет управлять коммерческим транспортным средством через границы штатов (межштатная торговля). Каков минимальный возраст для владения CDL для межштатной работы?","options":["18 лет","19 лет","20 лет","21 год"],"explanation":"Миссури требует, чтобы водителю был 21 год для работы в межштатной торговле; владельцы CDL в возрасте от 18 до 20 лет ограничены внутриштатной работой. Источник: Missouri Commercial Driver License Manual, 'Missouri CDL Eligibility.'"},"25":{"q":"Прежде чем сдавать экзамен по навыкам вождения CDL (дорожный тест) в Миссури, заявитель должен владеть коммерческим ученическим разрешением (CLP) минимум в течение какого срока?","options":["7 days","14 days","30 days","60 days"],"explanation":"Федеральные правила и правила Миссури требуют владения CLP минимум 14 days, прежде чем можно сдавать экзамен по навыкам. Источник: Missouri DOR CDL Permit Rule Overview; 49 CFR 383.25."},"26":{"q":"Как долго действует коммерческое ученическое разрешение (CLP) в Миссури, и можно ли его продлить?","options":["180 days, продлевается один раз","360 days, не продлевается","1 год, продлевается ежегодно","2 года, не продлевается"],"explanation":"CLP в Миссури выдаётся на 360 days и не продлевается; если срок истекает, заявитель должен повторно сдать необходимые теоретические экзамены. Источник: Missouri DOR CDL Permit Rule Overview."},"27":{"q":"Какое подтверждение (endorsement) требуется в Миссури для управления коммерческим транспортным средством, предназначенным для перевозки 16 или более человек, включая водителя?","options":["Подтверждение S (School Bus)","Подтверждение P (Passenger)","Подтверждение N (Tanker)","Подтверждение T (Doubles/Triples)"],"explanation":"Подтверждение P (Passenger) требуется для транспортных средств, предназначенных для перевозки 16 или более человек, включая водителя; оно требует сдачи теоретического экзамена и экзамена по навыкам на пассажирском транспортном средстве. Источник: Missouri Commercial Driver License Manual, Endorsements section."},"28":{"q":"В Миссури подтверждение Tank Vehicle (N) требуется для транспортного средства, перевозящего жидкость или газ в цистерне с индивидуальной номинальной ёмкостью более 119 gallons и совокупной номинальной ёмкостью какой величины?","options":["500 gallons или более","750 gallons или более","1,000 gallons или более","1,500 gallons или более"],"explanation":"Подтверждение N применяется к цистернам с индивидуальной номинальной ёмкостью более 119 gallons и совокупной номинальной ёмкостью 1,000 gallons или более. Источник: Missouri Commercial Driver License Manual, Endorsements section; 49 CFR 383.5."},"29":{"q":"Какое подтверждение требуется водителям Class A в Миссури, прежде чем они смогут буксировать двойные или тройные прицепы?","options":["Подтверждение N (Tanker)","Подтверждение T (Doubles/Triples)","Подтверждение X (Combination)","Подтверждение H (Hazardous Materials)"],"explanation":"Подтверждение T (Doubles/Triples) требует сдачи специального теоретического экзамена; оно применяется к водителям Class A, желающим буксировать несколько прицепов. Источник: Missouri Commercial Driver License Manual, Endorsements section."},"30":{"q":"Какое из следующих подтверждений НЕ может быть добавлено к коммерческому ученическому разрешению (CLP) в Миссури?","options":["P (Passenger)","S (School Bus)","N (Tanker)","T (Doubles/Triples)"],"explanation":"Единственные подтверждения, которые могут быть добавлены к CLP в Миссури, — это P (Passenger), S (School Bus) и N (Tanker). H, X и T запрещены на CLP. Источник: Missouri Commercial Driver License Manual; 49 CFR 383.153(b); Section 302.700, RSMo."},"31":{"q":"Прежде чем подтверждение Hazardous Materials (H) может быть добавлено к CDL в Миссури, заявитель должен сдать письменный тест И получить одобрение чего?","options":["Оценки угрозы безопасности TSA (проверка биографии)","Освобождения от специалиста по зрению","Спонсорского письма от работодателя в Миссури","Допуска по результатам придорожной инспекции DOT"],"explanation":"В дополнение к письменному тесту HazMat из 30 вопросов, заявители должны пройти дактилоскопию и получить одобрение оценки угрозы безопасности TSA, прежде чем будет добавлено подтверждение H (или X). Источник: Missouri DOR HazMat Endorsement Requirements; 49 CFR 1572."},"32":{"q":"CDL в Миссури с подтверждением Hazardous Materials (H или X) истечёт не более чем через сколько лет после завершения оценки угрозы безопасности TSA?","options":["2 года","4 года","5 лет","8 лет"],"explanation":"Поскольку проверка биографии TSA действительна в течение пяти лет, CDL с подтверждением H или X истекает не более чем через 5 лет после завершения оценки угрозы безопасности. Источник: Missouri DOR HazMat Endorsement / HME FAQs; 49 CFR 1572."},"33":{"q":"В Миссури подтверждение School Bus (S) требует получения какого дополнительного подтверждения?","options":["Подтверждение N (Tanker)","Подтверждение P (Passenger)","Подтверждение H (Hazardous Materials)","Подтверждение T (Doubles/Triples)"],"explanation":"Согласно федеральным правилам и правилам Миссури, подтверждение School Bus (S) требует подтверждения Passenger (P); заявитель должен сдать теоретический тест по школьным автобусам и экзамен по навыкам на школьном автобусе. Источник: Missouri Commercial Driver License Manual; 49 CFR 383.93."},"34":{"q":"Прежде чем сдавать экзамен по навыкам CDL в Миссури (вступило в силу с February 7, 2022), заявитель должен пройти обучение водителей начального уровня (ELDT) у поставщика, указанного где?","options":["В списке утверждённых школ Missouri State Highway Patrol","В реестре поставщиков обучения FMCSA (Training Provider Registry)","В списке поставщиков Missouri Department of Revenue","В любой частной школе CDL по выбору заявителя"],"explanation":"ELDT необходимо пройти у поставщика, указанного в реестре поставщиков обучения FMCSA (Training Provider Registry), прежде чем сдавать экзамен по навыкам для первичного получения CDL или определённых подтверждений. Источник: Missouri DOR Commercial Drivers page; 49 CFR Part 380."},"35":{"q":"При самостоятельном подтверждении медицинского статуса для CDL в Миссури из скольких возможных категорий должен выбрать водитель?","options":["2 категории","3 категории","4 категории","6 категорий"],"explanation":"Водители самостоятельно относят себя к одной из четырёх категорий: межштатная без исключений, межштатная с исключениями, внутриштатная без исключений или внутриштатная с исключениями. Источник: Missouri Commercial Driver License Manual, Medical Self-Certification; 49 CFR 383.71."},"36":{"q":"Заявитель на CDL в Миссури, который удостоверяет статус «межштатная без исключений», должен также сделать что?","options":["Предоставить и поддерживать действительный сертификат медицинского эксперта (медицинская карта DOT)","Подать медицинское освобождение только для внутриштатной работы в Миссури","Не предоставлять ничего более; одного удостоверения достаточно","Получать ежегодную проверку зрения у оптометриста в Миссури"],"explanation":"Водитель, самостоятельно удостоверяющий статус «межштатная без исключений», подпадает под федеральные медицинские стандарты и должен предоставить и поддерживать в актуальном состоянии действительный сертификат медицинского эксперта, иначе рискует понижением категории. Источник: Missouri Commercial Driver License Manual, Self-Certification; 49 CFR 391.41."},"37":{"q":"Чтобы установить место жительства (domicile) в Миссури при подаче заявления на CDL, сколько документов, подтверждающих адрес проживания заявителя, требуется?","options":["Один документ","Два документа","Три документа","Никаких документов, если есть ранее выданные права"],"explanation":"Миссури требует два приемлемых документа, подтверждающих проживание/место жительства в Миссури, в дополнение к подтверждению личности, номера социального страхования и законного присутствия. Источник: Missouri DOR Commercial Drivers page; Missouri CDL Manual, Eligibility."},"38":{"q":"Какой статус законного присутствия Миссури требует от заявителя на CDL?","options":["Любой обладатель действительной визы независимо от статуса","Гражданин США или законный постоянный житель","Только гражданин США","Любой заявитель с номером социального страхования"],"explanation":"Миссури требует, чтобы заявители на CDL были гражданами США или негражданами США со статусом законного постоянного жителя. Источник: Missouri DOR Commercial Drivers page; Missouri CDL Manual, Eligibility."},"39":{"q":"Каков минимальный проходной балл на каждом теоретическом (письменном) экзамене CDL в Миссури?","options":["70%","75%","80%","85%"],"explanation":"Миссури требует балла 80% на каждом письменном экзамене CDL, проводимом в пунктах тестирования Highway Patrol (например, General Knowledge из 50 вопросов, HazMat из 30 вопросов, тесты на подтверждения из 20 вопросов). Источник: Missouri Commercial Driver License Manual, Section 14 (CDL Written Examinations)."},"40":{"q":"В Миссури какова максимальная концентрация алкоголя в крови (BAC), которую может иметь водитель при управлении коммерческим транспортным средством (CMV), прежде чем это будет считаться серьёзным нарушением?","options":["0.04%","0.08%","0.02%","0.10%"],"explanation":"Миссури запрещает управление CMV с BAC 0.04% или выше (половина предела 0.08% для некоммерческих водителей). Источник: Missouri DOR Form 5231, 'Commercial Motor Vehicle Operators and the Law'; 49 CFR 383.51."},"41":{"q":"Согласно закону Миссури о подразумеваемом согласии, что происходит, если владелец CDL отказывается пройти химический анализ (крови/дыхания) при законном требовании?","options":["CDL дисквалифицируется на 1 год, как и за первое DWI","Только штраф $500 без дисквалификации","Дисквалификация CDL на 60 дней","Никакого наказания, поскольку отказ не может использоваться как доказательство"],"explanation":"Отказ от анализа крови и/или дыхания владельцем CDL или при управлении CMV рассматривается как серьёзное нарушение и приводит к дисквалификации CDL на 1 год, как и за первое осуждение за DWI. Источник: Missouri DOR Form 5231; закон Миссури о подразумеваемом согласии (Chapter 577 RSMo); 49 CFR 383.51."},"42":{"q":"На какой срок дисквалифицируется CDL за ПЕРВОЕ серьёзное нарушение (такое как DWI на CMV), когда НЕ перевозятся опасные грузы?","options":["1 год","3 года","60 дней","Пожизненно"],"explanation":"Первое серьёзное нарушение, включая вождение в состоянии опьянения, отказ от анализа или оставление места происшествия, приводит к дисквалификации CDL на 1 год в Миссури. Источник: Missouri DOR Form 5231; 49 CFR 383.51."},"43":{"q":"Водитель совершает первое серьёзное нарушение при управлении транспортным средством, имеющим таблички (placard) об опасных грузах. Каков срок дисквалификации?","options":["3 года","1 год","5 лет","Пожизненно"],"explanation":"Первое серьёзное нарушение, совершённое при перевозке опасных грузов с табличками, влечёт дисквалификацию CDL на 3 года вместо стандартного 1 года. Источник: Missouri DOR Form 5231; 49 CFR 383.51."},"44":{"q":"Каковы последствия ВТОРОГО серьёзного нарушения (например, второго DWI) для CDL в Миссури?","options":["Пожизненная дисквалификация","Дисквалификация на 3 года","Дисквалификация на 10 лет","Дисквалификация на 1 год"],"explanation":"Второе осуждение за любое из перечисленных серьёзных нарушений приводит к пожизненной дисквалификации CDL в Миссури (некоторые водители могут иметь право на восстановление через 10 лет согласно федеральным указаниям). Источник: Missouri DOR Form 5231; 49 CFR 383.51."},"45":{"q":"Сколько грубых нарушений правил движения в течение 3-летнего периода приводят к дисквалификации CDL на 60 дней?","options":["2","3","4","1"],"explanation":"Два осуждения за грубые нарушения правил движения в течение трёх лет (на CMV) приводят к дисквалификации CDL на 60 дней. Источник: Missouri DOR Form 5231; 49 CFR 383.51."},"46":{"q":"Сколько грубых нарушений правил движения в течение 3 лет приводят к дисквалификации CDL на 120 дней?","options":["3 или более","2","5 или более","4 или более"],"explanation":"Три или более осуждения за грубые нарушения правил движения в течение трёх лет приводят к дисквалификации CDL на 120 дней. Источник: Missouri DOR Form 5231; 49 CFR 383.51."},"47":{"q":"Какое из следующих классифицируется как «грубое нарушение правил движения» для владельца CDL в Миссури?","options":["Превышение скорости на 15 mph или более сверх установленного предела","Превышение скорости на 5 mph сверх установленного предела","Нарушение правил парковки","Нарушение, связанное с освещением оборудования"],"explanation":"Грубые нарушения правил движения включают превышение скорости на 15 mph или более сверх предела, безрассудное вождение, неправильную или беспорядочную смену полосы и слишком близкое следование за впереди идущим транспортом. Незначительное превышение скорости и нарушения парковки не являются «грубыми». Источник: Missouri DOR Form 5231; 49 CFR 383.51."},"48":{"q":"Каков срок дисквалификации за ПЕРВОЕ нарушение на железнодорожном переезде (railroad-highway grade crossing) водителем?","options":["60 дней","30 дней","120 дней","1 год"],"explanation":"Первое нарушение на железнодорожном переезде приводит к дисквалификации CDL минимум на 60 дней. Источник: Missouri DOR Form 5231; 49 CFR 383.51."},"49":{"q":"Владелец CDL совершает ВТОРОЕ нарушение на железнодорожном переезде в течение 3 лет. Каков срок дисквалификации?","options":["120 дней","60 дней","1 год","180 дней"],"explanation":"Второе нарушение на железнодорожном переезде в течение трёх лет приводит к дисквалификации минимум на 120 дней. Источник: Missouri DOR Form 5231; 49 CFR 383.51."},"50":{"q":"Каков срок дисквалификации за ТРЕТЬЕ нарушение на железнодорожном переезде в течение 3-летнего периода?","options":["1 год","120 дней","180 дней","60 дней"],"explanation":"Третье или последующее нарушение на железнодорожном переезде в течение трёх лет приводит к дисквалификации минимум на 1 год. Источник: Missouri DOR Form 5231; 49 CFR 383.51."},"51":{"q":"Помимо дисквалификации, какой диапазон гражданского штрафа может грозить водителю за нарушение предписания о выводе из эксплуатации?","options":["$1,000 до $2,500","$100 до $500","$250 до $750","$5,000 до $10,000"],"explanation":"Водитель, нарушающий предписание о выводе из эксплуатации, подлежит гражданскому штрафу не менее $1,000 и не более $2,500, в дополнение к дисквалификации. Источник: 49 CFR 383.53; Missouri DOR Form 5231."},"52":{"q":"Согласно RSMo 304.822, каков штраф за ПЕРВОЕ нарушение запрета на использование телефона в руках / отправку текстовых сообщений?","options":["$150","$50","$250","$500"],"explanation":"Согласно закону Миссури Siddens Bening Hands Free Law, штраф составляет $150 за первое нарушение, $250 за второе и $500 за третье в течение установленного периода. Источник: Section 304.822 RSMo."},"53":{"q":"Владелец CDL осуждён за использование CMV для совершения тяжкого преступления (felony), связанного с производством или распространением контролируемого вещества. Какова дисквалификация?","options":["Пожизненная дисквалификация без права восстановления","Дисквалификация на 1 год","Дисквалификация на 3 года","Дисквалификация на 10 лет"],"explanation":"Использование CMV при совершении тяжкого преступления, связанного с производством, распространением или сбытом контролируемого вещества, приводит к пожизненной дисквалификации без возможности восстановления. Источник: Missouri DOR Form 5231; 49 CFR 383.51."},"54":{"q":"Какое из следующих является серьёзным нарушением, влекущим дисквалификацию CDL на 1 год при первом осуждении?","options":["Оставление места происшествия с участием CMV","Слишком близкое следование за впереди идущим транспортом","Неправильная смена полосы","Превышение скорости на 15 mph сверх предела"],"explanation":"Оставление места происшествия с участием CMV является серьёзным нарушением (дисквалификация на 1 год при первом нарушении). Слишком близкое следование, неправильная смена полосы и превышение скорости на 15+ mph являются «грубыми» нарушениями, а не серьёзными нарушениями. Источник: Missouri DOR Form 5231; 49 CFR 383.51."},"55":{"q":"Водитель причиняет смерть в результате небрежного управления CMV (например, транспортное непредумышленное убийство). Как это классифицируется для целей CDL?","options":["Серьёзное нарушение с дисквалификацией на 1 год при первом нарушении","Грубое нарушение правил движения с дисквалификацией на 60 дней","Нарушение на железнодорожном переезде с дисквалификацией на 120 дней","Нарушение предписания о выводе из эксплуатации с дисквалификацией на 90 дней"],"explanation":"Причинение смерти в результате небрежного или преступного управления CMV является серьёзным нарушением, приводящим к дисквалификации на 1 год при первом осуждении (3 года при наличии табличек hazmat; пожизненно при втором серьёзном нарушении). Источник: Missouri DOR Form 5231; 49 CFR 383.51."},"56":{"q":"Какое максимальное установленное ограничение скорости действует для коммерческого автотранспортного средства (грузовика) на сельской автомагистрали (interstate) или скоростной автодороге (freeway) в штате Миссури, если более низкий лимит не обозначен?","options":["70 mph","65 mph","60 mph","55 mph"],"explanation":"Миссури устанавливает максимальную скорость на сельских автомагистралях (interstate) и скоростных автодорогах (freeway) на уровне 70 mph, и отдельного, более низкого общегосударственного ограничения скорости для грузовиков не существует, поэтому грузовики могут двигаться с той же скоростью 70 mph, если не обозначена более низкая скорость. Источник: RSMo 304.010."},"57":{"q":"Согласно законодательству штата Миссури, на каких дорогах грузовикам, зарегистрированным для полной массы более 48 000 фунтов, запрещено движение по крайней левой полосе?","options":["На любом двухполосном шоссе штата с установленным лимитом 55 mph или выше","На всех сельских автомагистралях (interstate) с двумя или более полосами в каждом направлении","На любой дороге с разделительной полосой в любой точке штата независимо от количества полос","На автомагистралях (interstate), скоростных автодорогах (freeway) или скоростных трассах (expressway) в пределах урбанизированных территорий, имеющих три или более полос в одном направлении"],"explanation":"Миссури запрещает грузовикам, зарегистрированным для полной массы более 48 000 фунтов, движение по крайней левой полосе на автомагистралях (interstate), скоростных автодорогах (freeway) или скоростных трассах (expressway) в пределах урбанизированных территорий, имеющих три или более полос, идущих в одном направлении. Источник: RSMo 304.015."},"58":{"q":"В штате Миссури, на дороге с двумя или более полосами движения в одном направлении, по какой полосе, как правило, должно двигаться транспортное средство?","options":["По той полосе, на которой в данный момент меньше всего трафика","По правой полосе, за исключением случаев обгона, подготовки к левому повороту или иных указаний знаков/разметки","По левой полосе, чтобы держать правую полосу свободной для въезжающего транспорта","По центральной полосе на любой дороге, имеющей три полосы в одном направлении"],"explanation":"Миссури требует, чтобы все транспортные средства двигались по правой полосе на дорогах с двумя или более полосами в одном направлении, за исключением случаев обгона и опережения, подготовки к надлежащему левому повороту или иных указаний дорожной разметки, знаков или сигналов. Источник: RSMo 304.015."},"59":{"q":"На каком расстоянии от ближайшего рельса должен остановиться автобус или транспортное средство с табличками опасных материалов, приближающееся к железнодорожному переезду в штате Миссури?","options":["В пределах 100 футов, но не ближе 25 футов","В пределах 75 футов, но не ближе 10 футов","В пределах 50 футов, но не ближе 15 футов","В пределах 25 футов, но не ближе 5 футов"],"explanation":"Автобусы и транспортные средства с табличками HazMat должны остановиться в пределах 50 футов, но не ближе 15 футов от ближайшего рельса, а затем посмотреть и прислушаться перед пересечением. Источник: Руководство CDL штата Миссури; 49 CFR 392.10."},"60":{"q":"На дороге в штате Миссури водитель транспортного средства, встречающий или догоняющий остановившийся школьный автобус, который подаёт сигнал остановки, обязан сделать что?","options":["Остановить транспортное средство, не доезжая до автобуса, независимо от того, движется ли он навстречу автобусу или позади него","Остановиться только если движется в том же направлении, что и автобус","Снизить скорость до 10 mph и проехать с осторожностью без остановки","Остановиться только если у обочины явно присутствуют дети"],"explanation":"Миссури требует, чтобы водитель, встречающий или догоняющий школьный автобус с любого направления, который остановился и подаёт сигнал, остановил транспортное средство, не доезжая до автобуса. Исключение составляют раздельные проезжие части или встречный поток на дорогах с четырьмя и более полосами. Источник: RSMo 304.050."},"61":{"q":"Какое исключение в штате Миссури позволяет водителю НЕ останавливаться перед школьным автобусом, осуществляющим посадку или высадку детей?","options":["Водитель в этот момент движется со скоростью менее 25 mph","У автобуса мигают жёлтые (амбер) огни, но не красные огни","Водитель находится более чем в 100 футах от автобуса в момент его остановки","Автобус находится на отдельной проезжей части или движется в противоположном направлении по дороге с четырьмя или более полосами движения"],"explanation":"Водителю на дороге с раздельными проезжими частями не нужно останавливаться перед школьным автобусом, находящимся на другой проезжей части, или движущимся в противоположном направлении по дороге, содержащей четыре или более полос движения. Источник: RSMo 304.050."},"62":{"q":"Согласно закону штата Миссури «Move Over» (уступи дорогу), когда водитель приближается к неподвижному аварийному, эвакуационному, коммунальному транспортному средству или транспортному средству MoDOT с включёнными предупреждающими огнями на дороге, имеющей не менее четырёх полос (две или более в одном направлении), водитель должен прежде всего сделать что?","options":["Полностью остановиться, пока неподвижное транспортное средство не уедет","Перестроиться в полосу, не примыкающую к неподвижному транспортному средству, если это можно сделать безопасно","Непрерывно сигналить, проезжая мимо неподвижного транспортного средства","Съехать на правую обочину и ждать сигнала о том, что путь свободен"],"explanation":"Закон Миссури «Move Over» требует, чтобы водитель, там где дорога имеет не менее четырёх полос с двумя или более в одном направлении, перестроился в полосу, не примыкающую к неподвижному транспортному средству, когда это можно сделать безопасно. Источник: RSMo 304.022."},"63":{"q":"Согласно закону штата Миссури «Move Over», если перестроение в полосу подальше от неподвижного аварийного/коммунального транспортного средства небезопасно или невозможно, что вместо этого должен сделать водитель?","options":["Полностью остановиться в текущей полосе, пока трафик не рассеется","Сохранять установленное ограничение скорости и продолжать движение прямо","Действовать с должной осторожностью и снизить скорость, поддерживая безопасную скорость с учётом дорожных условий","Включить аварийную сигнализацию и быстро ускориться, проезжая место происшествия"],"explanation":"Когда перестроение нельзя выполнить безопасно, Миссури требует, чтобы водитель действовал с должной осторожностью и снизил скорость транспортного средства, поддерживая безопасную скорость с учётом дорожных условий. Источник: RSMo 304.022."},"64":{"q":"Коммерческий водитель в штате Миссури обязан возить предупреждающие устройства для использования при остановке на дороге. Из чего состоит стандартное требование?","options":["Три светоотражающих треугольника","Два светоотражающих треугольника и три фальшфейера","Четыре светоотражающих треугольника","Один светоотражающий треугольник и два флажка"],"explanation":"CMV должно быть оснащено тремя светоотражающими треугольниками (или одобренными эквивалентами) для выставления при остановке на проезжей части или рядом с ней. Источник: Руководство CDL штата Миссури; 49 CFR 393.95 / 392.22."},"65":{"q":"Когда коммерческое транспортное средство в штате Миссури остановлено на дороге с разделительной полосой или с односторонним движением, где следует разместить три предупреждающих треугольника?","options":["Все три на расстоянии 10 футов прямо позади транспортного средства","Один в 10 футах позади, один в 100 футах позади и один в 100 футах впереди","Примерно в 25, 50 и 100 футах позади транспортного средства","Примерно в 10, 100 и 200 футах позади транспортного средства, в сторону приближающегося трафика"],"explanation":"На дороге с разделительной полосой или с односторонним движением все три треугольника размещаются в сторону приближающегося трафика примерно в 10 футах, 100 футах и 200 футах позади остановившегося CMV. Источник: Руководство CDL штата Миссури; 49 CFR 392.22."},"66":{"q":"Когда коммерческое транспортное средство в штате Миссури остановлено на двухполосной дороге с двусторонним движением без разделительной полосы, где следует разместить предупреждающие треугольники?","options":["Один примерно в 10 футах позади, один примерно в 200 футах позади и один примерно в 200 футах впереди","Один примерно в 10 футах позади, один примерно в 100 футах позади и один примерно в 100 футах впереди транспортного средства","Все три позади транспортного средства на расстоянии 10, 100 и 200 футов","По одному с каждой стороны транспортного средства и один прямо позади него"],"explanation":"На двухполосной дороге с двусторонним движением водитель размещает один треугольник в пределах 10 футов от задней части, один примерно в 100 футах позади и один примерно в 100 футах впереди транспортного средства. Источник: Руководство CDL штата Миссури; 49 CFR 392.22."},"67":{"q":"Каково максимальное ограничение скорости на сельской скоростной трассе (expressway) в штате Миссури (не являющейся автомагистралью interstate или скоростной автодорогой freeway)?","options":["70 mph","60 mph","65 mph","55 mph"],"explanation":"Миссури устанавливает максимальную скорость на сельских скоростных трассах (expressway) на уровне 65 mph, ниже, чем 70 mph, разрешённые на сельских автомагистралях (interstate) и скоростных автодорогах (freeway). Источник: RSMo 304.010."},"68":{"q":"Каково максимальное ограничение скорости на автомагистрали (interstate), скоростной автодороге (freeway) или скоростной трассе (expressway) в штате Миссури, расположенной в пределах урбанизированной территории?","options":["60 mph","65 mph","70 mph","55 mph"],"explanation":"В пределах урбанизированных территорий Миссури ограничивает скорость на автомагистралях (interstate), скоростных автодорогах (freeway) и скоростных трассах (expressway) до 60 mph, если не обозначен более низкий лимит. Источник: RSMo 304.010."},"69":{"q":"Какой железнодорожный переезд НЕ требует, чтобы автобус или CMV с табличками HazMat в штате Миссури совершал обязательную остановку?","options":["Любой переезд в сельской местности без мигающих огней","Любой переезд, имеющий крестообразный знак (crossbuck), но без шлагбаума","Любой переезд на дороге с установленным лимитом ниже 45 mph","Переезд трамвайных путей или промышленных маневровых путей в пределах делового района, или переезд, отмеченный знаком «Exempt»"],"explanation":"Обязательная остановка не применяется на переездах трамвайных путей или промышленных маневровых путей в пределах делового района, на заброшенных переездах, отмеченных как таковые, или на переездах, отмеченных официальным знаком «Exempt». Источник: Руководство CDL штата Миссури; 49 CFR 392.10."},"70":{"q":"Какова максимальная допустимая по закону ширина транспортного средства, включая груз, на дорогах штата Миссури, прежде чем потребуется разрешение на негабаритный груз?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"explanation":"Миссури ограничивает ширину транспортного средства, включая груз, до 102 inches (8 feet 6 inches); превышение этого значения требует разрешения на негабаритный груз. Источник: RSMo 304.170; MoDOT Motor Carrier Services."},"71":{"q":"Какова максимальная допустимая по закону высота транспортного средства, включая груз, на системе автомагистралей interstate штата Миссури, прежде чем потребуется разрешение на негабаритный груз?","options":["13 feet 6 inches","15 feet","14 feet","16 feet"],"explanation":"Миссури ограничивает высоту, включая груз, до 14 feet на системе автомагистралей interstate (15 feet на некоторых других дорогах); превышение этого требует разрешения. Источник: RSMo 304.170; MoDOT."},"72":{"q":"При отсутствии разрешения на перегруз, какова максимальная полная масса транспортного средства, обычно допустимая на автомагистралях interstate штата Миссури?","options":["80,000 pounds","73,280 pounds","88,000 pounds","90,000 pounds"],"explanation":"Миссури следует федеральному лимиту в 80,000 pounds максимальной полной массы на системе interstate без разрешения на перегруз. Источник: правила MoDOT по негабаритным/перегруженным грузам; RSMo Глава 304."},"73":{"q":"Когда негабаритный груз обычно можно перемещать по дорогам штата Миссури по стандартному разрешению на однократную поездку?","options":["Только с полуночи до 6:00 утра","В любое время дня и ночи без ограничений","Только в выходные дни и государственные праздники","С получаса до восхода солнца до получаса после захода солнца"],"explanation":"MoDOT обычно ограничивает перемещение негабаритного груза периодом с получаса до восхода солнца до получаса после захода солнца, с дополнительными ограничениями в праздничные и выходные дни. Источник: правила MoDOT по разрешениям на негабаритные/перегруженные грузы."},"74":{"q":"Какова максимальная длина полуприцепа, эксплуатируемого на дорогах штата Миссури без разрешения?","options":["48 feet","53 feet","57 feet","60 feet"],"explanation":"Миссури ограничивает длину полуприцепа до 53 feet на системе дорог, прежде чем потребуется разрешение. Источник: RSMo 304.170."},"75":{"q":"На каком расстоянии школьный автобус в штате Миссури должен быть отчётливо виден приближающимся водителям на дороге без обочины и с ограничением скорости более 60 mph, чтобы трафик мог остановиться?","options":["Не менее 300 футов в каждом направлении","Не менее 200 футов в каждом направлении","Не менее 500 футов в каждом направлении","Не менее 1 000 футов в каждом направлении"],"explanation":"На дороге без обочины и с ограничением скорости более 60 mph останавливающийся школьный автобус должен быть отчётливо виден на расстоянии не менее 500 футов в каждом направлении (300 футов на других дорогах). Источник: RSMo 304.050."},"76":{"q":"Какое ведомство штата Миссури фактически выдаёт документ коммерческих водительских прав (CDL)?","options":["Департамент доходов штата Миссури (Missouri DOR)","Дорожный патруль штата Миссури (Missouri State Highway Patrol)","Департамент транспорта штата Миссури (MoDOT)","Федеральное управление по безопасности грузоперевозок (FMCSA)"],"explanation":"В штате Миссури Департамент доходов (DOR) выдаёт все водительские права, включая CDL, тогда как Дорожный патруль штата Миссури проводит тесты. Источник: страница Missouri DOR Commercial Drivers (dor.mo.gov/driver-license/issuance/commercial/)."},"77":{"q":"В штате Миссури кто проводит тесты CDL на знания (письменный) и навыки?","options":["Дорожный патруль штата Миссури (Missouri State Highway Patrol)","Лицензионные офисы Департамента доходов штата Миссури","Частные обучающие провайдеры, зарегистрированные FMCSA","Департамент транспорта штата Миссури"],"explanation":"Дорожный патруль штата Миссури проводит письменное тестирование знаний CDL на своих экзаменационных станциях для водителей и тест навыков (по записи) на назначенных пунктах тестирования CDL; затем DOR выдаёт права. Источник: страница Missouri DOR Commercial Drivers и Руководство CDL штата Миссури."},"78":{"q":"В течение какого срока действителен ученический коммерческий разрешительный документ (CLP) штата Миссури и можно ли его продлить?","options":["360 дней, и он не подлежит продлению","180 дней, и его можно продлить один раз","1 год, и его можно продлить на второй год","2 года, что соответствует федеральному максимуму"],"explanation":"Миссури выдаёт CLP на срок 360 дней, и он не подлежит продлению; если он истекает, заявитель должен снова пройти всё необходимое тестирование знаний. Источник: Missouri DOR CDL Permit Rule Overview (dor.mo.gov/driver-license/issuance/commercial/cdl-permit.html)."},"79":{"q":"Сколько времени заявитель в штате Миссури должен владеть ученическим коммерческим разрешением (CLP), прежде чем получит право сдавать тест навыков CDL?","options":["Минимум 14 дней","Минимум 30 дней","Минимум 10 дней","Минимум 60 дней"],"explanation":"Заявители на CDL должны владеть CLP минимум 14 дней, прежде чем пройдут тестирование навыков для получения полноценного CDL. Источник: Missouri DOR CDL Permit Rule Overview и федеральное правило о CLP (49 CFR 383.25)."},"80":{"q":"Какое обучение должен пройти заявитель в штате Миссури ПЕРЕД сдачей теста навыков на впервые получаемые права CDL класса A или класса B?","options":["Базовое обучение водителей начального уровня (ELDT) у провайдера из реестра обучающих провайдеров FMCSA (Training Provider Registry)","Утверждённый штатом курс безопасного вождения в офисе DOR","Аудиторный семинар по безопасности Дорожного патруля штата Миссури","Только проводимый работодателем инструктаж на рабочем месте"],"explanation":"Перед тестом навыков CDL (и для некоторых новых отметок) заявители в штате Миссури должны пройти базовое обучение водителей начального уровня (ELDT) у провайдера, внесённого в реестр обучающих провайдеров FMCSA (Training Provider Registry), действующий с 7 февраля 2022 года. Источник: страница Missouri DOR Commercial Drivers; правило FMCSA ELDT (49 CFR Part 380)."},"81":{"q":"Из каких трёх частей состоит тест навыков CDL в штате Миссури, в порядке следования?","options":["Осмотр транспортного средства (предрейсовый), базовое управление транспортным средством и вождение по дороге","Письменные знания, проверка пневматических тормозов и вождение по дороге","Базовое управление транспортным средством, проверка опасных материалов и вождение по дороге","Осмотр транспортного средства, повторный тест знаний и оценка безопасного вождения"],"explanation":"Модернизированный тест навыков CDL штата Миссури имеет три компонента: осмотр транспортного средства (предрейсовый), тест базового управления транспортным средством и тест вождения по дороге. Источник: Руководство CDL штата Миссури и страница Missouri DOR Commercial Drivers."},"82":{"q":"Из каких четырёх категорий самосертификации должен выбрать заявитель на CDL в штате Миссури?","options":["Неисключённая межштатная, исключённая межштатная, неисключённая внутриштатная и исключённая внутриштатная","Межштатная, внутриштатная, региональная и местная","Коммерческая, сельскохозяйственная, аварийная и государственная","Класс A, класс B, класс C и hazmat"],"explanation":"Заявители на CDL в штате Миссури должны самосертифицироваться по одной из четырёх категорий: неисключённая межштатная (NI), исключённая межштатная (EI), неисключённая внутриштатная (NA) и исключённая внутриштатная (EA). Источник: страница Missouri DOR CDL Medical Certification Requirements."},"83":{"q":"Какая категория самосертификации в штате Миссури требует, чтобы водитель был квалифицирован согласно 49 CFR Part 391 и имел при себе медицинское свидетельство DOT?","options":["Неисключённая межштатная (NI)","Исключённая межштатная (EI)","Исключённая внутриштатная (EA)","Исключённая межштатная аварийная (EE)"],"explanation":"Неисключённый межштатный (NI) водитель осуществляет деятельность в межштатной торговле, подпадает под 49 CFR Part 391 и должен получить и поддерживать медицинское свидетельство DOT. Исключённые категории не подпадают под это федеральное требование о медицинском свидетельстве. Источник: страница Missouri DOR CDL Medical Certification."},"84":{"q":"Как информация о медицинском свидетельстве, как правило, поступает в Департамент доходов штата Миссури для учётной записи держателя CDL?","options":["Она передаётся в электронном виде из Национального реестра сертифицированных медицинских экспертов (National Registry of Certified Medical Examiners)","Водитель всегда должен отправлять оригинальную бумажную карточку почтой в MoDOT","Работодатель водителя подаёт её в Дорожный патруль","Она загружается только через стороннего поставщика HAZMAT"],"explanation":"Миссури получает передаваемую в электронном виде информацию о медицинском свидетельстве из Национального реестра сертифицированных медицинских экспертов (National Registry of Certified Medical Examiners), поэтому водители должны обращаться к сертифицированному эксперту, внесённому в этот реестр. Источник: страница Missouri DOR CDL Medical Certification Requirements."},"85":{"q":"Что происходит с неисключённым водителем CDL в штате Миссури, который не поддерживает действующее медицинское свидетельство в своём деле?","options":["CDL понижается, и коммерческие водительские привилегии утрачиваются","CDL приостанавливается ровно на 24 часа, а затем восстанавливается","Ничего, потому что Миссури не отслеживает медицинский статус","Водитель автоматически переводится в категорию исключённой внутриштатной"],"explanation":"Неисключённый водитель, допустивший истечение срока медицинской сертификации, понижается, утрачивая привилегии CDL до тех пор, пока действующее свидетельство не будет в деле. Источник: Missouri DOR CDL Medical Certification FAQ; федеральное правило о медицинской сертификации (49 CFR 383.71/383.73)."},"86":{"q":"Каков стандартный цикл продления CDL в штате Миссури для водителя в возрасте от 21 до 69 лет?","options":["6 лет","4 года","8 лет","10 лет"],"explanation":"Стандартный CDL штата Миссури выдаётся на срок 6 лет для водителей в возрасте от 21 до 69 лет (срок 3 года применяется к водителям 18-20 лет и 70+). Источник: информация Missouri DOR о выдаче водительских прав."},"87":{"q":"CDL штата Миссури с отметкой об опасных материалах (H) связан с каким дополнительным требованием, которое может сократить срок его действия?","options":["Оценка угрозы безопасности TSA (проверка биографических данных)","Ежегодная повторная проверка зрения в офисе DOR","Отдельный дорожный тест Дорожного патруля каждый год","Нотариально заверенное письмо-спонсорство от работодателя"],"explanation":"Отметка HAZMAT требует оценки угрозы безопасности TSA; в штате Миссури отметка (а часто и срок действия прав) связана с этим циклом проверки биографических данных, поэтому он короче стандартного срока в 6 лет. Источник: страница Missouri DOR Commercial Drivers; федеральное правило HAZMAT/TSA (49 CFR 1572)."},"88":{"q":"Каков минимальный возраст для подачи заявления на CDL/CLP штата Миссури для управления коммерческим автотранспортным средством ТОЛЬКО в пределах штата Миссури (внутриштатно)?","options":["18 лет","16 лет","21 год","19 лет"],"explanation":"Миссури требует, чтобы заявители были не моложе 18 лет для получения CLP/CDL для внутриштатного коммерческого вождения; для межштатной деятельности требуется 21 год. Источник: Руководство CDL штата Миссури и страница Missouri DOR Commercial Drivers."},"89":{"q":"Каков минимальный возраст, требуемый для управления коммерческим автотранспортным средством в межштатной торговле по CDL штата Миссури?","options":["21 год","18 лет","19 лет","25 лет"],"explanation":"Водители должны быть не моложе 21 года для осуществления деятельности в межштатной торговле; держатель CDL штата Миссури в возрасте 18-20 лет обычно ограничен внутриштатным вождением. Источник: Руководство CDL штата Миссури; федеральное правило (49 CFR 391.11)."},"90":{"q":"Прежде чем заявителю в штате Миссури может быть выдан CLP, какими водительскими правами он уже должен владеть или получить?","options":["Действующими базовыми (некоммерческими) водительскими правами штата Миссури","Действующим CDL из другого штата","Только ученическим разрешением из любого штата США","Для получения CLP права не требуются"],"explanation":"Заявитель должен иметь или получить базовые водительские права штата Миссури, прежде чем может быть выдан CLP штата Миссури. Источник: Missouri DOR CDL Permit Rule Overview."},"91":{"q":"Когда CLP штата Миссури истекает до того, как держатель сдаст тест навыков, что должен сделать заявитель, чтобы получить новый CLP?","options":["Снова пройти всё необходимое тестирование знаний","Просто оплатить небольшую надбавку за продление без повторного тестирования","Подождать 30 дней, и CLP автоматически восстановится","Сдать только тест навыков, без повторного тестирования знаний"],"explanation":"Поскольку 360-дневный CLP не подлежит продлению, при его истечении заявитель должен пройти всё необходимое тестирование знаний для получения нового CLP. Источник: Missouri DOR CDL Permit Rule Overview."},"92":{"q":"Какую отметку РАЗРЕШЕНО размещать на ученическом коммерческом разрешении (CLP) штата Миссури?","options":["Школьный автобус (S)","Опасные материалы (H)","Цистерна (N) с перевозкой продукта","Двойные/тройные прицепы (T)"],"explanation":"На CLP штата Миссури могут быть отметки «Школьный автобус» (S) и «Пассажирская» (P) (с ограничениями), но отметки «Опасные материалы» (H), «Цистерна» (X/N при загрузке) и «Двойные/тройные» (T) на CLP запрещены. Источник: Missouri DOR CDL Testing/CLP FAQ; федеральное правило о CLP (49 CFR 383.25)."},"93":{"q":"Согласно процессу проверки документов штата Миссури, сколько сотрудников лицензионного офиса должны существенно участвовать в проверке документов заявителя на CDL?","options":["Не менее двух сотрудников","Ровно один сотрудник","Не менее четырёх сотрудников","Проверка сотрудником не требуется, если документы отсканированы"],"explanation":"Миссури требует, чтобы не менее двух сотрудников существенно участвовали в проверке и подтверждении личности, места жительства и тестовых документов коммерческого заявителя. Источник: Missouri DOR CDL Testing/CLP FAQ."},"94":{"q":"Какое утверждение о держателе прав из другого штата, подающем заявление на CLP штата Миссури, является верным?","options":["Он должен установить место жительства в штате Миссури и сначала перейти на базовые права штата Миссури (что может произойти в тот же день)","Миссури свободно выдаёт CLP нерезидентам, имеющим любые действующие права другого штата","Он может сохранить свои права другого штата и никогда не переходить на местные","Он должен подождать 90 дней в качестве резидента штата Миссури, прежде чем совершать любую операцию с CLP"],"explanation":"Миссури не выдаёт CLP нерезиденту; заявитель должен установить место жительства в штате Миссури и сначала перейти на свои базовые права, что можно сделать в тот же день, что и подачу заявления на CLP. Источник: Missouri DOR CDL Testing/CLP FAQ."},"95":{"q":"Каков минимальный проходной балл на тестах знаний CDL (письменных) в штате Миссури?","options":["80 процентов","70 процентов","75 процентов","90 процентов"],"explanation":"Тесты знаний CDL штата Миссури требуют минимального балла 80 процентов для сдачи, что соответствует федеральному стандарту для тестирования знаний CDL. Источник: Руководство CDL штата Миссури; федеральный стандарт теста знаний (49 CFR 383.135)."}},"tr":{"0":{"q":"Özel izin olmaksızın Missouri karayollarında işletilen bir aracın, yükü dahil izin verilen azami genişliği nedir?","options":["96 inç","100 inç","102 inç","108 inç"],"explanation":"RSMo 304.170 uyarınca, hiçbir araç (yükü dahil) Missouri karayollarında 102 inç genişliği aşamaz; gabari lambaları ve aynalar gibi güvenlik donanımları bunun dışındadır. Bunu aşmak için MoDOT'tan gabari dışı (oversize) izni gerekir. Kaynak: Missouri Revised Statutes 304.170; Missouri Driver Guide Bölüm 15."},"1":{"q":"Missouri Eyaletlerarası (Interstate) ve belirlenmiş karayollarında, izin olmaksızın izin verilen azami araç yüksekliği (yük dahil) nedir?","options":["13 feet 6 inç","14 feet","14 feet 6 inç","15 feet"],"explanation":"RSMo 304.170, Eyaletlerarası ve belirlenmiş karayollarında azami yüksekliği yük dahil 14 feet olarak belirler. Kaynak: Missouri Revised Statutes 304.170."},"2":{"q":"Eyaletlerarası ve belirlenmiş güzergahlar DIŞINDAKİ Missouri karayollarında, yük dahil genel azami araç yüksekliği nedir?","options":["13 feet","13 feet 6 inç","14 feet","15 feet"],"explanation":"RSMo 304.170, Eyaletlerarası ve belirlenmiş karayollar dışındaki tüm karayollarında yüksekliği 13 feet 6 inç ile sınırlar. Otomobil taşıyan araçlar istisna olarak 14 feet'e ulaşabilir. Kaynak: Missouri Revised Statutes 304.170."},"3":{"q":"Missouri karayollarında işletilen tek bir motorlu aracın (örneğin sabit kasalı bir kamyon) yük dahil azami uzunluğu nedir?","options":["40 feet","45 feet","48 feet","53 feet"],"explanation":"RSMo 304.170, tek bir motorlu aracın yük dahil uzunluğunu 45 feet ile sınırlar. Daha uzun kombinasyonlar ve yarı römorklar ayrı hükümlerle düzenlenir. Kaynak: Missouri Revised Statutes 304.170."},"4":{"q":"Missouri'de ulusal ağ üzerinde (Eyaletlerarası ve belirlenmiş karayollar) izin verilen azami yarı römork uzunluğu nedir?","options":["48 feet","50 feet","53 feet","57 feet"],"explanation":"Bir çekici/yarı römork kombinasyonundaki yarı römork, Missouri'deki Eyaletlerarası ve belirlenmiş karayollardan oluşan ulusal ağda RSMo 304.170 ve federal standartlara uygun olarak 53 feet uzunluğa kadar olabilir. Kaynak: Missouri Revised Statutes 304.170; Missouri Driver Guide Bölüm 15."},"5":{"q":"Missouri karayollarında, fazla ağırlık izni olmaksızın (daha düşük bir tabela ile belirtilmiş köprü sınırı yoksa) izin verilen azami brüt ağırlık nedir?","options":["73,280 pound","76,000 pound","80,000 pound","84,000 pound"],"explanation":"RSMo 304.180, bir köprü veya yapı için daha düşük bir sınır belirtilmediği sürece, Missouri karayollarında brüt ağırlığı 80,000 pound ile sınırlar. Bu, federal Eyaletlerarası sınırla uyumludur. Kaynak: Missouri Revised Statutes 304.180."},"6":{"q":"Missouri'nin Eyaletlerarası sisteminde tek bir aksta izin verilen azami ağırlık nedir?","options":["18,000 pound","20,000 pound","22,000 pound","24,000 pound"],"explanation":"RSMo 304.180 ve federal standart, Eyaletlerarası sistemde herhangi bir tek aksı 20,000 pound ile sınırlar. Kaynak: Missouri Revised Statutes 304.180."},"7":{"q":"Missouri'nin Eyaletlerarası sisteminde bir tandem aks grubunda izin verilen azami ağırlık nedir?","options":["30,000 pound","34,000 pound","36,000 pound","40,000 pound"],"explanation":"RSMo 304.180 ve federal standart, Eyaletlerarası sistemde bir tandem aks grubunu 34,000 pound ile sınırlar. Kaynak: Missouri Revised Statutes 304.180."},"8":{"q":"Missouri yasalarına göre, bir 'tandem aks' akslar arasındaki mesafeye göre nasıl tanımlanır?","options":["Birbirinden 40 inç veya daha az aralıklı akslar","Birbirinden 40 inçten fazla ama 96 inçten fazla olmayan aralıklı akslar","Birbirinden 96 inçten fazla ama 120 inçten fazla olmayan aralıklı akslar","Aralarındaki mesafeye bakılmaksızın herhangi iki aks"],"explanation":"RSMo 304.180, tandem aksı, uç noktaları arasındaki mesafe 40 inçten fazla ve 96 inçten fazla olmayan, birbiri ardına dizilmiş iki veya daha fazla aks olarak tanımlar. Kaynak: Missouri Revised Statutes 304.180."},"9":{"q":"Eyaletlerarası sistemin parçası OLMAYAN Missouri karayollarında, brüt ağırlık 80,000 pound'u aşmamak kaydıyla, bir araç tek ve tandem aks ağırlık sınırlarını ne kadar aşabilir?","options":["1,000 pound'a kadar","2,000 pound'a kadar","4,000 pound'a kadar","Hiçbir tolerans yoktur"],"explanation":"RSMo 304.180, Eyaletlerarası olmayan karayollarındaki araçların tek ve tandem aks sınırlarını 2,000 pound'a kadar aşmasına izin verir, ancak toplam brüt ağırlık 80,000 pound'u aşamaz. Kaynak: Missouri Revised Statutes 304.180."},"10":{"q":"Missouri'nin Eyaletlerarası ve belirlenmiş karayollarında, bir araç için azami yasal ağırlık öncelikli olarak neye göre belirlenir?","options":["Federal Köprü Formülü ve tablosu","Yerle temas eden lastik sayısı","Aracın tescilli GVWR değeri","Sürücünün CDL sınıfı"],"explanation":"Eyaletlerarası ve belirlenmiş karayollarındaki azami ağırlıklar, izin verilen brüt ağırlığı aks sayısı ve aralarındaki mesafeyle ilişkilendiren ve genel üst sınırı 80,000 pound olan Federal Köprü Formülü ve tablosu tarafından düzenlenir. Kaynak: Missouri Revised Statutes 304.180; FHWA Federal Köprü Formülü."},"11":{"q":"Missouri'de kullanılan Federal Köprü Formülü, izin verilen brüt ağırlığı hangi iki faktöre göre sınırlar?","options":["Lastik basıncı ve yük tipi","Motor beygir gücü ve aks sayısı","Aks sayısı ve aralarındaki mesafe","Araç yaşı ve tescilli ağırlık"],"explanation":"Federal Köprü Formülü (Köprü Formülü B), köprüleri aşırı gerilmeden korumak için, herhangi bir ardışık aks grubunda izin verilen ağırlığı, gruptaki aks sayısı ve dış akslar arasındaki mesafeyi kullanarak belirler. Missouri bunu RSMo 304.180 kapsamında uygular. Kaynak: Missouri Revised Statutes 304.180; FHWA."},"12":{"q":"Missouri karayollarında işletim için ne zaman bir MoDOT gabari dışı/fazla ağırlık izni gereklidir?","options":["Yalnızca gece seyahat ederken","Araç ve yük yasal boyut veya ağırlık sınırlarını aştığında","Yalnızca eyalet dışında tescilli araçlar için","Bir araç 26,001 pound'dan fazla olduğunda her zaman"],"explanation":"Bir araç ve yükü, Missouri'nin genişlik, yükseklik, uzunluk veya ağırlık için yasal sınırlarını aştığında her zaman bir MoDOT gabari dışı/fazla ağırlık izni gereklidir. Yasal sınırlara sığacak şekilde makul ölçüde sökülebilen yükler genellikle izne tabi tutulmaz. Kaynak: Missouri DOT Motor Carrier Services / OSOW; RSMo 304.170-304.200."},"13":{"q":"Standart bir MoDOT tek seferlik gabari dışı/fazla ağırlık izni ne kadar süre geçerlidir?","options":["24 saat","Birbirini izleyen yedi gün","30 gün","Bir yıl"],"explanation":"MoDOT tek seferlik gabari dışı/fazla ağırlık izinleri, birbirini izleyen yedi gün boyunca geçerlidir. Uygun şartları sağlayan sürekli operasyonlar için yıllık (blanket) izinler mevcuttur. Kaynak: Missouri DOT gabari dışı/fazla ağırlık izni düzenlemeleri."},"14":{"q":"Temel MoDOT tek seferlik FAZLA AĞIRLIK izni ücreti nasıl hesaplanır?","options":["Ağırlıktan bağımsız sabit 50 dolar","15 dolar artı yasal brüt ağırlığın üzerindeki her 10,000 pound için 20 dolar","100 dolar artı aks başına 5 dolar","Seyahat edilen mil başına 25 dolar"],"explanation":"MoDOT, 15 dolar temel tek seferlik izin ücreti artı yasal brüt ağırlığın üzerindeki her 10,000 pound (veya kesri) için 20 dolar ücret alır; çok ağır taşımalar bir köprü ve yol analizi ücreti ekler. Kaynak: Missouri DOT gabari dışı/fazla ağırlık izni ücret tarifesi."},"15":{"q":"Missouri'deki çoğu gabari dışı yük için, gündüz seyahati genellikle hangi zaman aralığıyla sınırlandırılır?","options":["Yalnızca gece yarısından öğlene kadar","Gün doğumundan yarım saat önce ile gün batımından yarım saat sonrası arası","Yalnızca sabah 8:00 ile öğleden sonra 4:00 arası","Günün 24 saati, herhangi bir zaman"],"explanation":"Missouri'de izinli gabari dışı yükler genellikle gün doğumundan yarım saat önce ile gün batımından yarım saat sonrasına kadar seyahat edebilir; yalnızca fazla ağırlıkta olan (yasal boyutlu) yükler sürekli hareket edebilir. Kaynak: Missouri DOT gabari dışı/fazla ağırlık izni düzenlemeleri."},"16":{"q":"Missouri'nin tarımsal ağırlık istisnası kapsamında, Eyaletlerarası sistem DIŞINDAKİ karayollarında bir çiftlikten süt taşıyan veya canlı hayvan taşıyan bir araç için azami brüt ağırlık nedir?","options":["80,000 pound","82,000 pound","85,500 pound","90,000 pound"],"explanation":"RSMo 304.180, bir çiftlikten işleme tesisine süt taşıyan veya canlı hayvan taşıyan bir aracın, Eyaletlerarası sistem dışındaki karayollarında 85,500 pound brüt ağırlığa kadar ulaşmasına izin verir. Bu, Eyaletlerarası sistemde geçerli değildir. Kaynak: Missouri Revised Statutes 304.180; Missouri Dept. of Agriculture."},"17":{"q":"Missouri'nin hasat sezonu istisnası kapsamında, hasat sırasında tahıl veya tahıl yan ürünleri taşıyan araçlar, Eyaletlerarası olmayan karayollarında normal ağırlık sınırlarını ne kadar aşabilir?","options":["Yüzde 5","Yüzde 10","Yüzde 15","Sabit 2,000 pound"],"explanation":"RSMo 304.180, hasat zamanlarında tahıl ve tahıl yan ürünü taşıyıcılarının, Eyaletlerarası sistem dışındaki karayollarında azami ağırlık sınırlarını yüzde 10'a kadar aşmasına izin verir. Kaynak: Missouri Revised Statutes 304.180; Missouri Dept. of Agriculture."},"18":{"q":"Missouri'nin artırılmış ağırlık tarımsal istisnasını kullanan bir canlı hayvan veya tahıl taşıyıcısı hangi kısıtlamaya uymalıdır?","options":["Eyaletlerarası sistemi kullanmamalı veya yükün ağırlığının altında bir sınır tabelası olan bir köprüden geçmemelidir","Yalnızca gece seyahat etmelidir","Her zaman iki işaretçi (flag person) bulundurmalıdır","Yalnızca çiftliğin 25 mil çevresinde işletilebilir"],"explanation":"RSMo 304.180 uyarınca, artırılmış tarımsal ağırlık iznini kullanan taşıyıcılar, Eyaletlerarası karayolu sisteminin herhangi bir bölümünü kullanamaz ve araç ile yükün brüt ağırlığından daha düşük bir sınır tabelası olan herhangi bir köprüden geçemez. Kaynak: Missouri Revised Statutes 304.180; Missouri Dept. of Agriculture."},"19":{"q":"Missouri boyut kuralları kapsamında otomobil taşıyıcıları için genellikle izin verilen azami ön ve arka taşma (overhang) nedir?","options":["Önde 2 feet, arkada 3 feet","Önde 3 feet, arkada 4 feet","Önde 4 feet, arkada 6 feet","Hiçbir taşmaya izin verilmez"],"explanation":"RSMo 304.170 kapsamındaki Missouri boyut kuralları, otomobil taşıyıcılarına 3 feet'ten fazla olmayan ön taşma ve 4 feet'ten fazla olmayan arka taşma izni verir. Kaynak: Missouri Revised Statutes 304.170."},"20":{"q":"Missouri'de, çekilen araçların GVWR değeri 10,000 pound'u aşması koşuluyla, 26,001 pound veya daha fazla Brüt Kombinasyon Ağırlık Değeri (GCWR) olan herhangi bir araç kombinasyonunu işletmek için hangi CDL sınıfı gereklidir?","options":["Sınıf A","Sınıf B","Sınıf C","Sınıf E"],"explanation":"Missouri, Sınıf A'yı, çekilen birimin GVWR değeri 10,000 pound'u aşan ve GCWR değeri 26,001 veya daha fazla pound olan herhangi bir araç kombinasyonu olarak tanımlar. Kaynak: Missouri Commercial Driver License Manual, Bölüm 1 (CDL Sınıflandırmaları)."},"21":{"q":"Missouri kuralları uyarınca, 26,001+ pound GVWR'ye sahip tek bir güç ünitesinin Sınıf B yerine Sınıf A CDL gerektirmesi için çekilen aracın azami GVWR değeri nedir?","options":["8,000 pound","10,000 pound","15,000 pound","26,001 pound"],"explanation":"Bir Sınıf B CDL, 10,000 pound GVWR'yi AŞMAYAN bir birim çeken 26,001+ lbs GVWR'ye sahip tek bir aracı kapsar; çekilen birim 10,000 lbs GVWR'yi aşarsa, Sınıf A gereklidir. Kaynak: Missouri Commercial Driver License Manual, Bölüm 1."},"22":{"q":"Missouri CDL Kılavuzuna göre, bir Sınıf C CDL, 26,001 pound GVWR'nin altındaki bir araca yalnızca tehlikeli maddeler için plakartlandığında VEYA kaç kişiyi taşımak üzere tasarlandığında uygulanır?","options":["Sürücü hariç 9 veya daha fazla kişi","Sürücü dahil 12 veya daha fazla kişi","Sürücü hariç 15 veya daha fazla kişi","Operatör dahil 16 veya daha fazla kişi"],"explanation":"Missouri'nin Sınıf C'si, tehlikeli maddeler için plakartlanmış veya operatör dahil 16 veya daha fazla kişiyi taşımak üzere tasarlanmış, 26,001 lbs GVWR'nin altındaki tek bir aracı kapsar. Kaynak: Missouri Commercial Driver License Manual, Bölüm 1."},"23":{"q":"Yalnızca eyalet içi (Missouri içinde) sürüş için bir Missouri CDL almak için asgari yaş nedir?","options":["16 yaş","18 yaş","19 yaş","21 yaş"],"explanation":"Missouri CDL uygunluğu, eyalet içi işletim için (21 yaşına kadar) 18 yaşı ve eyaletlerarası işletim için 21 yaşı belirtir. Kaynak: Missouri Commercial Driver License Manual, 'Missouri CDL Uygunluğu.'"},"24":{"q":"Bir Missouri sürücüsü eyalet sınırları ötesinde (eyaletlerarası ticaret) ticari bir araç işletmek istiyor. Eyaletlerarası işletim için bir CDL'ye sahip olmanın asgari yaşı nedir?","options":["18 yaş","19 yaş","20 yaş","21 yaş"],"explanation":"Missouri, eyaletlerarası ticarette işletim yapmak için bir sürücünün 21 yaşında olmasını gerektirir; 18-20 yaş arası CDL sahipleri eyalet içi işletimle sınırlıdır. Kaynak: Missouri Commercial Driver License Manual, 'Missouri CDL Uygunluğu.'"},"25":{"q":"Missouri'de CDL beceri (yol) testini almadan önce, bir başvuru sahibinin bir Ticari Öğrenci İzni (CLP) en az ne kadar süre elinde bulundurmuş olması gerekir?","options":["7 gün","14 gün","30 gün","60 gün"],"explanation":"Federal ve Missouri kuralları, beceri testi alınmadan önce CLP'nin en az 14 gün elde bulundurulmasını gerektirir. Kaynak: Missouri DOR CDL İzin Kuralı Genel Bakış; 49 CFR 383.25."},"26":{"q":"Bir Missouri Ticari Öğrenci İzni (CLP) ne kadar süre geçerlidir ve yenilenebilir mi?","options":["180 gün, bir kez yenilenebilir","360 gün, yenilenemez","1 yıl, yıllık yenilenebilir","2 yıl, yenilenemez"],"explanation":"Bir Missouri CLP, 360 gün için verilir ve yenilenemez; süresi dolarsa, başvuru sahibinin gerekli bilgi testlerini yeniden alması gerekir. Kaynak: Missouri DOR CDL İzin Kuralı Genel Bakış."},"27":{"q":"Missouri'de, sürücü dahil 16 veya daha fazla kişiyi taşımak üzere tasarlanmış ticari bir aracı sürmek için hangi onay (endorsement) gereklidir?","options":["S (Okul Otobüsü) onayı","P (Yolcu) onayı","N (Tanker) onayı","T (İkili/Üçlü Römork) onayı"],"explanation":"Sürücü dahil 16 veya daha fazla kişiyi taşımak üzere tasarlanmış araçlar için P (Yolcu) onayı gereklidir; bir bilgi testi ve bir yolcu aracında bir beceri testi gerektirir. Kaynak: Missouri Commercial Driver License Manual, Onaylar bölümü."},"28":{"q":"Missouri'de, bireysel anma kapasitesi 119 galondan fazla ve toplam anma kapasitesi ne kadar olan bir tankta sıvı veya gaz taşıyan bir araç için Tank Aracı (N) onayı gereklidir?","options":["500 galon veya daha fazla","750 galon veya daha fazla","1,000 galon veya daha fazla","1,500 galon veya daha fazla"],"explanation":"N onayı, bireysel anma kapasitesi 119 galondan fazla ve toplam anma kapasitesi 1,000 galon veya daha fazla olan tanklara uygulanır. Kaynak: Missouri Commercial Driver License Manual, Onaylar bölümü; 49 CFR 383.5."},"29":{"q":"Missouri'deki Sınıf A sürücülerinin ikili veya üçlü römork çekebilmeleri için önce hangi onaya ihtiyaçları vardır?","options":["N (Tanker) onayı","T (İkili/Üçlü Römork) onayı","X (Kombinasyon) onayı","H (Tehlikeli Maddeler) onayı"],"explanation":"T (İkili/Üçlü Römork) onayı, özel bir bilgi sınavının geçilmesini gerektirir; birden fazla römork çekmek isteyen Sınıf A sürücülerine uygulanır. Kaynak: Missouri Commercial Driver License Manual, Onaylar bölümü."},"30":{"q":"Aşağıdaki onaylardan hangisi bir Missouri Ticari Öğrenci İznine (CLP) EKLENEMEZ?","options":["P (Yolcu)","S (Okul Otobüsü)","N (Tanker)","T (İkili/Üçlü Römork)"],"explanation":"Bir Missouri CLP'sine eklenebilecek tek onaylar P (Yolcu), S (Okul Otobüsü) ve N (Tanker)'dir. H, X ve T bir CLP üzerinde yasaktır. Kaynak: Missouri Commercial Driver License Manual; 49 CFR 383.153(b); Section 302.700, RSMo."},"31":{"q":"Tehlikeli Maddeler (H) onayı bir Missouri CDL'sine eklenmeden önce, başvuru sahibinin yazılı testi geçmesi VE neyin onayını alması gerekir?","options":["Bir TSA güvenlik tehdidi değerlendirmesi (geçmiş kontrolü)","Bir görme uzmanının muafiyet belgesi","Bir Missouri işveren sponsorluk mektubu","Bir DOT yol kenarı denetim izni"],"explanation":"30 soruluk HazMat yazılı testine ek olarak, başvuru sahiplerinin H (veya X) onayı eklenmeden önce parmak izi vermesi ve bir TSA güvenlik tehdidi değerlendirmesinin onayını alması gerekir. Kaynak: Missouri DOR HazMat Onay Gereklilikleri; 49 CFR 1572."},"32":{"q":"Tehlikeli Maddeler (H veya X) onayı taşıyan bir Missouri CDL'si, TSA güvenlik tehdidi değerlendirmesi tamamlandıktan en fazla kaç yıl sonra geçerliliğini yitirir?","options":["2 yıl","4 yıl","5 yıl","8 yıl"],"explanation":"TSA geçmiş kontrolü beş yıl geçerli olduğundan, H veya X onayına sahip bir CDL, güvenlik tehdidi değerlendirmesi tamamlandıktan en fazla 5 yıl sonra geçerliliğini yitirir. Kaynak: Missouri DOR HazMat Onay / HME SSS; 49 CFR 1572."},"33":{"q":"Missouri'de, Okul Otobüsü (S) onayı, ek olarak hangi onayın da alınmasını gerektirir?","options":["N (Tanker) onayı","P (Yolcu) onayı","H (Tehlikeli Maddeler) onayı","T (İkili/Üçlü Römork) onayı"],"explanation":"Federal ve Missouri kuralları uyarınca, Okul Otobüsü (S) onayı, Yolcu (P) onayını gerektirir; başvuru sahibinin okul otobüsü bilgi testini ve bir okul otobüsünde bir beceri testini geçmesi gerekir. Kaynak: Missouri Commercial Driver License Manual; 49 CFR 383.93."},"34":{"q":"Missouri'de CDL beceri testini almadan önce (7 Şubat 2022'den itibaren geçerli), bir başvuru sahibinin nerede listelenen bir sağlayıcıdan Giriş Düzeyi Sürücü Eğitimini (ELDT) tamamlaması gerekir?","options":["Missouri State Highway Patrol onaylı okul listesi","FMCSA Eğitim Sağlayıcı Sicili (Training Provider Registry)","Missouri Department of Revenue tedarikçi listesi","Başvuru sahibinin seçtiği herhangi bir özel CDL okulu"],"explanation":"ELDT, ilk CDL veya belirli onaylar için beceri testinden önce FMCSA'nın Eğitim Sağlayıcı Sicilinde (Training Provider Registry) listelenen bir sağlayıcı aracılığıyla tamamlanmalıdır. Kaynak: Missouri DOR Ticari Sürücüler sayfası; 49 CFR Part 380."},"35":{"q":"Bir Missouri CDL'si için tıbbi durumu öz beyanla bildirirken, bir sürücünün kaç olası kategori arasından seçim yapması gerekir?","options":["2 kategori","3 kategori","4 kategori","6 kategori"],"explanation":"Sürücüler dört kategoriden birine öz beyanla bildirir: muafiyetsiz eyaletlerarası, muafiyetli eyaletlerarası, muafiyetsiz eyalet içi veya muafiyetli eyalet içi. Kaynak: Missouri Commercial Driver License Manual, Tıbbi Öz Beyan; 49 CFR 383.71."},"36":{"q":"'Muafiyetsiz eyaletlerarası' olarak beyanda bulunan bir Missouri CDL başvuru sahibinin ayrıca ne yapması gerekir?","options":["Geçerli bir tıbbi muayene sertifikası (DOT tıbbi kartı) sağlamalı ve güncel tutmalıdır","Yalnızca Missouri'ye özgü bir eyalet içi tıbbi muafiyet sunmalıdır","Daha fazla bir şey sağlamamalıdır; beyan tek başına yeterlidir","Bir Missouri optometristinden yıllık görme testi almalıdır"],"explanation":"Muafiyetsiz eyaletlerarası olarak öz beyanda bulunan bir sürücü, federal tıbbi standartlara tabidir ve geçerli bir tıbbi muayene sertifikası sunup güncel tutmalıdır, aksi takdirde lisansının düşürülmesi (downgrade) riskiyle karşı karşıya kalır. Kaynak: Missouri Commercial Driver License Manual, Öz Beyan; 49 CFR 391.41."},"37":{"q":"Bir CDL için başvururken Missouri ikametgahını tesis etmek için, başvuru sahibinin ikamet adresini doğrulayan kaç belge gereklidir?","options":["Bir belge","İki belge","Üç belge","Önceki bir lisans varsa belge gerekmez"],"explanation":"Missouri, kimlik kanıtı, Sosyal Güvenlik numarası ve yasal mevcudiyete ek olarak, Missouri ikametgahını/yerleşimini gösteren iki kabul edilebilir belge gerektirir. Kaynak: Missouri DOR Ticari Sürücüler sayfası; Missouri CDL Manual, Uygunluk."},"38":{"q":"Missouri, bir CDL başvuru sahibinden hangi yasal mevcudiyet durumunu gerektirir?","options":["Statüsünden bağımsız olarak herhangi bir geçerli vize sahibi","ABD vatandaşı veya yasal daimi ikamet sahibi","Yalnızca ABD vatandaşı","Sosyal Güvenlik numarası olan herhangi bir başvuru sahibi"],"explanation":"Missouri, CDL başvuru sahiplerinin bir ABD vatandaşı veya yasal daimi ikamet statüsüne sahip bir ABD vatandaşı olmayan kişi olmasını gerektirir. Kaynak: Missouri DOR Ticari Sürücüler sayfası; Missouri CDL Manual, Uygunluk."},"39":{"q":"Her bir Missouri CDL bilgi (yazılı) sınavında asgari geçme puanı nedir?","options":["%70","%75","%80","%85"],"explanation":"Missouri, Highway Patrol test merkezlerinde uygulanan her CDL yazılı sınavında %80 puan gerektirir (örneğin, 50 soruluk Genel Bilgi, 30 soruluk HazMat, 20 soruluk onay testleri). Kaynak: Missouri Commercial Driver License Manual, Bölüm 14 (CDL Yazılı Sınavları)."},"40":{"q":"Missouri'de, bir sürücünün ticari bir motorlu araç (CMV) işletirken sahip olabileceği, büyük bir ihlal sayılmadan önceki azami kandaki alkol konsantrasyonu (BAC) nedir?","options":["%0.04","%0.08","%0.02","%0.10"],"explanation":"Missouri, %0.04 veya daha yüksek BAC ile bir CMV işletmeyi yasaklar (ticari olmayan sürücüler için geçerli %0.08 sınırının yarısı). Kaynak: Missouri DOR Form 5231, 'Ticari Motorlu Araç Operatörleri ve Yasa'; 49 CFR 383.51."},"41":{"q":"Missouri'nin zımni rıza (implied consent) yasası uyarınca, bir CDL sahibi yasal olarak talep edildiğinde kimyasal (kan/nefes) bir testi yapmayı reddederse ne olur?","options":["CDL, ilk DWI ile aynı şekilde 1 yıl için iptal edilir (disqualified)","İptal olmaksızın yalnızca 500 dolar para cezası","60 günlük CDL iptali","Reddetme kanıt olarak kullanılamayacağı için ceza yoktur"],"explanation":"Bir CDL sahibi olarak veya bir CMV işletirken kan ve/veya nefes testini reddetmek, büyük bir ihlal olarak ele alınır ve ilk DWI mahkumiyetiyle aynı şekilde 1 yıllık CDL iptali ile sonuçlanır. Kaynak: Missouri DOR Form 5231; Missouri zımni rıza yasası (Chapter 577 RSMo); 49 CFR 383.51."},"42":{"q":"Tehlikeli madde taşınmadığı durumlarda, İLK büyük ihlal (örneğin bir CMV'de DWI) için bir CDL ne kadar süre iptal edilir?","options":["1 yıl","3 yıl","60 gün","Ömür boyu"],"explanation":"Alkol/uyuşturucu etkisi altında araç kullanma, bir testi reddetme veya bir kaza yerinden ayrılma dahil olmak üzere ilk büyük ihlal, Missouri'de 1 yıllık CDL iptaliyle sonuçlanır. Kaynak: Missouri DOR Form 5231; 49 CFR 383.51."},"43":{"q":"Bir sürücü, tehlikeli maddeler için plakartlanmış bir araç işletirken ilk büyük ihlali işler. İptal süresi nedir?","options":["3 yıl","1 yıl","5 yıl","Ömür boyu"],"explanation":"Plakartlanmış tehlikeli madde taşırken işlenen ilk büyük ihlal, standart 1 yıl yerine 3 yıllık CDL iptali taşır. Kaynak: Missouri DOR Form 5231; 49 CFR 383.51."},"44":{"q":"İKİNCİ bir büyük ihlalin (örneğin ikinci bir DWI) bir Missouri CDL'si üzerindeki sonucu nedir?","options":["Ömür boyu iptal","3 yıllık iptal","10 yıllık iptal","1 yıllık iptal"],"explanation":"Listelenen büyük ihlallerden herhangi biri için ikinci bir mahkumiyet, Missouri'de ömür boyu CDL iptaliyle sonuçlanır (bazı sürücüler federal kılavuz ilkeler uyarınca 10 yıl sonra yeniden lisans almaya uygun olabilir). Kaynak: Missouri DOR Form 5231; 49 CFR 383.51."},"45":{"q":"3 yıllık bir süre içinde kaç ciddi trafik ihlali 60 günlük CDL iptaliyle sonuçlanır?","options":["2","3","4","1"],"explanation":"Üç yıl içinde (bir CMV'de) iki ciddi trafik mahkumiyeti 60 günlük CDL iptaliyle sonuçlanır. Kaynak: Missouri DOR Form 5231; 49 CFR 383.51."},"46":{"q":"3 yıl içinde kaç ciddi trafik ihlali 120 günlük CDL iptaline yol açar?","options":["3 veya daha fazla","2","5 veya daha fazla","4 veya daha fazla"],"explanation":"Üç yıl içinde üç veya daha fazla ciddi trafik mahkumiyeti 120 günlük CDL iptaliyle sonuçlanır. Kaynak: Missouri DOR Form 5231; 49 CFR 383.51."},"47":{"q":"Aşağıdakilerden hangisi bir Missouri CDL sahibi için 'ciddi trafik ihlali' olarak sınıflandırılır?","options":["Belirtilen sınırın 15 mph veya daha fazla üzerinde hız yapmak","Belirtilen sınırın 5 mph üzerinde hız yapmak","Bir park ihlali","Bir ekipman aydınlatma ihlali"],"explanation":"Ciddi trafik ihlalleri arasında sınırın 15 mph veya daha fazla üzerinde hız yapmak, dikkatsiz araç kullanmak, uygunsuz veya düzensiz şerit değiştirmek ve çok yakın takip etmek yer alır. Hafif hız aşımı ve park ihlalleri 'ciddi' değildir. Kaynak: Missouri DOR Form 5231; 49 CFR 383.51."},"48":{"q":"Bir sürücünün İLK demiryolu-karayolu hemzemin geçit ihlali için iptal süresi nedir?","options":["60 gün","30 gün","120 gün","1 yıl"],"explanation":"İlk demiryolu-karayolu hemzemin geçit ihlali, asgari 60 günlük CDL iptaliyle sonuçlanır. Kaynak: Missouri DOR Form 5231; 49 CFR 383.51."},"49":{"q":"Bir CDL sahibi, 3 yıl içinde İKİNCİ bir demiryolu-karayolu hemzemin geçit ihlali işler. İptal süresi nedir?","options":["120 gün","60 gün","1 yıl","180 gün"],"explanation":"Üç yıl içinde ikinci bir demiryolu-karayolu hemzemin geçit ihlali, asgari 120 günlük iptalle sonuçlanır. Kaynak: Missouri DOR Form 5231; 49 CFR 383.51."},"50":{"q":"3 yıllık bir süre içinde ÜÇÜNCÜ bir demiryolu-karayolu hemzemin geçit ihlali için iptal süresi nedir?","options":["1 yıl","120 gün","180 gün","60 gün"],"explanation":"Üç yıl içinde üçüncü veya sonraki bir demiryolu-karayolu hemzemin geçit ihlali, asgari 1 yıllık iptalle sonuçlanır. Kaynak: Missouri DOR Form 5231; 49 CFR 383.51."},"51":{"q":"İptalin yanı sıra, bir sürücü bir hizmet dışı emrini ihlal etmekten hangi hukuki para cezası aralığıyla karşılaşabilir?","options":["1,000 ila 2,500 dolar","100 ila 500 dolar","250 ila 750 dolar","5,000 ila 10,000 dolar"],"explanation":"Bir hizmet dışı emrini ihlal eden bir sürücü, iptale ek olarak, 1,000 dolardan az ve 2,500 dolardan fazla olmayan bir hukuki para cezasına tabidir. Kaynak: 49 CFR 383.53; Missouri DOR Form 5231."},"52":{"q":"RSMo 304.822 uyarınca, eller serbest / mesajlaşma yasağının İLK ihlali için para cezası nedir?","options":["150 dolar","50 dolar","250 dolar","500 dolar"],"explanation":"Missouri'nin Siddens Bening Hands Free Yasası uyarınca, para cezası ilk ihlal için 150 dolar, ikinci için 250 dolar ve belirli bir süre içindeki üçüncü için 500 dolardır. Kaynak: Section 304.822 RSMo."},"53":{"q":"Bir CDL sahibi, kontrollü bir maddenin üretimi veya dağıtımıyla ilgili bir suç işlemek için bir CMV kullanmaktan mahkum edilir. İptal nedir?","options":["Yeniden lisans almaksızın ömür boyu iptal","1 yıllık iptal","3 yıllık iptal","10 yıllık iptal"],"explanation":"Kontrollü bir maddenin üretimi, dağıtımı veya temini ile ilgili bir suçun işlenmesinde bir CMV kullanmak, yeniden lisans alma olasılığı olmaksızın ömür boyu iptalle sonuçlanır. Kaynak: Missouri DOR Form 5231; 49 CFR 383.51."},"54":{"q":"Aşağıdakilerden hangisi, ilk mahkumiyette 1 yıllık CDL iptalini tetikleyen büyük bir ihlaldir?","options":["Bir CMV'nin karıştığı bir kaza yerinden ayrılmak","Çok yakın takip etmek","Uygunsuz şerit değiştirme","Sınırın 15 mph üzerinde hız yapmak"],"explanation":"Bir CMV'nin karıştığı bir kaza yerinden ayrılmak büyük bir ihlaldir (1 yıllık ilk ihlal iptali). Çok yakın takip etmek, uygunsuz şerit değiştirme ve 15+ mph hız aşımı, büyük ihlaller değil, 'ciddi' ihlallerdir. Kaynak: Missouri DOR Form 5231; 49 CFR 383.51."},"55":{"q":"Bir sürücü, bir CMV'nin ihmalkar işletimi yoluyla (örneğin taşıtla adam öldürme) bir ölüme neden olur. Bu, CDL açısından nasıl sınıflandırılır?","options":["1 yıllık ilk ihlal iptali taşıyan büyük bir ihlal","60 gün taşıyan ciddi bir trafik ihlali","120 gün taşıyan bir demiryolu geçit ihlali","90 gün taşıyan bir hizmet dışı ihlali"],"explanation":"Bir CMV'nin ihmalkar veya suç teşkil eden işletimi yoluyla bir ölüme neden olmak büyük bir ihlaldir ve ilk mahkumiyette 1 yıllık iptalle sonuçlanır (hazmat plakartlıysa 3 yıl; ikinci bir büyük ihlalde ömür boyu). Kaynak: Missouri DOR Form 5231; 49 CFR 383.51."},"56":{"q":"Missouri'deki kırsal bir eyaletler arası karayolunda (interstate) veya otoyolda (freeway), daha düşük bir limitin belirtilmediği durumlarda, ticari bir motorlu araca (kamyona) uygulanan azami belirtilmiş hız limiti nedir?","options":["70 mph","65 mph","60 mph","55 mph"],"explanation":"Missouri, kırsal eyaletler arası karayollarında ve otoyollarda azami hızı 70 mph olarak belirler ve kamyonlar için ayrı, daha düşük bir eyalet çapında hız limiti bulunmadığından, daha düşük bir hız belirtilmediği sürece kamyonlar da aynı 70 mph ile seyredebilir. Kaynak: RSMo 304.010."},"57":{"q":"Missouri yasalarına göre, brüt ağırlığı 48,000 pound'dan fazla için tescil edilmiş kamyonların en sol şeritte gitmesi hangi yollarda yasaktır?","options":["Belirtilen limiti 55 mph veya daha yüksek olan herhangi bir iki şeritli eyalet karayolu","Her yönde iki veya daha fazla şeride sahip tüm kırsal eyaletler arası karayolları","Şerit sayısından bağımsız olarak eyaletin herhangi bir yerindeki bölünmüş herhangi bir karayolu","Aynı yönde üç veya daha fazla şeride sahip, kentleşmiş alanlardaki eyaletler arası karayolları, otoyollar veya ekspres yollar"],"explanation":"Missouri, brüt ağırlığı 48,000 pound'dan fazla için tescil edilmiş kamyonların, aynı yönde ilerleyen üç veya daha fazla şeride sahip kentleşmiş alanlardaki eyaletler arası karayolları, otoyollar veya ekspres yollardaki en sol şeritte gitmesini yasaklar. Kaynak: RSMo 304.015."},"58":{"q":"Missouri'de, aynı yönde ilerleyen iki veya daha fazla şeride sahip bir karayolunda, bir araç genel olarak nerede sürülmelidir?","options":["O an en az trafik olan şeritte","Sollarken, sola dönüşe hazırlanırken veya işaretler/yol çizgileriyle aksi yönde yönlendirilen durumlar hariç, sağ şeritte","Sağ şeridi yola giren trafiğe açık tutmak için sol şeritte","Aynı yönde üç şeride sahip herhangi bir yolda orta şeritte"],"explanation":"Missouri, aynı yönde iki veya daha fazla şeride sahip karayollarında tüm araçların sağ şeritte sürülmesini gerektirir; sollama yaparken, uygun bir sola dönüşe hazırlanırken veya trafik çizgileri, işaretleri ya da sinyalleriyle aksi yönde yönlendirilen durumlar hariçtir. Kaynak: RSMo 304.015."},"59":{"q":"Missouri'de bir demiryolu geçidine yaklaşan bir otobüs veya plakart (tehlike işaretli) tehlikeli madde aracı, en yakın raydan ne kadar mesafede durmalıdır?","options":["100 feet içinde ancak 25 feet'ten az olmamak üzere","75 feet içinde ancak 10 feet'ten az olmamak üzere","50 feet içinde ancak 15 feet'ten az olmamak üzere","25 feet içinde ancak 5 feet'ten az olmamak üzere"],"explanation":"Otobüsler ve plakartlı HazMat araçları, en yakın raydan 50 feet içinde ancak 15 feet'ten az olmamak üzere durmalı, ardından geçmeden önce bakıp dinlemelidir. Kaynak: Missouri CDL Kılavuzu; 49 CFR 392.10."},"60":{"q":"Missouri'de bir karayolunda, durma sinyalini gösteren ve durmuş bir okul otobüsüyle karşılaşan veya onu sollayan bir aracın sürücüsü ne yapmalıdır?","options":["Otobüse doğru veya arkasında giderken, otobüse ulaşmadan önce aracı durdurmalı","Sadece otobüsle aynı yönde gidiyorsa durmalı","10 mph'ye yavaşlayıp durmadan dikkatlice geçmeli","Sadece yol kenarında gözle görülür şekilde çocuklar varsa durmalı"],"explanation":"Missouri, her iki yönden durmuş ve durma sinyali veren bir okul otobüsüyle karşılaşan veya onu sollayan bir sürücünün, otobüse ulaşmadan önce aracı durdurmasını gerektirir. İstisna, dört veya daha fazla şeritli karayollarındaki ayrı yollar veya karşı yöndeki trafik içindir. Kaynak: RSMo 304.050."},"61":{"q":"Hangi Missouri istisnası, bir sürücünün çocuk indiren veya bindiren bir okul otobüsü için durmamasına izin verir?","options":["Sürücü o an 25 mph'den daha yavaş gidiyordur","Otobüsün kehribar (sarı) ışıkları yanıp sönüyordur ancak kırmızı ışıkları yanmıyordur","Otobüs durduğunda sürücü ondan 100 feet'ten daha uzaktadır","Otobüs farklı bir yoldadır veya dört ya da daha fazla şeritli bir karayolunda karşı yönde gitmektedir"],"explanation":"Ayrı yollara sahip bir karayolundaki bir sürücünün, farklı bir yoldaki bir okul otobüsü veya dört ya da daha fazla şeritli bir karayolunda karşı yönde ilerleyen bir okul otobüsü için durması gerekmez. Kaynak: RSMo 304.050."},"62":{"q":"Missouri'nin Move Over (Şerit Değiştir) yasası uyarınca, bir sürücü, en az dört şeride (aynı yönde iki veya daha fazla) sahip bir yolda uyarı ışıkları yanan duran bir acil durum, çekici, altyapı veya MoDOT aracına yaklaştığında, sürücü ilk olarak ne yapmalıdır?","options":["Duran araç ayrılana kadar tamamen durmalı","Güvenli bir şekilde yapılabiliyorsa, duran araca bitişik olmayan bir şeride geçiş yapmalı","Duran aracı geçerken kornaya sürekli basmalı","Sağ banketinе çekip her şey güvende sinyalini beklemeli"],"explanation":"Missouri'nin Move Over yasası, yolda aynı yönde iki veya daha fazla şeritle birlikte en az dört şerit bulunduğunda, sürücünün güvenli bir şekilde yapılabildiğinde duran araca bitişik olmayan bir şeride geçmesini gerektirir. Kaynak: RSMo 304.022."},"63":{"q":"Missouri'nin Move Over yasası uyarınca, duran bir acil durum/altyapı aracından uzağa şerit değiştirmek güvensiz veya imkansızsa, sürücü bunun yerine ne yapmalıdır?","options":["Trafik açılana kadar mevcut şeritte tamamen durmalı","Belirtilen hız limitini koruyup düz devam etmeli","Gereken dikkatle ilerlemeli ve hızı azaltarak yol koşulları için güvenli bir hızı korumalı","Tehlike sinyallerini açıp olay yerini hızla geçmeli"],"explanation":"Şerit değişikliği güvenli bir şekilde yapılamadığında, Missouri sürücünün gereken dikkatle ilerlemesini ve aracın hızını azaltarak yol koşulları için güvenli bir hızı korumasını gerektirir. Kaynak: RSMo 304.022."},"64":{"q":"Bir Missouri ticari sürücüsü, karayolunda durduğunda kullanmak üzere uyarı cihazları taşımalıdır. Standart gereklilik neyden oluşur?","options":["Üç yansıtıcı üçgen","İki yansıtıcı üçgen ve üç işaret fişeği","Dört yansıtıcı üçgen","Bir yansıtıcı üçgen ve iki bayrak"],"explanation":"Bir CMV, yolun üzerinde veya kenarında durulduğunda yerleştirmek için üç yansıtıcı üçgen (veya onaylı eşdeğerleri) ile donatılmalıdır. Kaynak: Missouri CDL Kılavuzu; 49 CFR 393.95 / 392.22."},"65":{"q":"Bir Missouri ticari aracı bölünmüş veya tek yönlü bir yolda durduğunda, üç uyarı üçgeni nereye yerleştirilmelidir?","options":["Üçü de aracın tam arkasında 10 feet mesafede","Biri 10 feet arkada, biri 100 feet arkada ve biri 100 feet önde","Aracın arkasında yaklaşık 25, 50 ve 100 feet mesafede","Aracın arkasında, yaklaşan trafiğe doğru yaklaşık 10, 100 ve 200 feet mesafede"],"explanation":"Bölünmüş veya tek yönlü bir yolda, üç üçgenin tamamı yaklaşan trafiğe doğru, duran CMV'nin arkasında yaklaşık 10 feet, 100 feet ve 200 feet mesafelerde yerleştirilir. Kaynak: Missouri CDL Kılavuzu; 49 CFR 392.22."},"66":{"q":"Bir Missouri ticari aracı iki şeritli, iki yönlü, bölünmemiş bir yolda durduğunda, uyarı üçgenleri nereye yerleştirilmelidir?","options":["Biri yaklaşık 10 feet arkada, biri yaklaşık 200 feet arkada ve biri yaklaşık 200 feet önde","Biri yaklaşık 10 feet arkada, biri yaklaşık 100 feet arkada ve biri aracın yaklaşık 100 feet önünde","Üçü de aracın arkasında 10, 100 ve 200 feet mesafede","Aracın her iki yanında birer tane ve tam arkasında bir tane"],"explanation":"İki şeritli, iki yönlü bir yolda sürücü bir üçgeni arkanın 10 feet içine, birini yaklaşık 100 feet arkaya ve birini aracın yaklaşık 100 feet önüne yerleştirir. Kaynak: Missouri CDL Kılavuzu; 49 CFR 392.22."},"67":{"q":"Bir Missouri kırsal ekspres yolunda (eyaletler arası karayolu veya otoyol değil), azami hız limiti nedir?","options":["70 mph","60 mph","65 mph","55 mph"],"explanation":"Missouri, kırsal ekspres yollarda azami hızı 65 mph olarak belirler; bu, kırsal eyaletler arası karayollarında ve otoyollarda izin verilen 70 mph'nin altındadır. Kaynak: RSMo 304.010."},"68":{"q":"Kentleşmiş bir alan içinde bulunan bir Missouri eyaletler arası karayolunda, otoyolunda veya ekspres yolunda azami hız limiti nedir?","options":["60 mph","65 mph","70 mph","55 mph"],"explanation":"Kentleşmiş alanlar içinde, daha düşük bir limit belirtilmediği sürece Missouri eyaletler arası karayolları, otoyolları ve ekspres yollarını 60 mph ile sınırlar. Kaynak: RSMo 304.010."},"69":{"q":"Hangi demiryolu geçidi, bir Missouri otobüsünün veya plakartlı HazMat CMV'sinin zorunlu durmayı yapmasını GEREKTİRMEZ?","options":["Yanıp sönen ışıkları olmayan kırsal bir alandaki herhangi bir geçit","Çapraz işaret (crossbuck) olan ancak bariyeri olmayan herhangi bir geçit","45 mph'nin altında belirtilmiş bir yoldaki herhangi bir geçit","Bir iş bölgesi içindeki bir tramvay geçidi veya endüstriyel manevra hattı ya da 'Exempt' (Muaf) işaretiyle işaretlenmiş bir geçit"],"explanation":"Zorunlu durma, bir iş bölgesi içindeki tramvay geçitlerinde veya endüstriyel manevra hatlarında, bu şekilde işaretlenmiş terk edilmiş geçitlerde ya da yetkili bir 'Exempt' (Muaf) işaretiyle işaretlenmiş geçitlerde uygulanmaz. Kaynak: Missouri CDL Kılavuzu; 49 CFR 392.10."},"70":{"q":"Bir büyük boy (oversize) izni gerekmeden önce, Missouri karayollarında yük dahil azami yasal araç genişliği nedir?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"explanation":"Missouri, yük dahil araç genişliğini 102 inches (8 feet 6 inches) ile sınırlar; bunu aşmak bir büyük boy izni gerektirir. Kaynak: RSMo 304.170; MoDOT Motor Carrier Services."},"71":{"q":"Bir büyük boy (oversize) izni gerekmeden önce, Missouri eyaletler arası karayolu sisteminde yük dahil azami yasal araç yüksekliği nedir?","options":["13 feet 6 inches","15 feet","14 feet","16 feet"],"explanation":"Missouri, eyaletler arası karayolu sisteminde yük dahil yüksekliği 14 feet ile sınırlar (belirli diğer yollarda 15 feet); bunun üzeri bir izin gerektirir. Kaynak: RSMo 304.170; MoDOT."},"72":{"q":"Bir ağırlık aşımı (overweight) izni olmadan, Missouri'nin eyaletler arası karayollarında genellikle izin verilen azami brüt araç ağırlığı nedir?","options":["80,000 pounds","73,280 pounds","88,000 pounds","90,000 pounds"],"explanation":"Missouri, eyaletler arası sistemde ağırlık aşımı izni olmadan azami brüt ağırlık olarak 80,000 pounds federal limitini takip eder. Kaynak: MoDOT Büyük Boy/Ağırlık Aşımı düzenlemeleri; RSMo Bölüm 304."},"73":{"q":"Standart bir tek seferlik izin kapsamında, Missouri karayollarında büyük boy bir yük genellikle ne zaman taşınabilir?","options":["Sadece gece yarısı ile sabah 6:00 arasında","Günün veya gecenin herhangi bir saatinde herhangi bir kısıtlama olmadan","Sadece hafta sonları ve eyalet tatillerinde","Gün doğumundan yarım saat önce ile gün batımından yarım saat sonraya kadar"],"explanation":"MoDOT genellikle büyük boy yük taşımacılığını gün doğumundan yarım saat önce ile gün batımından yarım saat sonraya kadar olan döneme kısıtlar; ayrıca ek tatil ve hafta sonu kısıtlamaları vardır. Kaynak: MoDOT Büyük Boy/Ağırlık Aşımı izin düzenlemeleri."},"74":{"q":"Missouri karayollarında izin olmadan çalıştırılan bir yarı römorkun azami uzunluğu nedir?","options":["48 feet","53 feet","57 feet","60 feet"],"explanation":"Missouri, bir izin gerekmeden önce karayolu sisteminde bir yarı römorku 53 feet uzunlukla sınırlar. Kaynak: RSMo 304.170."},"75":{"q":"Bir Missouri okul otobüsünün, banketi olmayan ve hız limiti 60 mph'nin üzerinde olan bir karayolunda, trafiğin durabilmesi için yaklaşan sürücülere ne kadar mesafeden açıkça görünür olması gerekir?","options":["Her yönde en az 300 feet","Her yönde en az 200 feet","Her yönde en az 500 feet","Her yönde en az 1,000 feet"],"explanation":"Banketi olmayan ve hız limiti 60 mph'den fazla olan bir karayolunda, duran bir okul otobüsünün her yönde en az 500 feet mesafeden açıkça görünür olması gerekir (diğer karayollarında 300 feet). Kaynak: RSMo 304.050."},"76":{"q":"Ticari Sürücü Belgesi (CDL) belgesini fiilen hangi Missouri kurumu düzenler?","options":["Missouri Gelir Bakanlığı (DOR)","Missouri Eyalet Karayolu Devriyesi","Missouri Ulaştırma Bakanlığı (MoDOT)","Federal Motorlu Taşıyıcı Güvenliği İdaresi (FMCSA)"],"explanation":"Missouri'de Gelir Bakanlığı (DOR), CDL dahil tüm sürücü belgelerini düzenlerken, Missouri Eyalet Karayolu Devriyesi testleri yürütür. Kaynak: Missouri DOR Ticari Sürücüler sayfası (dor.mo.gov/driver-license/issuance/commercial/)."},"77":{"q":"Missouri'de CDL bilgi (yazılı) ve beceri testlerini kim yürütür?","options":["Missouri Eyalet Karayolu Devriyesi","Missouri Gelir Bakanlığı belge ofisleri","Özel FMCSA kayıtlı eğitim sağlayıcıları","Missouri Ulaştırma Bakanlığı"],"explanation":"Missouri Eyalet Karayolu Devriyesi, CDL yazılı bilgi testini Sürücü Sınav İstasyonlarında ve beceri testini (randevuyla) belirlenen CDL test sahalarında yürütür; daha sonra DOR belgeyi düzenler. Kaynak: Missouri DOR Ticari Sürücüler sayfası ve Missouri CDL Kılavuzu."},"78":{"q":"Bir Missouri Ticari Öğrenci İzni (CLP) ne kadar süre geçerlidir ve yenilenebilir mi?","options":["360 gün ve yenilenemez","180 gün ve bir kez yenilenebilir","1 yıl ve ikinci bir yıl için yenilenebilir","2 yıl, federal azami süreyle eşleşir"],"explanation":"Missouri, CLP'yi 360 günlük bir süre için düzenler ve yenilenemez; süresi dolarsa başvuru sahibi gerekli tüm bilgi testlerini tekrar tamamlamalıdır. Kaynak: Missouri DOR CDL İzin Kuralı Genel Bakışı (dor.mo.gov/driver-license/issuance/commercial/cdl-permit.html)."},"79":{"q":"Bir Missouri başvuru sahibi, CDL beceri testine girmeye uygun olmadan önce bir Ticari Öğrenci İznini ne kadar süre elinde tutmalıdır?","options":["En az 14 gün","En az 30 gün","En az 10 gün","En az 60 gün"],"explanation":"CDL başvuru sahipleri, tam bir CDL için beceri testini tamamlamadan önce bir CLP'yi en az 14 gün elinde tutmalıdır. Kaynak: Missouri DOR CDL İzin Kuralı Genel Bakışı ve federal CLP kuralı (49 CFR 383.25)."},"80":{"q":"Bir Missouri başvuru sahibi, ilk kez bir Sınıf A veya Sınıf B CDL için beceri testine girmeden ÖNCE hangi eğitimi tamamlamalıdır?","options":["FMCSA Eğitim Sağlayıcı Kaydı'ndaki bir sağlayıcıdan Giriş Seviyesi Sürücü Eğitimi (ELDT)","Bir DOR ofisinde eyalet onaylı bir savunma sürüş kursu","Bir Missouri Eyalet Karayolu Devriyesi sınıf içi güvenlik semineri","Yalnızca işveren tarafından yürütülen iş başı oryantasyonu"],"explanation":"CDL beceri testinden önce (ve belirli yeni onaylar için), Missouri başvuru sahipleri, 7 Şubat 2022'den beri yürürlükte olan FMCSA Eğitim Sağlayıcı Kaydı'nda listelenen bir sağlayıcıdan Giriş Seviyesi Sürücü Eğitimi (ELDT) tamamlamalıdır. Kaynak: Missouri DOR Ticari Sürücüler sayfası; FMCSA ELDT kuralı (49 CFR Part 380)."},"81":{"q":"Missouri CDL beceri testi hangi üç bölümden, hangi sırayla oluşur?","options":["Araç (sefer öncesi) muayenesi, temel araç kontrolü ve yolda sürüş","Yazılı bilgi, hava freni kontrolü ve yolda sürüş","Temel araç kontrolü, tehlikeli madde kontrolü ve yolda sürüş","Araç muayenesi, bilgi yeniden testi ve bir savunma sürüş değerlendirmesi"],"explanation":"Missouri'nin modernize edilmiş CDL beceri testinin üç bileşeni vardır: araç (sefer öncesi) muayenesi, temel araç kontrol beceri testi ve yolda sürüş testi. Kaynak: Missouri CDL Kılavuzu ve Missouri DOR Ticari Sürücüler sayfası."},"82":{"q":"Bir Missouri CDL başvuru sahibinin seçmesi gereken dört öz-sertifikasyon kategorisi nelerdir?","options":["Muaf olmayan eyaletler arası, muaf eyaletler arası, muaf olmayan eyalet içi ve muaf eyalet içi","Eyaletler arası, eyalet içi, bölgesel ve yerel","Ticari, tarımsal, acil durum ve devlet","Sınıf A, Sınıf B, Sınıf C ve hazmat"],"explanation":"Missouri CDL başvuru sahipleri dört kategoriden birini öz-sertifiye etmelidir: muaf olmayan eyaletler arası (NI), muaf eyaletler arası (EI), muaf olmayan eyalet içi (NA) ve muaf eyalet içi (EA). Kaynak: Missouri DOR CDL Tıbbi Sertifikasyon Gereklilikleri sayfası."},"83":{"q":"Missouri'de hangi öz-sertifikasyon kategorisi, sürücünün 49 CFR Part 391 kapsamında yeterli olmasını ve bir DOT tıbbi muayene uzmanı sertifikası taşımasını gerektirir?","options":["Muaf olmayan eyaletler arası (NI)","Muaf eyaletler arası (EI)","Muaf eyalet içi (EA)","Muaf eyaletler arası acil durum (EE)"],"explanation":"Muaf olmayan eyaletler arası (NI) bir sürücü, eyaletler arası ticarette faaliyet gösterir, 49 CFR Part 391'e tabidir ve bir DOT tıbbi muayene uzmanı sertifikası edinmeli ve sürdürmelidir. Muaf kategoriler bu federal tıbbi sertifika gerekliliğine tabi değildir. Kaynak: Missouri DOR CDL Tıbbi Sertifikasyon sayfası."},"84":{"q":"Bir CDL sahibinin kaydı için tıbbi muayene uzmanı sertifika bilgisi genellikle Missouri Gelir Bakanlığı'na nasıl ulaşır?","options":["National Registry of Certified Medical Examiners'tan elektronik olarak iletilir","Sürücü her zaman orijinal bir kağıt kartı MoDOT'a postalamak zorundadır","Sürücünün işvereni bunu Karayolu Devriyesi'ne dosyalar","Yalnızca üçüncü taraf bir HAZMAT satıcısı aracılığıyla yüklenir"],"explanation":"Missouri, tıbbi muayene uzmanı sertifika bilgisini National Registry of Certified Medical Examiners'tan elektronik olarak iletilen şekilde alır, bu nedenle sürücüler o kayıttaki sertifikalı bir muayene uzmanını kullanmalıdır. Kaynak: Missouri DOR CDL Tıbbi Sertifikasyon Gereklilikleri sayfası."},"85":{"q":"Güncel bir tıbbi muayene uzmanı sertifikasını dosyada tutmayan muaf olmayan bir Missouri CDL sürücüsüne ne olur?","options":["CDL düşürülür ve ticari sürüş ayrıcalıkları kaybedilir","CDL tam olarak 24 saat askıya alınır, sonra geri verilir","Hiçbir şey, çünkü Missouri tıbbi durumu takip etmez","Sürücü otomatik olarak muaf eyalet içi kategorisine taşınır"],"explanation":"Tıbbi sertifikasyonun süresinin dolmasına izin veren muaf olmayan bir sürücü düşürülür ve dosyada güncel bir sertifika olana kadar CDL ayrıcalıklarını kaybeder. Kaynak: Missouri DOR CDL Tıbbi Sertifikasyon SSS; federal tıbbi sertifikasyon kuralı (49 CFR 383.71/383.73)."},"86":{"q":"21 ila 69 yaşları arasındaki bir sürücünün elinde bulundurduğu bir Missouri CDL için standart yenileme döngüsü nedir?","options":["6 yıl","4 yıl","8 yıl","10 yıl"],"explanation":"Standart bir Missouri CDL, 21 ila 69 yaşları arasındaki sürücüler için 6 yıllık bir süreyle düzenlenir (18-20 ve 70+ yaşındaki sürücüler için 3 yıllık bir süre uygulanır). Kaynak: Missouri DOR sürücü belgesi düzenleme bilgileri."},"87":{"q":"Tehlikeli Maddeler (H) onaylı bir Missouri CDL, geçerliliğini kısaltabilecek hangi ek gereklilikle bağlantılıdır?","options":["Bir TSA güvenlik tehdidi değerlendirmesi (geçmiş kontrolü)","Bir DOR ofisinde yıllık bir görme yeniden testi","Her yıl ayrı bir Karayolu Devriyesi yol testi","Noter onaylı bir işveren sponsorluk mektubu"],"explanation":"HAZMAT onayı bir TSA güvenlik tehdidi değerlendirmesi gerektirir; Missouri'de onay (ve genellikle belge süresi) bu geçmiş kontrolü döngüsüne bağlıdır, bu nedenle standart 6 yıllık süreden daha kısadır. Kaynak: Missouri DOR Ticari Sürücüler sayfası; federal HAZMAT/TSA kuralı (49 CFR 1572)."},"88":{"q":"Bir ticari motorlu aracı YALNIZCA Missouri içinde (eyalet içi) sürmek için bir Missouri CDL/CLP'ye başvurmak için asgari yaş nedir?","options":["18 yaşında","16 yaşında","21 yaşında","19 yaşında"],"explanation":"Missouri, eyalet içi ticari sürüş için bir CLP/CDL almak isteyen başvuru sahiplerinin en az 18 yaşında olmasını gerektirir; eyaletler arası faaliyet için 21 yaş gereklidir. Kaynak: Missouri CDL Kılavuzu ve Missouri DOR Ticari Sürücüler sayfası."},"89":{"q":"Bir Missouri CDL ile eyaletler arası ticarette bir ticari motorlu aracı çalıştırmak için gereken asgari yaş nedir?","options":["21 yaşında","18 yaşında","19 yaşında","25 yaşında"],"explanation":"Sürücülerin eyaletler arası ticarette faaliyet göstermek için en az 21 yaşında olması gerekir; 18-20 yaşındaki bir Missouri CDL sahibi genellikle eyalet içi sürüşle sınırlıdır. Kaynak: Missouri CDL Kılavuzu; federal kural (49 CFR 391.11)."},"90":{"q":"Bir Missouri başvuru sahibine bir CLP verilmeden önce, hangi sürücü belgesine zaten sahip olmaları veya bunu edinmeleri gerekir?","options":["Geçerli bir Missouri temel (ticari olmayan) sürücü belgesi","Başka bir eyaletten geçerli bir CDL","Yalnızca herhangi bir ABD eyaletinden bir öğrenci izni","Bir CLP almak için belge gerekmez"],"explanation":"Bir başvuru sahibinin, bir Missouri CLP düzenlenmeden önce bir Missouri temel sürücü belgesine sahip olması veya bunu edinmesi gerekir. Kaynak: Missouri DOR CDL İzin Kuralı Genel Bakışı."},"91":{"q":"Bir Missouri CLP'nin süresi, sahibi beceri testini geçmeden önce dolduğunda, başvuru sahibi yeni bir CLP almak için ne yapmalıdır?","options":["Gerekli tüm bilgi testlerini tekrar tamamlamalı","Yeniden test olmadan sadece küçük bir yenileme ek ücreti ödemeli","30 gün beklemeli ve CLP otomatik olarak yeniden etkinleşmeli","Bilgi yeniden testi olmadan yalnızca beceri testine girmeli"],"explanation":"360 günlük CLP yenilenemez olduğundan, süresi dolduğunda başvuru sahibi yeni bir CLP almak için gerekli tüm bilgi testlerini tamamlamalıdır. Kaynak: Missouri DOR CDL İzin Kuralı Genel Bakışı."},"92":{"q":"Hangi onayın bir Missouri Ticari Öğrenci İznine (CLP) konulmasına İZİN verilir?","options":["Okul Otobüsü (S)","Tehlikeli Maddeler (H)","Ürün taşıyan Tank Aracı (N)","Çift/Üçlü Römork (T)"],"explanation":"Bir Missouri CLP'sinde, Okul Otobüsü (S) ve Yolcu (P) onayları (kısıtlamalarla) taşınabilir, ancak Tehlikeli Maddeler (H), Tank (yüklü olduğunda X/N) ve Çift/Üçlü (T) onayları bir CLP'de yasaktır. Kaynak: Missouri DOR CDL Test/CLP SSS; federal CLP kuralı (49 CFR 383.25)."},"93":{"q":"Missouri'nin belge doğrulama süreci kapsamında, bir CDL başvuru sahibinin belgelerini incelemeye kaç belge ofisi çalışanının önemli ölçüde katılması gerekir?","options":["En az iki çalışan","Tam olarak bir çalışan","En az dört çalışan","Belgeler taranırsa çalışan incelemesi gerekmez"],"explanation":"Missouri, bir ticari başvuru sahibinin kimliğini, ikametgahını ve test belgelerini incelemeye ve doğrulamaya en az iki çalışanın önemli ölçüde katılmasını gerektirir. Kaynak: Missouri DOR CDL Test/CLP SSS."},"94":{"q":"Eyalet dışı bir belge sahibinin bir Missouri CLP'sine başvurmasıyla ilgili hangi ifade doğrudur?","options":["Önce Missouri ikametgahı kurmalı ve bir Missouri temel belgesine geçiş yapmalıdırlar (bu aynı gün gerçekleşebilir)","Missouri, geçerli herhangi bir eyalet dışı belgeye sahip ikamet etmeyenlere serbestçe CLP düzenler","Eyalet dışı belgelerini tutabilir ve hiçbir zaman değiştirmek zorunda kalmazlar","Herhangi bir CLP işleminden önce bir Missouri sakini olarak 90 gün beklemelidirler"],"explanation":"Missouri, ikamet etmeyen birine CLP düzenlemez; başvuru sahibi önce Missouri ikametgahı kurmalı ve temel belgesini geçirmelidir; bu, CLP başvurusuyla aynı gün yapılabilir. Kaynak: Missouri DOR CDL Test/CLP SSS."},"95":{"q":"Missouri CDL bilgi (yazılı) testlerinde asgari geçme puanı nedir?","options":["80 percent","70 percent","75 percent","90 percent"],"explanation":"Missouri CDL bilgi testleri, CDL bilgi testleri için federal standartla tutarlı olarak geçmek için en az 80 percent puan gerektirir. Kaynak: Missouri CDL Kılavuzu; federal bilgi testi standardı (49 CFR 383.135)."}},"es":{"0":{"q":"¿Cuál es el ancho máximo, incluida la carga, permitido para un vehículo que circula por las carreteras de Misuri sin un permiso especial?","options":["96 inches","100 inches","102 inches","108 inches"],"explanation":"Según el RSMo 304.170, ningún vehículo (incluida su carga) puede exceder las 102 inches de ancho en las carreteras de Misuri, salvo dispositivos de seguridad como luces de gálibo y espejos. Exceder esto requiere un permiso de sobredimensión de MoDOT. Fuente: Missouri Revised Statutes 304.170; Missouri Driver Guide Capítulo 15."},"1":{"q":"En las carreteras interestatales y designadas de Misuri, ¿cuál es la altura máxima del vehículo, incluida la carga, permitida sin un permiso?","options":["13 feet 6 inches","14 feet","14 feet 6 inches","15 feet"],"explanation":"El RSMo 304.170 establece la altura máxima en las carreteras interestatales y designadas en 14 feet, incluida la carga. Fuente: Missouri Revised Statutes 304.170."},"2":{"q":"En las carreteras de Misuri DISTINTAS a las interestatales y rutas designadas, ¿cuál es la altura máxima general del vehículo, incluida la carga?","options":["13 feet","13 feet 6 inches","14 feet","15 feet"],"explanation":"El RSMo 304.170 limita la altura a 13 feet 6 inches en todas las carreteras distintas a las interestatales y designadas. Los vehículos que transportan automóviles pueden alcanzar 14 feet como excepción. Fuente: Missouri Revised Statutes 304.170."},"3":{"q":"¿Cuál es la longitud máxima, incluida la carga, de un vehículo automotor único (como un camión rígido) que circula por las carreteras de Misuri?","options":["40 feet","45 feet","48 feet","53 feet"],"explanation":"El RSMo 304.170 limita un vehículo automotor único, incluida la carga, a 45 feet de longitud. Las combinaciones más largas y los semirremolques se rigen por disposiciones separadas. Fuente: Missouri Revised Statutes 304.170."},"4":{"q":"¿Cuál es la longitud máxima de semirremolque permitida en la red nacional (carreteras interestatales y designadas) en Misuri?","options":["48 feet","50 feet","53 feet","57 feet"],"explanation":"Un semirremolque en una combinación de tractocamión/semirremolque puede tener hasta 53 feet de longitud en la red nacional de carreteras interestatales y designadas en Misuri, de acuerdo con el RSMo 304.170 y los estándares federales. Fuente: Missouri Revised Statutes 304.170; Missouri Driver Guide Capítulo 15."},"5":{"q":"¿Cuál es el peso bruto máximo permitido en las carreteras de Misuri sin un permiso de sobrepeso (en ausencia de un límite de puente señalizado más bajo)?","options":["73,280 pounds","76,000 pounds","80,000 pounds","84,000 pounds"],"explanation":"El RSMo 304.180 limita el peso bruto a 80,000 pounds en las carreteras de Misuri, excepto donde un puente o estructura esté señalizado para menos. Esto coincide con el límite federal interestatal. Fuente: Missouri Revised Statutes 304.180."},"6":{"q":"¿Cuál es el peso máximo permitido en un eje simple en el sistema interestatal de Misuri?","options":["18,000 pounds","20,000 pounds","22,000 pounds","24,000 pounds"],"explanation":"El RSMo 304.180 y el estándar federal limitan cualquier eje simple a 20,000 pounds en el sistema interestatal. Fuente: Missouri Revised Statutes 304.180."},"7":{"q":"¿Cuál es el peso máximo permitido en un grupo de ejes en tándem en el sistema interestatal de Misuri?","options":["30,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"El RSMo 304.180 y el estándar federal limitan un grupo de ejes en tándem a 34,000 pounds en el sistema interestatal. Fuente: Missouri Revised Statutes 304.180."},"8":{"q":"Según la ley de Misuri, ¿cómo se define un 'eje en tándem' por el espaciamiento entre los ejes?","options":["Ejes separados 40 inches o menos","Ejes separados más de 40 inches pero no más de 96 inches","Ejes separados más de 96 inches pero no más de 120 inches","Cualquier par de ejes sin importar el espaciamiento"],"explanation":"El RSMo 304.180 define un eje en tándem como dos o más ejes dispuestos uno detrás de otro cuyos extremos están separados más de 40 inches y no más de 96 inches. Fuente: Missouri Revised Statutes 304.180."},"9":{"q":"En las carreteras de Misuri que NO forman parte del sistema interestatal, ¿en cuánto puede un vehículo exceder los límites de peso de eje simple y tándem, siempre que el peso bruto aún no exceda las 80,000 pounds?","options":["Hasta 1,000 pounds","Hasta 2,000 pounds","Hasta 4,000 pounds","No hay tolerancia"],"explanation":"El RSMo 304.180 permite que los vehículos en carreteras no interestatales excedan los límites de eje simple y tándem hasta en 2,000 pounds, pero el peso bruto total no puede exceder las 80,000 pounds. Fuente: Missouri Revised Statutes 304.180."},"10":{"q":"En las carreteras interestatales y designadas de Misuri, el peso legal máximo para un vehículo se determina principalmente por ¿qué?","options":["La Fórmula de Puente Federal y su tabla","El número de neumáticos en contacto con el suelo","El GVWR registrado del vehículo","La clase de CDL del conductor"],"explanation":"Los pesos máximos en las carreteras interestatales y designadas se rigen por la Fórmula de Puente Federal y su tabla, que relaciona el peso bruto permitido con el número de ejes y la distancia entre ellos, con un tope general de 80,000 pounds. Fuente: Missouri Revised Statutes 304.180; FHWA Federal Bridge Formula."},"11":{"q":"La Fórmula de Puente Federal utilizada en Misuri limita el peso bruto permitido en función de ¿cuáles dos factores?","options":["Presión de los neumáticos y tipo de carga","Potencia del motor y número de ejes","El número de ejes y la distancia entre ellos","Antigüedad del vehículo y peso registrado"],"explanation":"La Fórmula de Puente Federal (Bridge Formula B) establece el peso permitido en cualquier grupo de ejes consecutivos usando el número de ejes del grupo y el espaciamiento entre los ejes exteriores, protegiendo los puentes de sobrecargas. Misuri la aplica según el RSMo 304.180. Fuente: Missouri Revised Statutes 304.180; FHWA."},"12":{"q":"¿Cuándo se requiere un permiso de sobredimensión/sobrepeso de MoDOT para circular por las carreteras de Misuri?","options":["Solo al viajar de noche","Cuando el vehículo y la carga exceden los límites legales de tamaño o peso","Solo para vehículos registrados fuera del estado","Siempre que un vehículo pese más de 26,001 pounds"],"explanation":"Se requiere un permiso de sobredimensión/sobrepeso de MoDOT siempre que un vehículo y su carga excedan los límites legales de Misuri en ancho, altura, longitud o peso. Las cargas que pueden desarmarse razonablemente para cumplir con los límites legales generalmente no se autorizan. Fuente: Missouri DOT Motor Carrier Services / OSOW; RSMo 304.170-304.200."},"13":{"q":"¿Por cuánto tiempo es válido un permiso estándar de viaje único de sobredimensión/sobrepeso de MoDOT?","options":["24 horas","Siete días consecutivos","30 días","Un año"],"explanation":"Los permisos de viaje único de sobredimensión/sobrepeso de MoDOT son válidos por siete días consecutivos. Hay permisos anuales (generales) disponibles para operaciones continuas que califiquen. Fuente: Missouri DOT Oversize/Overweight permit regulations."},"14":{"q":"¿Cómo se calcula la tarifa básica del permiso de viaje único de SOBREPESO de MoDOT?","options":["Una tarifa fija de $50 sin importar el peso","$15 más $20 por cada 10,000 pounds que excedan el peso bruto legal","$100 más $5 por eje","$25 por milla recorrida"],"explanation":"MoDOT cobra una tarifa base de permiso de viaje único de $15 más $20 por cada 10,000 pounds (o fracción) por encima del peso bruto legal; los transportes muy pesados agregan una tarifa de análisis de puente y calzada. Fuente: Missouri DOT Oversize/Overweight permit fee schedule."},"15":{"q":"Para la mayoría de las cargas sobredimensionadas en Misuri, el viaje diurno generalmente está restringido a ¿qué franja horaria?","options":["Solo de medianoche a mediodía","Desde media hora antes del amanecer hasta media hora después del atardecer","Solo de 8:00 a.m. a 4:00 p.m.","A cualquier hora, las 24 horas del día"],"explanation":"Las cargas sobredimensionadas con permiso en Misuri generalmente pueden viajar desde media hora antes del amanecer hasta media hora después del atardecer; las cargas que solo tienen sobrepeso (tamaño legal) pueden circular continuamente. Fuente: Missouri DOT Oversize/Overweight permit regulations."},"16":{"q":"Bajo la variación de peso agrícola de Misuri, ¿cuál es el peso bruto máximo para un vehículo que transporta leche desde una granja o que transporta ganado en carreteras DISTINTAS al sistema interestatal?","options":["80,000 pounds","82,000 pounds","85,500 pounds","90,000 pounds"],"explanation":"El RSMo 304.180 permite que un vehículo que transporta leche desde una granja hacia su procesamiento, o que transporta ganado, alcance hasta 85,500 pounds de peso bruto en carreteras distintas al sistema interestatal. Esto no aplica en las interestatales. Fuente: Missouri Revised Statutes 304.180; Missouri Dept. of Agriculture."},"17":{"q":"Bajo la variación de temporada de cosecha de Misuri, los vehículos que transportan granos o subproductos de granos durante la cosecha pueden exceder los límites normales de peso en carreteras no interestatales ¿en qué cantidad?","options":["5 por ciento","10 por ciento","15 por ciento","2,000 pounds fijas"],"explanation":"El RSMo 304.180 permite que los transportistas de granos y subproductos de granos durante las épocas de cosecha excedan los límites máximos de peso hasta en un 10 por ciento en carreteras distintas al sistema interestatal. Fuente: Missouri Revised Statutes 304.180; Missouri Dept. of Agriculture."},"18":{"q":"Un transportista de ganado o granos que utiliza la variación agrícola de mayor peso de Misuri debe observar ¿cuál restricción?","options":["No debe usar el sistema interestatal ni cruzar un puente señalizado por debajo del peso de la carga","Debe viajar solo de noche","Debe llevar dos abanderados en todo momento","Solo puede operar dentro de 25 millas de la granja"],"explanation":"Según el RSMo 304.180, los transportistas que utilizan la mayor tolerancia de peso agrícola no pueden usar ninguna parte del sistema de carreteras interestatales ni cruzar ningún puente señalizado para menos del peso bruto del vehículo y la carga. Fuente: Missouri Revised Statutes 304.180; Missouri Dept. of Agriculture."},"19":{"q":"¿Cuál es el voladizo delantero y trasero máximo generalmente permitido para los transportes de automóviles bajo las reglas de dimensiones de Misuri?","options":["2 feet adelante, 3 feet atrás","3 feet adelante, 4 feet atrás","4 feet adelante, 6 feet atrás","No se permite voladizo"],"explanation":"Las reglas de dimensiones de Misuri bajo el RSMo 304.170 permiten a los transportes de automóviles un voladizo delantero no mayor a 3 feet y un voladizo trasero no mayor a 4 feet. Fuente: Missouri Revised Statutes 304.170."},"20":{"q":"En Misuri, ¿qué clase de CDL se requiere para operar cualquier combinación de vehículos con una Calificación de Peso Bruto Combinado (GCWR) de 26,001 o más libras, siempre que el vehículo (o vehículos) remolcado tenga un GVWR superior a 10,000 libras?","options":["Clase A","Clase B","Clase C","Clase E"],"explanation":"Misuri define la Clase A como cualquier combinación de vehículos con un GCWR de 26,001 o más libras donde el GVWR de la unidad remolcada excede las 10,000 libras. Fuente: Missouri Commercial Driver License Manual, Sección 1 (Clasificaciones de CDL)."},"21":{"q":"Según las reglas de Misuri, ¿cuál es el GVWR máximo de un vehículo remolcado antes de que una unidad de potencia única calificada con 26,001+ libras de GVWR requiera una CDL Clase A (en lugar de Clase B)?","options":["8,000 libras","10,000 libras","15,000 libras","26,001 libras"],"explanation":"Una CDL Clase B cubre un vehículo único de 26,001+ lbs de GVWR que remolca una unidad que NO excede las 10,000 lbs de GVWR; si la unidad remolcada excede las 10,000 lbs de GVWR, se requiere una Clase A. Fuente: Missouri Commercial Driver License Manual, Sección 1."},"22":{"q":"Según el Manual de CDL de Misuri, una CDL Clase C aplica solo a un vehículo de menos de 26,001 libras de GVWR cuando está rotulado para materiales peligrosos O está diseñado para transportar ¿cuántas personas?","options":["9 o más personas, sin incluir al conductor","12 o más personas, incluido el conductor","15 o más personas, sin incluir al conductor","16 o más personas, incluido el operador"],"explanation":"La Clase C de Misuri cubre un vehículo único de menos de 26,001 lbs de GVWR que está rotulado para materiales peligrosos o diseñado para transportar 16 o más personas, incluido el operador. Fuente: Missouri Commercial Driver License Manual, Sección 1."},"23":{"q":"¿Cuál es la edad mínima para obtener una CDL de Misuri solo para conducción INTRAESTATAL (dentro de Misuri)?","options":["16 años","18 años","19 años","21 años"],"explanation":"La elegibilidad para la CDL de Misuri establece la edad de 18 años para operación intraestatal (hasta los 21 años) y 21 años para operación interestatal. Fuente: Missouri Commercial Driver License Manual, 'Missouri CDL Eligibility.'"},"24":{"q":"Un conductor de Misuri quiere operar un vehículo comercial cruzando las fronteras estatales (comercio interestatal). ¿Cuál es la edad mínima para tener una CDL para operación interestatal?","options":["18 años","19 años","20 años","21 años"],"explanation":"Misuri exige que un conductor tenga 21 años para operar en comercio interestatal; los titulares de CDL de 18 a 20 años están restringidos a la operación intraestatal. Fuente: Missouri Commercial Driver License Manual, 'Missouri CDL Eligibility.'"},"25":{"q":"Antes de presentar la prueba de destrezas (de manejo) de la CDL en Misuri, un solicitante debe haber tenido un Permiso de Aprendiz Comercial (CLP) por un mínimo de ¿cuánto tiempo?","options":["7 días","14 días","30 días","60 días"],"explanation":"Las reglas federales y de Misuri exigen que el CLP se tenga un mínimo de 14 días antes de poder presentar la prueba de destrezas. Fuente: Missouri DOR CDL Permit Rule Overview; 49 CFR 383.25."},"26":{"q":"¿Por cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) de Misuri, y se puede renovar?","options":["180 días, renovable una vez","360 días, no renovable","1 año, renovable anualmente","2 años, no renovable"],"explanation":"Un CLP de Misuri se emite por 360 días y no es renovable; si expira, el solicitante debe volver a presentar las pruebas de conocimientos requeridas. Fuente: Missouri DOR CDL Permit Rule Overview."},"27":{"q":"¿Qué endoso se requiere en Misuri para conducir un vehículo comercial diseñado para transportar 16 o más personas, incluido el conductor?","options":["Endoso S (Autobús Escolar)","Endoso P (Pasajeros)","Endoso N (Cisterna)","Endoso T (Dobles/Triples)"],"explanation":"El endoso P (Pasajeros) se requiere para vehículos diseñados para transportar 16 o más personas incluido el conductor; requiere una prueba de conocimientos y una prueba de destrezas en un vehículo de pasajeros. Fuente: Missouri Commercial Driver License Manual, sección de Endosos."},"28":{"q":"En Misuri, el endoso de Vehículo Cisterna (N) se requiere para un vehículo que transporta líquido o gas en un tanque con una capacidad nominal individual de más de 119 galones y una capacidad nominal agregada de ¿qué cantidad?","options":["500 galones o más","750 galones o más","1,000 galones o más","1,500 galones o más"],"explanation":"El endoso N aplica a tanques con una capacidad nominal individual de más de 119 galones y una capacidad nominal agregada de 1,000 galones o más. Fuente: Missouri Commercial Driver License Manual, sección de Endosos; 49 CFR 383.5."},"29":{"q":"¿Qué endoso necesitan los conductores de Clase A en Misuri antes de poder remolcar remolques dobles o triples?","options":["Endoso N (Cisterna)","Endoso T (Dobles/Triples)","Endoso X (Combinación)","Endoso H (Materiales Peligrosos)"],"explanation":"El endoso T (Dobles/Triples) requiere aprobar un examen especial de conocimientos; aplica a los conductores de Clase A que deseen remolcar múltiples remolques. Fuente: Missouri Commercial Driver License Manual, sección de Endosos."},"30":{"q":"¿Cuál de los siguientes endosos NO puede agregarse a un Permiso de Aprendiz Comercial (CLP) de Misuri?","options":["P (Pasajeros)","S (Autobús Escolar)","N (Cisterna)","T (Dobles/Triples)"],"explanation":"Los únicos endosos que pueden agregarse a un CLP de Misuri son P (Pasajeros), S (Autobús Escolar) y N (Cisterna). H, X y T están prohibidos en un CLP. Fuente: Missouri Commercial Driver License Manual; 49 CFR 383.153(b); Section 302.700, RSMo."},"31":{"q":"Antes de que el endoso de Materiales Peligrosos (H) pueda agregarse a una CDL de Misuri, el solicitante debe aprobar el examen escrito Y recibir la aprobación de ¿qué?","options":["Una evaluación de amenaza a la seguridad de la TSA (verificación de antecedentes)","Una exención de un especialista de la vista","Una carta de patrocinio de un empleador de Misuri","Una autorización de inspección de carretera del DOT"],"explanation":"Además del examen escrito de HazMat de 30 preguntas, los solicitantes deben completar la toma de huellas dactilares y recibir la aprobación de una evaluación de amenaza a la seguridad de la TSA antes de que se agregue el endoso H (o X). Fuente: Missouri DOR HazMat Endorsement Requirements; 49 CFR 1572."},"32":{"q":"Una CDL de Misuri con un endoso de Materiales Peligrosos (H o X) expirará no más de ¿cuántos años después de que se completó la evaluación de amenaza a la seguridad de la TSA?","options":["2 años","4 años","5 años","8 años"],"explanation":"Debido a que la verificación de antecedentes de la TSA es válida por cinco años, una CDL con un endoso H o X expira no más de 5 años después de que se completó la evaluación de amenaza a la seguridad. Fuente: Missouri DOR HazMat Endorsement / HME FAQs; 49 CFR 1572."},"33":{"q":"En Misuri, el endoso de Autobús Escolar (S) requiere que también se obtenga ¿cuál endoso adicional?","options":["Endoso N (Cisterna)","Endoso P (Pasajeros)","Endoso H (Materiales Peligrosos)","Endoso T (Dobles/Triples)"],"explanation":"Según las reglas federales y de Misuri, el endoso de Autobús Escolar (S) requiere el endoso de Pasajeros (P); el solicitante debe aprobar la prueba de conocimientos de autobús escolar y una prueba de destrezas en un autobús escolar. Fuente: Missouri Commercial Driver License Manual; 49 CFR 383.93."},"34":{"q":"Antes de presentar la prueba de destrezas de la CDL en Misuri (vigente desde el 7 de febrero de 2022), un solicitante debe completar la Capacitación para Conductores de Nivel Inicial (ELDT) de un proveedor listado ¿dónde?","options":["La lista de escuelas aprobadas del Missouri State Highway Patrol","El FMCSA Training Provider Registry","La lista de proveedores del Missouri Department of Revenue","Cualquier escuela privada de CDL que elija el solicitante"],"explanation":"La ELDT debe completarse a través de un proveedor listado en el Training Provider Registry de la FMCSA antes de la prueba de destrezas para una CDL inicial o ciertos endosos. Fuente: Missouri DOR Commercial Drivers page; 49 CFR Part 380."},"35":{"q":"Al autocertificar el estado médico para una CDL de Misuri, ¿entre cuántas categorías posibles debe elegir un conductor?","options":["2 categorías","3 categorías","4 categorías","6 categorías"],"explanation":"Los conductores se autocertifican en una de cuatro categorías: interestatal no exceptuado, interestatal exceptuado, intraestatal no exceptuado o intraestatal exceptuado. Fuente: Missouri Commercial Driver License Manual, Medical Self-Certification; 49 CFR 383.71."},"36":{"q":"Un solicitante de CDL de Misuri que se certifica como 'interestatal no exceptuado' también debe hacer ¿qué?","options":["Proporcionar y mantener un certificado válido de examinador médico (tarjeta médica del DOT)","Presentar una exención médica intraestatal solo de Misuri","No proporcionar nada más; la certificación por sí sola es suficiente","Obtener una prueba de la vista anual de un optometrista de Misuri"],"explanation":"Un conductor que se autocertifica como interestatal no exceptuado está sujeto a los estándares médicos federales y debe presentar y mantener vigente un certificado válido de examinador médico, o se arriesga a una degradación. Fuente: Missouri Commercial Driver License Manual, Self-Certification; 49 CFR 391.41."},"37":{"q":"Para establecer el domicilio en Misuri al solicitar una CDL, ¿cuántos documentos que verifiquen la dirección de residencia del solicitante se requieren?","options":["Un documento","Dos documentos","Tres documentos","Ningún documento si existe una licencia previa"],"explanation":"Misuri requiere dos documentos aceptables que demuestren la residencia/domicilio en Misuri, además de la prueba de identidad, el número de Seguro Social y la presencia legal. Fuente: Missouri DOR Commercial Drivers page; Missouri CDL Manual, Eligibility."},"38":{"q":"¿Qué estatus de presencia legal exige Misuri a un solicitante de CDL?","options":["Cualquier titular de visa válida sin importar su estatus","Ciudadano estadounidense o residente permanente legal","Solo ciudadano estadounidense","Cualquier solicitante con un número de Seguro Social"],"explanation":"Misuri exige que los solicitantes de CDL sean ciudadanos estadounidenses o personas no ciudadanas con estatus de residente permanente legal. Fuente: Missouri DOR Commercial Drivers page; Missouri CDL Manual, Eligibility."},"39":{"q":"¿Cuál es la calificación mínima aprobatoria en cada examen de conocimientos (escrito) de la CDL de Misuri?","options":["70%","75%","80%","85%"],"explanation":"Misuri requiere una calificación del 80% en cada examen escrito de la CDL, administrado en los centros de pruebas del Highway Patrol (por ejemplo, Conocimientos Generales de 50 preguntas, HazMat de 30 preguntas, pruebas de endoso de 20 preguntas). Fuente: Missouri Commercial Driver License Manual, Sección 14 (CDL Written Examinations)."},"40":{"q":"En Misuri, ¿cuál es la concentración máxima de alcohol en sangre (BAC) que un conductor puede tener mientras opera un vehículo motorizado comercial (CMV) antes de que se considere una infracción mayor?","options":["0.04%","0.08%","0.02%","0.10%"],"explanation":"Misuri prohíbe operar un CMV con un BAC de 0.04% o más (la mitad del límite de 0.08% para conductores no comerciales). Fuente: Missouri DOR Form 5231, 'Commercial Motor Vehicle Operators and the Law'; 49 CFR 383.51."},"41":{"q":"Bajo la ley de consentimiento implícito de Misuri, ¿qué sucede si un titular de CDL se niega a someterse a una prueba química (de sangre/aliento) cuando se solicita legalmente?","options":["La CDL se descalifica por 1 año, igual que un primer DWI","Solo una multa de $500 sin descalificación","Una descalificación de la CDL de 60 días","Ninguna sanción porque la negativa no puede usarse como prueba"],"explanation":"Negarse a una prueba de sangre o de aliento siendo titular de CDL o mientras se opera un CMV se trata como una infracción mayor y resulta en una descalificación de la CDL de 1 año, igual que una primera condena por DWI. Fuente: Missouri DOR Form 5231; ley de consentimiento implícito de Misuri (Chapter 577 RSMo); 49 CFR 383.51."},"42":{"q":"¿Por cuánto tiempo se descalifica una CDL por una PRIMERA infracción mayor (como DWI en un CMV) cuando NO se transportan materiales peligrosos?","options":["1 año","3 años","60 días","De por vida"],"explanation":"Una primera infracción mayor, incluyendo conducir bajo la influencia, negarse a una prueba o abandonar la escena de un accidente, resulta en una descalificación de la CDL de 1 año en Misuri. Fuente: Missouri DOR Form 5231; 49 CFR 383.51."},"43":{"q":"Un conductor comete una primera infracción mayor mientras opera un vehículo rotulado para materiales peligrosos. ¿Cuál es el período de descalificación?","options":["3 años","1 año","5 años","De por vida"],"explanation":"Una primera infracción mayor cometida mientras se transportan materiales peligrosos rotulados conlleva una descalificación de la CDL de 3 años, en lugar del año estándar. Fuente: Missouri DOR Form 5231; 49 CFR 383.51."},"44":{"q":"¿Cuál es la consecuencia de una SEGUNDA infracción mayor (por ejemplo, un segundo DWI) en una CDL de Misuri?","options":["Descalificación de por vida","Descalificación de 3 años","Descalificación de 10 años","Descalificación de 1 año"],"explanation":"Una segunda condena por cualquiera de las infracciones mayores listadas resulta en una descalificación de la CDL de por vida en Misuri (algunos conductores pueden ser elegibles para reinstalación después de 10 años bajo las directrices federales). Fuente: Missouri DOR Form 5231; 49 CFR 383.51."},"45":{"q":"¿Cuántas infracciones de tránsito graves dentro de un período de 3 años resultan en una descalificación de la CDL de 60 días?","options":["2","3","4","1"],"explanation":"Dos condenas por infracciones de tránsito graves dentro de tres años (en un CMV) resultan en una descalificación de la CDL de 60 días. Fuente: Missouri DOR Form 5231; 49 CFR 383.51."},"46":{"q":"¿Cuántas infracciones de tránsito graves dentro de 3 años conducen a una descalificación de la CDL de 120 días?","options":["3 o más","2","5 o más","4 o más"],"explanation":"Tres o más condenas por infracciones de tránsito graves dentro de tres años resultan en una descalificación de la CDL de 120 días. Fuente: Missouri DOR Form 5231; 49 CFR 383.51."},"47":{"q":"¿Cuál de las siguientes se clasifica como una 'infracción de tránsito grave' para un titular de CDL de Misuri?","options":["Exceder la velocidad en 15 mph o más por encima del límite señalizado","Exceder la velocidad en 5 mph por encima del límite señalizado","Una infracción de estacionamiento","Una infracción de iluminación del equipo"],"explanation":"Las infracciones de tránsito graves incluyen exceder la velocidad en 15 mph o más por encima del límite, conducción imprudente, cambios de carril indebidos o erráticos, y seguir demasiado cerca. Los excesos de velocidad menores y las infracciones de estacionamiento no son 'graves.' Fuente: Missouri DOR Form 5231; 49 CFR 383.51."},"48":{"q":"¿Cuál es el período de descalificación por la PRIMERA infracción de un conductor en un cruce a nivel entre ferrocarril y carretera?","options":["60 días","30 días","120 días","1 año"],"explanation":"Una primera infracción en un cruce a nivel entre ferrocarril y carretera resulta en una descalificación mínima de la CDL de 60 días. Fuente: Missouri DOR Form 5231; 49 CFR 383.51."},"49":{"q":"Un titular de CDL comete una SEGUNDA infracción en un cruce a nivel entre ferrocarril y carretera dentro de 3 años. ¿Cuál es el período de descalificación?","options":["120 días","60 días","1 año","180 días"],"explanation":"Una segunda infracción en un cruce a nivel entre ferrocarril y carretera dentro de tres años resulta en una descalificación mínima de 120 días. Fuente: Missouri DOR Form 5231; 49 CFR 383.51."},"50":{"q":"¿Cuál es el período de descalificación por una TERCERA infracción en un cruce a nivel entre ferrocarril y carretera dentro de un período de 3 años?","options":["1 año","120 días","180 días","60 días"],"explanation":"Una tercera o subsiguiente infracción en un cruce a nivel entre ferrocarril y carretera dentro de tres años resulta en una descalificación mínima de 1 año. Fuente: Missouri DOR Form 5231; 49 CFR 383.51."},"51":{"q":"Además de la descalificación, ¿qué rango de sanción civil puede enfrentar un conductor por violar una orden de fuera de servicio?","options":["$1,000 a $2,500","$100 a $500","$250 a $750","$5,000 a $10,000"],"explanation":"Un conductor que viola una orden de fuera de servicio está sujeto a una sanción civil de no menos de $1,000 y no más de $2,500, además de la descalificación. Fuente: 49 CFR 383.53; Missouri DOR Form 5231."},"52":{"q":"Bajo el RSMo 304.822, ¿cuál es la multa por una PRIMERA violación de la prohibición de manos libres / mensajes de texto?","options":["$150","$50","$250","$500"],"explanation":"Bajo la Siddens Bening Hands Free Law de Misuri, la multa es de $150 por una primera violación, $250 por una segunda y $500 por una tercera dentro de un período definido. Fuente: Section 304.822 RSMo."},"53":{"q":"Un titular de CDL es condenado por usar un CMV para cometer un delito grave que involucra la fabricación o distribución de una sustancia controlada. ¿Cuál es la descalificación?","options":["Descalificación de por vida sin reinstalación","Descalificación de 1 año","Descalificación de 3 años","Descalificación de 10 años"],"explanation":"Usar un CMV en la comisión de un delito grave que involucra la fabricación, distribución o dispensación de una sustancia controlada resulta en una descalificación de por vida sin posibilidad de reinstalación. Fuente: Missouri DOR Form 5231; 49 CFR 383.51."},"54":{"q":"¿Cuál de las siguientes es una infracción mayor que desencadena una descalificación de la CDL de 1 año en una primera condena?","options":["Abandonar la escena de un accidente que involucra un CMV","Seguir demasiado cerca","Un cambio de carril indebido","Exceder la velocidad en 15 mph por encima del límite"],"explanation":"Abandonar la escena de un accidente que involucra un CMV es una infracción mayor (descalificación de 1 año por primera infracción). Seguir demasiado cerca, los cambios de carril indebidos y exceder la velocidad en 15+ mph son infracciones 'graves', no infracciones mayores. Fuente: Missouri DOR Form 5231; 49 CFR 383.51."},"55":{"q":"Un conductor causa una muerte por la operación negligente de un CMV (por ejemplo, homicidio vehicular). ¿Cómo se clasifica esto para fines de la CDL?","options":["Una infracción mayor que conlleva una descalificación de 1 año por primera infracción","Una infracción de tránsito grave que conlleva 60 días","Una infracción de cruce ferroviario que conlleva 120 días","Una violación de fuera de servicio que conlleva 90 días"],"explanation":"Causar una muerte por la operación negligente o criminal de un CMV es una infracción mayor, que resulta en una descalificación de 1 año en una primera condena (3 años si está rotulado con hazmat; de por vida en una segunda infracción mayor). Fuente: Missouri DOR Form 5231; 49 CFR 383.51."},"56":{"q":"En una interestatal o autopista rural de Misuri, ¿cuál es el límite de velocidad máximo señalizado que aplica a un vehículo comercial (camión) cuando no hay un límite menor señalizado?","options":["70 mph","65 mph","60 mph","55 mph"],"explanation":"Misuri fija la velocidad máxima en interestatales y autopistas rurales en 70 mph, y no existe un límite de velocidad estatal separado y menor para camiones, por lo que los camiones pueden circular a las mismas 70 mph a menos que se señalice una velocidad menor. Fuente: RSMo 304.010."},"57":{"q":"Según la ley de Misuri, ¿en qué vías tienen prohibido circular por el carril del extremo izquierdo los camiones registrados para un peso bruto de más de 48,000 libras?","options":["Cualquier carretera estatal de dos carriles con un límite señalizado de 55 mph o más","Todas las interestatales rurales con dos o más carriles en cada sentido","Cualquier carretera dividida en cualquier parte del estado, sin importar la cantidad de carriles","Interestatales, autopistas o vías rápidas dentro de áreas urbanizadas que tengan tres o más carriles en el mismo sentido"],"explanation":"Misuri prohíbe a los camiones registrados para más de 48,000 libras de peso bruto circular por el carril del extremo izquierdo en autopistas interestatales, autopistas o vías rápidas dentro de áreas urbanizadas que tengan tres o más carriles que avancen en el mismo sentido. Fuente: RSMo 304.015."},"58":{"q":"En Misuri, en una carretera con dos o más carriles de tráfico que avanzan en el mismo sentido, ¿por dónde debe circular generalmente un vehículo?","options":["Por el carril que tenga menos tráfico en ese momento","Por el carril derecho, salvo al rebasar, al prepararse para un giro a la izquierda, o cuando lo indiquen señales o marcas viales","Por el carril izquierdo, para mantener libre el carril derecho para el tráfico que ingresa","Por el carril central en cualquier vía que tenga tres carriles en el mismo sentido"],"explanation":"Misuri exige que todos los vehículos circulen por el carril derecho en carreteras con dos o más carriles en el mismo sentido, salvo al alcanzar y rebasar, al prepararse para un giro adecuado a la izquierda, o cuando lo indiquen marcas, señales o semáforos de tráfico. Fuente: RSMo 304.015."},"59":{"q":"Un autobús o un vehículo con materiales peligrosos rotulado que se aproxima a un cruce ferroviario en Misuri debe detenerse ¿a qué distancia del riel más cercano?","options":["A menos de 100 pies pero no a menos de 25 pies","A menos de 75 pies pero no a menos de 10 pies","A menos de 50 pies pero no a menos de 15 pies","A menos de 25 pies pero no a menos de 5 pies"],"explanation":"Los autobuses y los vehículos con HazMat rotulados deben detenerse a menos de 50 pies pero no a menos de 15 pies del riel más cercano, y luego mirar y escuchar antes de cruzar. Fuente: Manual CDL de Misuri; 49 CFR 392.10."},"60":{"q":"En una carretera de Misuri, el conductor de un vehículo que se cruza con un autobús escolar detenido, o que lo va a rebasar, mientras este muestra su señal de alto, ¿qué debe hacer?","options":["Detener el vehículo antes de llegar al autobús, ya sea que circule hacia el autobús o detrás de él","Detenerse solo si circula en el mismo sentido que el autobús","Reducir a 10 mph y pasar con precaución sin detenerse","Detenerse solo si hay niños visiblemente presentes al borde de la carretera"],"explanation":"Misuri exige que un conductor que se cruce con un autobús escolar desde cualquier sentido, o que lo vaya a rebasar, mientras este está detenido y señalizando, detenga el vehículo antes de llegar al autobús. La excepción es para calzadas separadas o tráfico en sentido opuesto en carreteras de cuatro o más carriles. Fuente: RSMo 304.050."},"61":{"q":"¿Cuál excepción de Misuri permite que un conductor NO se detenga ante un autobús escolar que recoge o deja niños?","options":["El conductor circula a menos de 25 mph en ese momento","El autobús tiene sus luces ámbar (amarillas) intermitentes encendidas pero no sus luces rojas","El conductor está a más de 100 pies del autobús cuando este se detiene","El autobús está en una calzada distinta, o circula en sentido opuesto en una carretera con cuatro o más carriles de tráfico"],"explanation":"Un conductor en una carretera con calzadas separadas no necesita detenerse ante un autobús escolar que está en una calzada distinta, o que circula en sentido opuesto en una carretera que tiene cuatro o más carriles de tráfico. Fuente: RSMo 304.050."},"62":{"q":"Según la ley Move Over de Misuri, cuando un conductor se aproxima a un vehículo estacionado de emergencia, de remolque, de servicios públicos o de MoDOT que muestra luces de advertencia en una vía con al menos cuatro carriles (dos o más en el mismo sentido), ¿qué debe hacer primero el conductor?","options":["Detenerse por completo hasta que el vehículo estacionado se retire","Cambiar a un carril que no sea adyacente al vehículo estacionado, si puede hacerse de forma segura","Tocar la bocina de forma continua mientras pasa junto al vehículo estacionado","Orillarse al acotamiento derecho y esperar una señal de vía libre"],"explanation":"La ley Move Over de Misuri exige que un conductor, cuando la vía tiene al menos cuatro carriles con dos o más en el mismo sentido, cambie a un carril que no sea adyacente al vehículo estacionado cuando pueda hacerse de forma segura. Fuente: RSMo 304.022."},"63":{"q":"Según la ley Move Over de Misuri, si cambiar de carril para alejarse de un vehículo estacionado de emergencia o de servicios públicos es inseguro o imposible, ¿qué debe hacer en su lugar el conductor?","options":["Detenerse por completo en el carril actual hasta que el tráfico se despeje","Mantener el límite de velocidad señalizado y continuar de frente","Avanzar con la debida precaución y reducir la velocidad, manteniendo una velocidad segura para las condiciones de la vía","Activar las luces intermitentes de emergencia y acelerar rápidamente para pasar la escena"],"explanation":"Cuando no se puede cambiar de carril de forma segura, Misuri exige que el conductor avance con la debida precaución y reduzca la velocidad del vehículo, manteniendo una velocidad segura para las condiciones de la vía. Fuente: RSMo 304.022."},"64":{"q":"Un conductor comercial de Misuri debe llevar dispositivos de advertencia para usarlos cuando se detenga en la carretera. ¿En qué consiste el requisito estándar?","options":["Tres triángulos reflectantes","Dos triángulos reflectantes y tres bengalas","Cuatro triángulos reflectantes","Un triángulo reflectante y dos banderas"],"explanation":"Un CMV debe estar equipado con tres triángulos reflectantes (o equivalentes aprobados) para colocarlos cuando se detenga sobre la vía o a un costado de ella. Fuente: Manual CDL de Misuri; 49 CFR 393.95 / 392.22."},"65":{"q":"Cuando un vehículo comercial de Misuri está detenido en una calzada dividida o de un solo sentido, ¿dónde deben colocarse los tres triángulos de advertencia?","options":["Los tres a 10 pies directamente detrás del vehículo","Uno a 10 pies atrás, uno a 100 pies atrás y uno a 100 pies adelante","Aproximadamente a 25, 50 y 100 pies detrás del vehículo","Aproximadamente a 10, 100 y 200 pies detrás del vehículo, hacia el tráfico que se aproxima"],"explanation":"En una vía dividida o de un solo sentido, los tres triángulos se colocan hacia el tráfico que se aproxima, aproximadamente a 10 pies, 100 pies y 200 pies detrás del CMV detenido. Fuente: Manual CDL de Misuri; 49 CFR 392.22."},"66":{"q":"Cuando un vehículo comercial de Misuri está detenido en una vía de dos carriles, de doble sentido y no dividida, ¿dónde deben colocarse los triángulos de advertencia?","options":["Uno aproximadamente a 10 pies atrás, uno aproximadamente a 200 pies atrás y uno aproximadamente a 200 pies adelante","Uno aproximadamente a 10 pies atrás, uno aproximadamente a 100 pies atrás y uno aproximadamente a 100 pies adelante del vehículo","Los tres detrás del vehículo a 10, 100 y 200 pies","Uno a cada lado del vehículo y uno directamente detrás de él"],"explanation":"En una vía de dos carriles y doble sentido, el conductor coloca un triángulo a menos de 10 pies de la parte trasera, uno aproximadamente a 100 pies atrás y uno aproximadamente a 100 pies adelante del vehículo. Fuente: Manual CDL de Misuri; 49 CFR 392.22."},"67":{"q":"En una vía rápida rural de Misuri (que no sea interestatal ni autopista), ¿cuál es el límite de velocidad máximo?","options":["70 mph","60 mph","65 mph","55 mph"],"explanation":"Misuri fija la velocidad máxima en las vías rápidas rurales en 65 mph, por debajo de las 70 mph permitidas en las interestatales y autopistas rurales. Fuente: RSMo 304.010."},"68":{"q":"¿Cuál es el límite de velocidad máximo en una interestatal, autopista o vía rápida de Misuri ubicada dentro de un área urbanizada?","options":["60 mph","65 mph","70 mph","55 mph"],"explanation":"Dentro de las áreas urbanizadas, Misuri limita las interestatales, autopistas y vías rápidas a 60 mph a menos que se señalice un límite menor. Fuente: RSMo 304.010."},"69":{"q":"¿Cuál cruce ferroviario NO exige que un autobús o un CMV con HazMat rotulado de Misuri haga la parada obligatoria?","options":["Cualquier cruce en un área rural sin luces intermitentes","Cualquier cruce que tenga un crucero (crossbuck) pero sin barrera","Cualquier cruce en una vía señalizada por debajo de 45 mph","Un cruce de tranvía o una vía de maniobras industriales dentro de un distrito comercial, o un cruce marcado con un letrero de 'Exempt'"],"explanation":"La parada obligatoria no aplica en cruces de tranvía o vías de maniobras industriales dentro de un distrito comercial, en cruces abandonados marcados como tales, ni en cruces marcados con un letrero autorizado de 'Exempt'. Fuente: Manual CDL de Misuri; 49 CFR 392.10."},"70":{"q":"¿Cuál es el ancho máximo legal del vehículo, incluida la carga, en las carreteras de Misuri antes de requerir un permiso de sobredimensión?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"explanation":"Misuri limita el ancho del vehículo, incluida la carga, a 102 inches (8 feet 6 inches); superar esto requiere un permiso de sobredimensión. Fuente: RSMo 304.170; MoDOT Motor Carrier Services."},"71":{"q":"¿Cuál es la altura máxima legal del vehículo, incluida la carga, en el sistema de autopistas interestatales de Misuri antes de requerir un permiso de sobredimensión?","options":["13 feet 6 inches","15 feet","14 feet","16 feet"],"explanation":"Misuri limita la altura, incluida la carga, a 14 feet en el sistema de autopistas interestatales (15 feet en ciertas otras vías); superar eso requiere un permiso. Fuente: RSMo 304.170; MoDOT."},"72":{"q":"Sin un permiso de sobrepeso, ¿cuál es el peso bruto vehicular máximo permitido generalmente en las autopistas interestatales de Misuri?","options":["80,000 pounds","73,280 pounds","88,000 pounds","90,000 pounds"],"explanation":"Misuri sigue el límite federal de 80,000 pounds de peso bruto máximo en el sistema interestatal sin un permiso de sobrepeso. Fuente: regulaciones de sobredimensión/sobrepeso de MoDOT; RSMo Capítulo 304."},"73":{"q":"¿Cuándo puede moverse generalmente una carga sobredimensionada en las carreteras de Misuri bajo un permiso estándar de un solo viaje?","options":["Solo entre la medianoche y las 6:00 a.m.","A cualquier hora del día o de la noche sin restricción","Solo los fines de semana y días feriados estatales","Desde media hora antes del amanecer hasta media hora después del atardecer"],"explanation":"MoDOT generalmente restringe el movimiento de cargas sobredimensionadas al periodo desde media hora antes del amanecer hasta media hora después del atardecer, con restricciones adicionales en feriados y fines de semana. Fuente: regulaciones de permisos de sobredimensión/sobrepeso de MoDOT."},"74":{"q":"¿Cuál es la longitud máxima de un semirremolque operado en las carreteras de Misuri sin un permiso?","options":["48 feet","53 feet","57 feet","60 feet"],"explanation":"Misuri limita un semirremolque a 53 feet de longitud en el sistema de carreteras antes de requerir un permiso. Fuente: RSMo 304.170."},"75":{"q":"Se requiere que un autobús escolar de Misuri sea claramente visible para los conductores que se aproximan ¿a qué distancia en una carretera sin acotamiento y con un límite de velocidad superior a 60 mph, de modo que el tráfico pueda detenerse?","options":["Al menos 300 feet en cada sentido","Al menos 200 feet en cada sentido","Al menos 500 feet en cada sentido","Al menos 1,000 feet en cada sentido"],"explanation":"En una carretera sin acotamiento y con un límite de velocidad superior a 60 mph, un autobús escolar que se detiene debe ser claramente visible al menos 500 feet en cada sentido (300 feet en otras carreteras). Fuente: RSMo 304.050."},"76":{"q":"¿Qué agencia de Misuri emite realmente el documento de la Licencia de Conducir Comercial (CDL)?","options":["El Departamento de Ingresos de Misuri (DOR)","La Patrulla de Caminos del Estado de Misuri","El Departamento de Transporte de Misuri (MoDOT)","La Administración Federal de Seguridad de Autotransportes (FMCSA)"],"explanation":"En Misuri, el Departamento de Ingresos (DOR) emite todas las licencias de conducir, incluida la CDL, mientras que la Patrulla de Caminos del Estado de Misuri administra los exámenes. Fuente: página de Conductores Comerciales del DOR de Misuri (dor.mo.gov/driver-license/issuance/commercial/)."},"77":{"q":"En Misuri, ¿quién administra los exámenes de conocimientos (escrito) y de habilidades de la CDL?","options":["La Patrulla de Caminos del Estado de Misuri","Las oficinas de licencias del Departamento de Ingresos de Misuri","Proveedores de capacitación privados registrados ante la FMCSA","El Departamento de Transporte de Misuri"],"explanation":"La Patrulla de Caminos del Estado de Misuri realiza el examen escrito de conocimientos de la CDL en sus Estaciones de Examinación de Conductores y el examen de habilidades (con cita) en los sitios de examen de CDL designados; luego el DOR emite la licencia. Fuente: página de Conductores Comerciales del DOR de Misuri y Manual CDL de Misuri."},"78":{"q":"¿Por cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) de Misuri, y se puede renovar?","options":["360 días, y no es renovable","180 días, y se puede renovar una vez","1 año, y se puede renovar por un segundo año","2 años, igualando el máximo federal"],"explanation":"Misuri emite el CLP por un periodo de 360 días y no es renovable; si vence, el solicitante debe completar nuevamente todos los exámenes de conocimientos requeridos. Fuente: Resumen de la Regla del Permiso CDL del DOR de Misuri (dor.mo.gov/driver-license/issuance/commercial/cdl-permit.html)."},"79":{"q":"¿Cuánto tiempo debe tener un solicitante de Misuri un Permiso de Aprendiz Comercial antes de ser elegible para tomar el examen de habilidades de la CDL?","options":["Un mínimo de 14 días","Un mínimo de 30 días","Un mínimo de 10 días","Un mínimo de 60 días"],"explanation":"Los solicitantes de una CDL deben tener un CLP por un mínimo de 14 días antes de completar el examen de habilidades para una CDL completa. Fuente: Resumen de la Regla del Permiso CDL del DOR de Misuri y la regla federal del CLP (49 CFR 383.25)."},"80":{"q":"¿Cuál capacitación debe completar un solicitante de Misuri ANTES de tomar el examen de habilidades para una CDL Clase A o Clase B por primera vez?","options":["Capacitación para Conductores Principiantes (ELDT) de un proveedor del Registro de Proveedores de Capacitación de la FMCSA","Un curso de manejo defensivo aprobado por el estado en una oficina del DOR","Un seminario de seguridad en aula de la Patrulla de Caminos del Estado de Misuri","Únicamente una orientación en el trabajo dirigida por el empleador"],"explanation":"Antes del examen de habilidades de la CDL (y para ciertos endosos nuevos), los solicitantes de Misuri deben completar la Capacitación para Conductores Principiantes (ELDT) de un proveedor incluido en el Registro de Proveedores de Capacitación de la FMCSA, vigente desde el 7 de febrero de 2022. Fuente: página de Conductores Comerciales del DOR de Misuri; regla ELDT de la FMCSA (49 CFR Parte 380)."},"81":{"q":"El examen de habilidades de la CDL de Misuri se compone de ¿cuáles tres partes, en orden?","options":["Inspección del vehículo (previa al viaje), control básico del vehículo y manejo en carretera","Conocimientos escritos, revisión de frenos de aire y manejo en carretera","Control básico del vehículo, revisión de materiales peligrosos y manejo en carretera","Inspección del vehículo, reexamen de conocimientos y evaluación de manejo defensivo"],"explanation":"El examen de habilidades modernizado de la CDL de Misuri tiene tres componentes: la inspección del vehículo (previa al viaje), el examen de habilidades de control básico del vehículo y el examen de manejo en carretera. Fuente: Manual CDL de Misuri y página de Conductores Comerciales del DOR de Misuri."},"82":{"q":"¿Cuáles son las cuatro categorías de autocertificación entre las que debe elegir un solicitante de CDL de Misuri?","options":["Interestatal no exceptuado, interestatal exceptuado, intraestatal no exceptuado e intraestatal exceptuado","Interestatal, intraestatal, regional y local","Comercial, agrícola, de emergencia y gubernamental","Clase A, Clase B, Clase C y materiales peligrosos"],"explanation":"Los solicitantes de CDL de Misuri deben autocertificarse en una de cuatro categorías: interestatal no exceptuado (NI), interestatal exceptuado (EI), intraestatal no exceptuado (NA) e intraestatal exceptuado (EA). Fuente: página de Requisitos de Certificación Médica de la CDL del DOR de Misuri."},"83":{"q":"¿Cuál categoría de autocertificación en Misuri requiere que el conductor esté calificado bajo 49 CFR Parte 391 y porte un certificado de examinador médico del DOT?","options":["Interestatal no exceptuado (NI)","Interestatal exceptuado (EI)","Intraestatal exceptuado (EA)","Interestatal exceptuado de emergencia (EE)"],"explanation":"Un conductor interestatal no exceptuado (NI) opera en comercio interestatal, está sujeto a 49 CFR Parte 391, y debe obtener y mantener un certificado de examinador médico del DOT. Las categorías exceptuadas no están sujetas a ese requisito federal de certificado médico. Fuente: página de Certificación Médica de la CDL del DOR de Misuri."},"84":{"q":"¿Cómo llega generalmente la información del certificado del examinador médico al Departamento de Ingresos de Misuri para el registro de un titular de CDL?","options":["Se transmite electrónicamente desde el Registro Nacional de Examinadores Médicos Certificados","El conductor siempre debe enviar por correo una tarjeta original en papel a MoDOT","El empleador del conductor la presenta ante la Patrulla de Caminos","Se carga únicamente a través de un proveedor externo de HAZMAT"],"explanation":"Misuri recibe la información del certificado del examinador médico transmitida electrónicamente desde el Registro Nacional de Examinadores Médicos Certificados, por lo que los conductores deben usar un examinador certificado incluido en ese registro. Fuente: página de Requisitos de Certificación Médica de la CDL del DOR de Misuri."},"85":{"q":"¿Qué le sucede a un conductor de CDL no exceptuado de Misuri que no mantiene archivado un certificado de examinador médico vigente?","options":["La CDL es degradada y se pierden los privilegios de manejo comercial","La CDL se suspende exactamente por 24 horas, y luego se restablece","Nada, porque Misuri no rastrea el estado médico","El conductor pasa automáticamente a la categoría intraestatal exceptuada"],"explanation":"Un conductor no exceptuado que deja vencer la certificación médica es degradado, perdiendo los privilegios de la CDL hasta que tenga un certificado vigente archivado. Fuente: Preguntas frecuentes de Certificación Médica de la CDL del DOR de Misuri; regla federal de certificación médica (49 CFR 383.71/383.73)."},"86":{"q":"¿Cuál es el ciclo de renovación estándar para una CDL de Misuri en poder de un conductor de 21 a 69 años?","options":["6 años","4 años","8 años","10 años"],"explanation":"Una CDL estándar de Misuri se emite por un término de 6 años para conductores de 21 a 69 años (se aplica un término de 3 años para conductores de 18 a 20 y de 70 o más). Fuente: información de emisión de licencias de conducir del DOR de Misuri."},"87":{"q":"Una CDL de Misuri con un endoso de Materiales Peligrosos (H) está vinculada a ¿cuál requisito adicional que puede acortar su validez?","options":["Una evaluación de amenazas de seguridad de la TSA (verificación de antecedentes)","Un reexamen de visión anual en una oficina del DOR","Un examen de manejo por separado de la Patrulla de Caminos cada año","Una carta de patrocinio del empleador notariada"],"explanation":"El endoso de HAZMAT requiere una evaluación de amenazas de seguridad de la TSA; en Misuri el endoso (y a menudo el término de la licencia) está vinculado a ese ciclo de verificación de antecedentes, por lo que es más corto que el término estándar de 6 años. Fuente: página de Conductores Comerciales del DOR de Misuri; regla federal de HAZMAT/TSA (49 CFR 1572)."},"88":{"q":"¿Cuál es la edad mínima para solicitar una CDL/CLP de Misuri para manejar un vehículo comercial ÚNICAMENTE dentro de Misuri (intraestatal)?","options":["18 años","16 años","21 años","19 años"],"explanation":"Misuri exige que los solicitantes tengan al menos 18 años para obtener un CLP/CDL para manejo comercial intraestatal; se requieren 21 años para operación interestatal. Fuente: Manual CDL de Misuri y página de Conductores Comerciales del DOR de Misuri."},"89":{"q":"¿Cuál es la edad mínima requerida para operar un vehículo comercial en comercio interestatal con una CDL de Misuri?","options":["21 años","18 años","19 años","25 años"],"explanation":"Los conductores deben tener al menos 21 años para operar en comercio interestatal; un titular de CDL de Misuri de 18 a 20 años generalmente está limitado al manejo intraestatal. Fuente: Manual CDL de Misuri; regla federal (49 CFR 391.11)."},"90":{"q":"Antes de que se le pueda emitir un CLP a un solicitante de Misuri, ¿cuál licencia de conducir debe ya poseer u obtener?","options":["Una licencia de conducir base (no comercial) válida de Misuri","Una CDL válida de otro estado","Únicamente un permiso de aprendiz de cualquier estado de EE. UU.","No se requiere ninguna licencia para obtener un CLP"],"explanation":"Un solicitante debe tener u obtener una licencia de conducir base de Misuri antes de que se pueda emitir un CLP de Misuri. Fuente: Resumen de la Regla del Permiso CDL del DOR de Misuri."},"91":{"q":"Cuando un CLP de Misuri vence antes de que el titular apruebe el examen de habilidades, ¿qué debe hacer el solicitante para obtener un nuevo CLP?","options":["Completar nuevamente todos los exámenes de conocimientos requeridos","Simplemente pagar un pequeño recargo de renovación sin volver a examinarse","Esperar 30 días y el CLP se reinstala automáticamente","Tomar solo el examen de habilidades, sin volver a examinarse de conocimientos"],"explanation":"Debido a que el CLP de 360 días no es renovable, cuando vence el solicitante debe completar nuevamente todos los exámenes de conocimientos requeridos para obtener un nuevo CLP. Fuente: Resumen de la Regla del Permiso CDL del DOR de Misuri."},"92":{"q":"¿Cuál endoso SÍ se permite colocar en un Permiso de Aprendiz Comercial (CLP) de Misuri?","options":["Autobús Escolar (S)","Materiales Peligrosos (H)","Vehículo Cisterna (N) transportando producto","Remolques Dobles/Triples (T)"],"explanation":"En un CLP de Misuri, se pueden portar los endosos de Autobús Escolar (S) y de Pasajeros (P) (con restricciones), pero los endosos de Materiales Peligrosos (H), Cisterna (X/N cuando está cargado) y Dobles/Triples (T) están prohibidos en un CLP. Fuente: Preguntas frecuentes de Examinación CDL/CLP del DOR de Misuri; regla federal del CLP (49 CFR 383.25)."},"93":{"q":"Según el proceso de verificación de documentos de Misuri, ¿cuántos empleados de la oficina de licencias deben participar de manera sustancial en la revisión de los documentos de un solicitante de CDL?","options":["Al menos dos empleados","Exactamente un empleado","Al menos cuatro empleados","No se requiere revisión de ningún empleado si los documentos se escanean"],"explanation":"Misuri exige que al menos dos empleados participen de manera sustancial en la revisión y verificación de la identidad, residencia y documentos de examen de un solicitante comercial. Fuente: Preguntas frecuentes de Examinación CDL/CLP del DOR de Misuri."},"94":{"q":"¿Cuál afirmación sobre un titular de licencia de otro estado que solicita un CLP de Misuri es correcta?","options":["Debe establecer residencia en Misuri y transferir primero a una licencia base de Misuri (lo cual puede ocurrir el mismo día)","Misuri emite libremente CLP a no residentes que tengan cualquier licencia válida de otro estado","Puede conservar su licencia de otro estado y nunca transferirla","Debe esperar 90 días como residente de Misuri antes de cualquier trámite de CLP"],"explanation":"Misuri no emite un CLP a un no residente; el solicitante debe establecer residencia en Misuri y transferir primero su licencia base, lo cual puede hacerse el mismo día de la solicitud del CLP. Fuente: Preguntas frecuentes de Examinación CDL/CLP del DOR de Misuri."},"95":{"q":"¿Cuál es el puntaje mínimo de aprobación en los exámenes de conocimientos (escrito) de la CDL de Misuri?","options":["80 por ciento","70 por ciento","75 por ciento","90 por ciento"],"explanation":"Los exámenes de conocimientos de la CDL de Misuri requieren un puntaje mínimo de 80 por ciento para aprobar, en concordancia con el estándar federal para los exámenes de conocimientos de la CDL. Fuente: Manual CDL de Misuri; estándar federal de examen de conocimientos (49 CFR 383.135)."}},"hi":{"0":{"q":"मिसौरी राजमार्गों पर बिना किसी विशेष परमिट के संचालित वाहन के लिए, लोड सहित, अनुमत अधिकतम चौड़ाई क्या है?","options":["96 inches","100 inches","102 inches","108 inches"],"explanation":"RSMo 304.170 के तहत, क्लीयरेंस लाइट और दर्पण जैसे सुरक्षा उपकरणों को छोड़कर, मिसौरी राजमार्गों पर कोई भी वाहन (उसके लोड सहित) चौड़ाई में 102 inches से अधिक नहीं हो सकता। इससे अधिक होने पर MoDOT ओवरसाइज़ परमिट की आवश्यकता होती है। स्रोत: Missouri Revised Statutes 304.170; Missouri Driver Guide Chapter 15।"},"1":{"q":"मिसौरी इंटरस्टेट और निर्दिष्ट राजमार्गों पर, बिना परमिट के, लोड सहित, अनुमत अधिकतम वाहन ऊंचाई क्या है?","options":["13 feet 6 inches","14 feet","14 feet 6 inches","15 feet"],"explanation":"RSMo 304.170 इंटरस्टेट और निर्दिष्ट राजमार्गों पर अधिकतम ऊंचाई, लोड सहित, 14 feet निर्धारित करता है। स्रोत: Missouri Revised Statutes 304.170।"},"2":{"q":"मिसौरी के इंटरस्टेट और निर्दिष्ट मार्गों के अलावा अन्य राजमार्गों पर, लोड सहित, सामान्य अधिकतम वाहन ऊंचाई क्या है?","options":["13 feet","13 feet 6 inches","14 feet","15 feet"],"explanation":"RSMo 304.170 इंटरस्टेट और निर्दिष्ट राजमार्गों के अलावा अन्य सभी राजमार्गों पर ऊंचाई को 13 feet 6 inches तक सीमित करता है। ऑटोमोबाइल परिवहन करने वाले वाहन अपवाद के रूप में 14 feet तक पहुंच सकते हैं। स्रोत: Missouri Revised Statutes 304.170।"},"3":{"q":"मिसौरी राजमार्गों पर संचालित एकल मोटर वाहन (जैसे स्ट्रेट ट्रक) की, लोड सहित, अधिकतम लंबाई क्या है?","options":["40 feet","45 feet","48 feet","53 feet"],"explanation":"RSMo 304.170 एकल मोटर वाहन को, लोड सहित, लंबाई में 45 feet तक सीमित करता है। लंबे संयोजन और सेमीट्रेलर अलग प्रावधानों द्वारा नियंत्रित होते हैं। स्रोत: Missouri Revised Statutes 304.170।"},"4":{"q":"मिसौरी में राष्ट्रीय नेटवर्क (इंटरस्टेट और निर्दिष्ट राजमार्ग) पर अनुमत अधिकतम सेमीट्रेलर लंबाई क्या है?","options":["48 feet","50 feet","53 feet","57 feet"],"explanation":"मिसौरी में इंटरस्टेट और निर्दिष्ट राजमार्गों के राष्ट्रीय नेटवर्क पर एक ट्रक-ट्रैक्टर/सेमीट्रेलर संयोजन में सेमीट्रेलर 53 feet तक लंबा हो सकता है, जो RSMo 304.170 और संघीय मानकों के अनुरूप है। स्रोत: Missouri Revised Statutes 304.170; Missouri Driver Guide Chapter 15।"},"5":{"q":"मिसौरी राजमार्गों पर बिना ओवरवेट परमिट के अनुमत अधिकतम सकल भार क्या है (जब कोई कम पोस्ट की गई ब्रिज सीमा न हो)?","options":["73,280 pounds","76,000 pounds","80,000 pounds","84,000 pounds"],"explanation":"RSMo 304.180 मिसौरी राजमार्गों पर सकल भार को 80,000 pounds तक सीमित करता है, सिवाय वहां जहां किसी पुल या संरचना के लिए इससे कम पोस्ट किया गया हो। यह संघीय इंटरस्टेट सीमा से मेल खाता है। स्रोत: Missouri Revised Statutes 304.180।"},"6":{"q":"मिसौरी की इंटरस्टेट प्रणाली पर एकल एक्सल पर अनुमत अधिकतम भार क्या है?","options":["18,000 pounds","20,000 pounds","22,000 pounds","24,000 pounds"],"explanation":"RSMo 304.180 और संघीय मानक इंटरस्टेट प्रणाली पर किसी भी एकल एक्सल को 20,000 pounds तक सीमित करते हैं। स्रोत: Missouri Revised Statutes 304.180।"},"7":{"q":"मिसौरी की इंटरस्टेट प्रणाली पर एक टैंडम एक्सल समूह पर अनुमत अधिकतम भार क्या है?","options":["30,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"RSMo 304.180 और संघीय मानक इंटरस्टेट प्रणाली पर एक टैंडम एक्सल समूह को 34,000 pounds तक सीमित करते हैं। स्रोत: Missouri Revised Statutes 304.180।"},"8":{"q":"मिसौरी कानून के तहत, एक्सलों के बीच की दूरी के आधार पर 'टैंडम एक्सल' को कैसे परिभाषित किया गया है?","options":["एक-दूसरे से 40 inches या उससे कम दूरी पर एक्सल","एक-दूसरे से 40 inches से अधिक लेकिन 96 inches से अधिक नहीं दूरी पर एक्सल","एक-दूसरे से 96 inches से अधिक लेकिन 120 inches से अधिक नहीं दूरी पर एक्सल","किसी भी दूरी पर कोई भी दो एक्सल"],"explanation":"RSMo 304.180 एक टैंडम एक्सल को दो या अधिक एक्सल के रूप में परिभाषित करता है जो एक के पीछे एक व्यवस्थित होते हैं और जिनके चरम सिरे 40 inches से अधिक तथा 96 inches से अधिक नहीं दूरी पर होते हैं। स्रोत: Missouri Revised Statutes 304.180।"},"9":{"q":"मिसौरी के उन राजमार्गों पर जो इंटरस्टेट प्रणाली का हिस्सा नहीं हैं, एक वाहन एकल- और टैंडम-एक्सल भार सीमा को कितना पार कर सकता है, बशर्ते सकल भार अभी भी 80,000 pounds से अधिक न हो?","options":["1,000 pounds तक","2,000 pounds तक","4,000 pounds तक","कोई सहनशीलता नहीं है"],"explanation":"RSMo 304.180 गैर-इंटरस्टेट राजमार्गों पर वाहनों को एकल- और टैंडम-एक्सल सीमा को 2,000 pounds तक पार करने की अनुमति देता है, लेकिन कुल सकल भार 80,000 pounds से अधिक नहीं हो सकता। स्रोत: Missouri Revised Statutes 304.180।"},"10":{"q":"मिसौरी के इंटरस्टेट और निर्दिष्ट राजमार्गों पर, किसी वाहन के लिए अधिकतम कानूनी भार मुख्य रूप से किसके द्वारा निर्धारित होता है?","options":["Federal Bridge Formula और तालिका","जमीन पर टायरों की संख्या","वाहन का पंजीकृत GVWR","ड्राइवर की CDL श्रेणी"],"explanation":"इंटरस्टेट और निर्दिष्ट राजमार्गों पर अधिकतम भार Federal Bridge Formula और तालिका द्वारा नियंत्रित होता है, जो अनुमेय सकल भार को एक्सलों की संख्या और उनके बीच की दूरी से जोड़ता है, जिसकी कुल अधिकतम सीमा 80,000 pounds है। स्रोत: Missouri Revised Statutes 304.180; FHWA Federal Bridge Formula।"},"11":{"q":"मिसौरी में प्रयुक्त Federal Bridge Formula अनुमेय सकल भार को किन दो कारकों के आधार पर सीमित करता है?","options":["टायर का दबाव और लोड का प्रकार","इंजन की अश्वशक्ति और एक्सल की संख्या","एक्सलों की संख्या और उनके बीच की दूरी","वाहन की आयु और पंजीकृत भार"],"explanation":"Federal Bridge Formula (Bridge Formula B) किसी भी लगातार एक्सलों के समूह पर अनुमेय भार को समूह में एक्सलों की संख्या और बाहरी एक्सलों के बीच की दूरी का उपयोग करके निर्धारित करता है, जिससे पुलों को अत्यधिक तनाव से बचाया जाता है। मिसौरी इसे RSMo 304.180 के तहत लागू करता है। स्रोत: Missouri Revised Statutes 304.180; FHWA।"},"12":{"q":"मिसौरी राजमार्गों पर संचालन के लिए MoDOT ओवरसाइज़/ओवरवेट परमिट कब आवश्यक होता है?","options":["केवल रात में यात्रा करते समय","जब वाहन और लोड कानूनी आकार या भार सीमा से अधिक हो जाएं","केवल राज्य के बाहर पंजीकृत वाहनों के लिए","जब भी वाहन का वजन 26,001 pounds से अधिक हो"],"explanation":"MoDOT ओवरसाइज़/ओवरवेट परमिट तब आवश्यक होता है जब किसी वाहन और उसके लोड की चौड़ाई, ऊंचाई, लंबाई या भार मिसौरी की कानूनी सीमाओं से अधिक हो जाए। जिन लोड को कानूनी सीमाओं में फिट करने के लिए उचित रूप से अलग किया जा सकता है, उन्हें आमतौर पर परमिट नहीं दिया जाता। स्रोत: Missouri DOT Motor Carrier Services / OSOW; RSMo 304.170-304.200।"},"13":{"q":"एक मानक MoDOT एकल-यात्रा ओवरसाइज़/ओवरवेट परमिट कितने समय के लिए वैध होता है?","options":["24 hours","लगातार सात दिन","30 days","एक वर्ष"],"explanation":"MoDOT एकल-यात्रा ओवरसाइज़/ओवरवेट परमिट लगातार सात दिनों के लिए वैध होते हैं। योग्य निरंतर संचालन के लिए वार्षिक (ब्लैंकेट) परमिट उपलब्ध हैं। स्रोत: Missouri DOT Oversize/Overweight permit regulations।"},"14":{"q":"मूल MoDOT एकल-यात्रा ओवरवेट परमिट शुल्क की गणना कैसे की जाती है?","options":["भार की परवाह किए बिना एक समान $50","$15 और कानूनी सकल भार से ऊपर प्रत्येक 10,000 pounds के लिए $20","$100 और प्रति एक्सल $5","प्रति यात्रा मील $25"],"explanation":"MoDOT एक आधार एकल-यात्रा परमिट शुल्क $15 और कानूनी सकल भार से ऊपर प्रत्येक 10,000 pounds (या अंश) के लिए $20 लेता है; बहुत भारी मूवमेंट के लिए एक ब्रिज और रोडवे विश्लेषण शुल्क जोड़ा जाता है। स्रोत: Missouri DOT Oversize/Overweight permit fee schedule।"},"15":{"q":"मिसौरी में अधिकांश ओवरसाइज़ लोड के लिए, दिन के समय की यात्रा आमतौर पर किस समय-सीमा तक प्रतिबंधित होती है?","options":["केवल आधी रात से दोपहर तक","सूर्योदय से आधा घंटा पहले से सूर्यास्त के आधा घंटा बाद तक","केवल सुबह 8:00 बजे से शाम 4:00 बजे तक","किसी भी समय, दिन में 24 घंटे"],"explanation":"मिसौरी में परमिट प्राप्त ओवरसाइज़ लोड आमतौर पर सूर्योदय से आधा घंटा पहले से सूर्यास्त के आधा घंटा बाद तक यात्रा कर सकते हैं; जो लोड केवल ओवरवेट हैं (कानूनी आकार के) वे लगातार चल सकते हैं। स्रोत: Missouri DOT Oversize/Overweight permit regulations।"},"16":{"q":"मिसौरी की कृषि भार छूट के तहत, इंटरस्टेट प्रणाली के अलावा अन्य राजमार्गों पर किसी फार्म से दूध ढोने वाले या पशुधन ढोने वाले वाहन के लिए अधिकतम सकल भार क्या है?","options":["80,000 pounds","82,000 pounds","85,500 pounds","90,000 pounds"],"explanation":"RSMo 304.180 किसी फार्म से प्रसंस्करण के लिए दूध ढोने वाले, या पशुधन ढोने वाले वाहन को इंटरस्टेट प्रणाली के अलावा अन्य राजमार्गों पर 85,500 pounds सकल भार तक पहुंचने की अनुमति देता है। यह इंटरस्टेट पर लागू नहीं होता। स्रोत: Missouri Revised Statutes 304.180; Missouri Dept. of Agriculture।"},"17":{"q":"मिसौरी की फसल-मौसम छूट के तहत, फसल के दौरान अनाज या अनाज के सह-उत्पाद ढोने वाले वाहन गैर-इंटरस्टेट राजमार्गों पर सामान्य भार सीमा को कितना पार कर सकते हैं?","options":["5 percent","10 percent","15 percent","एक समान 2,000 pounds"],"explanation":"RSMo 304.180 फसल के समय अनाज और अनाज सह-उत्पाद ढोने वालों को इंटरस्टेट प्रणाली के अलावा अन्य राजमार्गों पर अधिकतम भार सीमा को 10 percent तक पार करने की अनुमति देता है। स्रोत: Missouri Revised Statutes 304.180; Missouri Dept. of Agriculture।"},"18":{"q":"मिसौरी की बढ़ी हुई भार वाली कृषि छूट का उपयोग करने वाले पशुधन या अनाज ढोने वाले को किस प्रतिबंध का पालन करना चाहिए?","options":["इंटरस्टेट प्रणाली का उपयोग नहीं करना चाहिए या लोड के भार से कम पोस्ट किए गए पुल को पार नहीं करना चाहिए","केवल रात में यात्रा करनी चाहिए","हर समय दो फ्लैग व्यक्ति रखने चाहिए","केवल फार्म के 25 मील के भीतर ही संचालन कर सकते हैं"],"explanation":"RSMo 304.180 के तहत, बढ़ी हुई कृषि भार छूट का उपयोग करने वाले ढोने वाले इंटरस्टेट राजमार्ग प्रणाली के किसी भी हिस्से का उपयोग नहीं कर सकते और किसी भी पुल को पार नहीं कर सकते जो वाहन और लोड के सकल भार से कम के लिए पोस्ट किया गया हो। स्रोत: Missouri Revised Statutes 304.180; Missouri Dept. of Agriculture।"},"19":{"q":"मिसौरी आकार नियमों के तहत ऑटो-ट्रांसपोर्टरों के लिए आमतौर पर अनुमत अधिकतम आगे और पीछे का ओवरहैंग क्या है?","options":["आगे 2 feet, पीछे 3 feet","आगे 3 feet, पीछे 4 feet","आगे 4 feet, पीछे 6 feet","कोई ओवरहैंग अनुमत नहीं है"],"explanation":"RSMo 304.170 के तहत मिसौरी आकार नियम ऑटो-ट्रांसपोर्टरों को 3 feet से अधिक नहीं आगे का ओवरहैंग और 4 feet से अधिक नहीं पीछे का ओवरहैंग देने की अनुमति देते हैं। स्रोत: Missouri Revised Statutes 304.170।"},"20":{"q":"मिसौरी में, 26,001 या अधिक pounds के Gross Combination Weight Rating (GCWR) वाले वाहनों के किसी भी संयोजन को संचालित करने के लिए कौन सी CDL श्रेणी आवश्यक है, बशर्ते खींचे जा रहे वाहन का GVWR 10,000 pounds से अधिक हो?","options":["Class A","Class B","Class C","Class E"],"explanation":"मिसौरी Class A को वाहनों के किसी भी ऐसे संयोजन के रूप में परिभाषित करता है जिसका GCWR 26,001 या अधिक pounds हो और जहां खींची गई इकाई का GVWR 10,000 pounds से अधिक हो। स्रोत: Missouri Commercial Driver License Manual, Section 1 (CDL Classifications)।"},"21":{"q":"मिसौरी नियमों के तहत, 26,001+ pounds GVWR रेटेड एकल पावर यूनिट के लिए Class A (Class B के बजाय) CDL की आवश्यकता होने से पहले खींचे जा रहे वाहन का अधिकतम GVWR कितना होता है?","options":["8,000 pounds","10,000 pounds","15,000 pounds","26,001 pounds"],"explanation":"एक Class B CDL ऐसे एकल वाहन को कवर करता है जिसका GVWR 26,001+ lbs हो और जो 10,000 lbs GVWR से अधिक नहीं वाली इकाई को खींच रहा हो; यदि खींची गई इकाई 10,000 lbs GVWR से अधिक हो, तो Class A आवश्यक है। स्रोत: Missouri Commercial Driver License Manual, Section 1।"},"22":{"q":"मिसौरी CDL मैनुअल के अनुसार, Class C CDL केवल 26,001 pounds GVWR से कम वाले वाहन पर तब लागू होता है जब वह खतरनाक सामग्री के लिए प्लेकार्ड हो या कितने व्यक्तियों को ले जाने के लिए डिज़ाइन किया गया हो?","options":["9 या अधिक व्यक्ति, ड्राइवर सहित नहीं","12 या अधिक व्यक्ति, ड्राइवर सहित","15 या अधिक व्यक्ति, ड्राइवर सहित नहीं","16 या अधिक व्यक्ति, ऑपरेटर सहित"],"explanation":"मिसौरी का Class C ऐसे एकल वाहन को कवर करता है जिसका GVWR 26,001 lbs से कम हो और जो खतरनाक सामग्री के लिए प्लेकार्ड हो या 16 या अधिक व्यक्तियों, ऑपरेटर सहित, को ले जाने के लिए डिज़ाइन किया गया हो। स्रोत: Missouri Commercial Driver License Manual, Section 1।"},"23":{"q":"केवल इंट्रास्टेट ड्राइविंग (मिसौरी के भीतर) के लिए मिसौरी CDL प्राप्त करने हेतु न्यूनतम आयु क्या है?","options":["16 वर्ष","18 वर्ष","19 वर्ष","21 वर्ष"],"explanation":"मिसौरी CDL पात्रता इंट्रास्टेट संचालन (21 वर्ष की आयु तक) के लिए 18 वर्ष और इंटरस्टेट संचालन के लिए 21 वर्ष की आयु सूचीबद्ध करती है। स्रोत: Missouri Commercial Driver License Manual, 'Missouri CDL Eligibility।'"},"24":{"q":"एक मिसौरी ड्राइवर राज्य की सीमाओं के पार (इंटरस्टेट वाणिज्य) वाणिज्यिक वाहन संचालित करना चाहता है। इंटरस्टेट संचालन के लिए CDL रखने हेतु न्यूनतम आयु क्या है?","options":["18 वर्ष","19 वर्ष","20 वर्ष","21 वर्ष"],"explanation":"मिसौरी में इंटरस्टेट वाणिज्य में संचालन के लिए ड्राइवर का 21 वर्ष का होना आवश्यक है; 18 से 20 वर्ष के CDL धारक इंट्रास्टेट संचालन तक सीमित हैं। स्रोत: Missouri Commercial Driver License Manual, 'Missouri CDL Eligibility।'"},"25":{"q":"मिसौरी में CDL कौशल (रोड) परीक्षा देने से पहले, एक आवेदक को कम से कम कितने समय के लिए Commercial Learner's Permit (CLP) रखना आवश्यक है?","options":["7 days","14 days","30 days","60 days"],"explanation":"संघीय और मिसौरी नियमों के अनुसार कौशल परीक्षा देने से पहले CLP को कम से कम 14 days तक रखना आवश्यक है। स्रोत: Missouri DOR CDL Permit Rule Overview; 49 CFR 383.25।"},"26":{"q":"मिसौरी Commercial Learner's Permit (CLP) कितने समय के लिए वैध होता है, और क्या इसे नवीनीकृत किया जा सकता है?","options":["180 days, एक बार नवीनीकरणीय","360 days, गैर-नवीनीकरणीय","1 year, वार्षिक रूप से नवीनीकरणीय","2 years, गैर-नवीनीकरणीय"],"explanation":"मिसौरी CLP 360 days के लिए जारी किया जाता है और गैर-नवीनीकरणीय है; यदि यह समाप्त हो जाता है, तो आवेदक को आवश्यक ज्ञान परीक्षाएं फिर से देनी होंगी। स्रोत: Missouri DOR CDL Permit Rule Overview।"},"27":{"q":"मिसौरी में 16 या अधिक लोगों, ड्राइवर सहित, को ले जाने के लिए डिज़ाइन किए गए वाणिज्यिक वाहन को चलाने के लिए कौन सा एंडोर्समेंट आवश्यक है?","options":["S (School Bus) एंडोर्समेंट","P (Passenger) एंडोर्समेंट","N (Tanker) एंडोर्समेंट","T (Doubles/Triples) एंडोर्समेंट"],"explanation":"16 या अधिक लोगों, ड्राइवर सहित, को ले जाने के लिए डिज़ाइन किए गए वाहनों के लिए P (Passenger) एंडोर्समेंट आवश्यक है; इसके लिए एक ज्ञान परीक्षा और एक यात्री वाहन में कौशल परीक्षा आवश्यक है। स्रोत: Missouri Commercial Driver License Manual, Endorsements section।"},"28":{"q":"मिसौरी में, Tank Vehicle (N) एंडोर्समेंट ऐसे वाहन के लिए आवश्यक है जो किसी टैंक में तरल या गैस का परिवहन करता है जिसकी व्यक्तिगत रेटेड क्षमता 119 gallons से अधिक हो और कुल रेटेड क्षमता कितनी हो?","options":["500 gallons या अधिक","750 gallons या अधिक","1,000 gallons या अधिक","1,500 gallons या अधिक"],"explanation":"N एंडोर्समेंट उन टैंकों पर लागू होता है जिनकी व्यक्तिगत रेटेड क्षमता 119 gallons से अधिक और कुल रेटेड क्षमता 1,000 gallons या अधिक हो। स्रोत: Missouri Commercial Driver License Manual, Endorsements section; 49 CFR 383.5।"},"29":{"q":"मिसौरी में Class A ड्राइवरों को डबल या ट्रिपल ट्रेलर खींचने से पहले किस एंडोर्समेंट की आवश्यकता होती है?","options":["N (Tanker) एंडोर्समेंट","T (Doubles/Triples) एंडोर्समेंट","X (Combination) एंडोर्समेंट","H (Hazardous Materials) एंडोर्समेंट"],"explanation":"T (Doubles/Triples) एंडोर्समेंट के लिए एक विशेष ज्ञान परीक्षा पास करना आवश्यक है; यह उन Class A ड्राइवरों पर लागू होता है जो कई ट्रेलर खींचना चाहते हैं। स्रोत: Missouri Commercial Driver License Manual, Endorsements section।"},"30":{"q":"निम्नलिखित में से कौन सा एंडोर्समेंट मिसौरी Commercial Learner's Permit (CLP) में नहीं जोड़ा जा सकता?","options":["P (Passenger)","S (School Bus)","N (Tanker)","T (Doubles/Triples)"],"explanation":"मिसौरी CLP में केवल P (Passenger), S (School Bus), और N (Tanker) एंडोर्समेंट ही जोड़े जा सकते हैं। H, X, और T को CLP पर प्रतिबंधित किया गया है। स्रोत: Missouri Commercial Driver License Manual; 49 CFR 383.153(b); Section 302.700, RSMo।"},"31":{"q":"मिसौरी CDL में Hazardous Materials (H) एंडोर्समेंट जोड़ने से पहले, आवेदक को लिखित परीक्षा पास करनी होगी और किसकी मंजूरी प्राप्त करनी होगी?","options":["एक TSA सुरक्षा खतरा आकलन (पृष्ठभूमि जांच)","एक दृष्टि विशेषज्ञ की छूट","एक मिसौरी नियोक्ता प्रायोजन पत्र","एक DOT रोडसाइड निरीक्षण मंजूरी"],"explanation":"30 प्रश्नों वाली HazMat लिखित परीक्षा के अलावा, आवेदकों को H (या X) एंडोर्समेंट जोड़े जाने से पहले फिंगरप्रिंटिंग पूरी करनी होगी और एक TSA सुरक्षा खतरा आकलन की मंजूरी प्राप्त करनी होगी। स्रोत: Missouri DOR HazMat Endorsement Requirements; 49 CFR 1572।"},"32":{"q":"Hazardous Materials (H या X) एंडोर्समेंट वाला एक मिसौरी CDL, TSA सुरक्षा खतरा आकलन पूरा होने के बाद अधिकतम कितने वर्षों में समाप्त हो जाएगा?","options":["2 years","4 years","5 years","8 years"],"explanation":"चूंकि TSA पृष्ठभूमि जांच पांच वर्षों के लिए वैध होती है, इसलिए H या X एंडोर्समेंट वाला CDL सुरक्षा खतरा आकलन पूरा होने के बाद अधिकतम 5 years में समाप्त हो जाता है। स्रोत: Missouri DOR HazMat Endorsement / HME FAQs; 49 CFR 1572।"},"33":{"q":"मिसौरी में, School Bus (S) एंडोर्समेंट के लिए किस अतिरिक्त एंडोर्समेंट को भी प्राप्त करना आवश्यक है?","options":["N (Tanker) एंडोर्समेंट","P (Passenger) एंडोर्समेंट","H (Hazardous Materials) एंडोर्समेंट","T (Doubles/Triples) एंडोर्समेंट"],"explanation":"संघीय और मिसौरी नियमों के तहत, School Bus (S) एंडोर्समेंट के लिए Passenger (P) एंडोर्समेंट आवश्यक है; आवेदक को स्कूल बस ज्ञान परीक्षा और एक स्कूल बस में कौशल परीक्षा पास करनी होगी। स्रोत: Missouri Commercial Driver License Manual; 49 CFR 383.93।"},"34":{"q":"मिसौरी में CDL कौशल परीक्षा देने से पहले (7 फरवरी 2022 से प्रभावी), एक आवेदक को कहां सूचीबद्ध प्रदाता से Entry-Level Driver Training (ELDT) पूरा करना होगा?","options":["Missouri State Highway Patrol अनुमोदित-स्कूल सूची","FMCSA Training Provider Registry","Missouri Department of Revenue विक्रेता सूची","आवेदक की पसंद का कोई भी निजी CDL स्कूल"],"explanation":"प्रारंभिक CDL या कुछ एंडोर्समेंट के लिए कौशल परीक्षा से पहले ELDT को FMCSA की Training Provider Registry पर सूचीबद्ध प्रदाता के माध्यम से पूरा किया जाना चाहिए। स्रोत: Missouri DOR Commercial Drivers page; 49 CFR Part 380।"},"35":{"q":"मिसौरी CDL के लिए चिकित्सा स्थिति का स्व-प्रमाणन करते समय, एक ड्राइवर को कितनी संभावित श्रेणियों में से चुनना होगा?","options":["2 श्रेणियां","3 श्रेणियां","4 श्रेणियां","6 श्रेणियां"],"explanation":"ड्राइवर चार श्रेणियों में से एक में स्व-प्रमाणन करते हैं: non-excepted interstate, excepted interstate, non-excepted intrastate, या excepted intrastate। स्रोत: Missouri Commercial Driver License Manual, Medical Self-Certification; 49 CFR 383.71।"},"36":{"q":"एक मिसौरी CDL आवेदक जो 'non-excepted interstate' के रूप में प्रमाणित करता है, उसे और क्या करना होगा?","options":["एक वैध चिकित्सा परीक्षक का प्रमाणपत्र (DOT medical card) प्रदान करना और बनाए रखना","एक मिसौरी-केवल इंट्रास्टेट चिकित्सा छूट जमा करना","और कुछ नहीं देना; केवल प्रमाणन ही पर्याप्त है","एक मिसौरी ऑप्टोमेट्रिस्ट से वार्षिक दृष्टि परीक्षण प्राप्त करना"],"explanation":"non-excepted interstate के रूप में स्व-प्रमाणन करने वाला ड्राइवर संघीय चिकित्सा मानकों के अधीन होता है और उसे एक वैध चिकित्सा परीक्षक का प्रमाणपत्र जमा करना और वर्तमान बनाए रखना होगा, अन्यथा डाउनग्रेड होने का जोखिम होता है। स्रोत: Missouri Commercial Driver License Manual, Self-Certification; 49 CFR 391.41।"},"37":{"q":"CDL के लिए आवेदन करते समय मिसौरी अधिवास स्थापित करने के लिए, आवेदक के निवास पते को सत्यापित करने वाले कितने दस्तावेज़ आवश्यक हैं?","options":["एक दस्तावेज़","दो दस्तावेज़","तीन दस्तावेज़","यदि पूर्व लाइसेंस मौजूद हो तो कोई दस्तावेज़ नहीं"],"explanation":"मिसौरी पहचान के प्रमाण, Social Security number, और वैध उपस्थिति के अलावा मिसौरी निवास/अधिवास दर्शाने वाले दो स्वीकार्य दस्तावेज़ों की आवश्यकता रखता है। स्रोत: Missouri DOR Commercial Drivers page; Missouri CDL Manual, Eligibility।"},"38":{"q":"मिसौरी CDL आवेदक से किस वैध-उपस्थिति स्थिति की आवश्यकता होती है?","options":["स्थिति की परवाह किए बिना कोई भी वैध वीज़ा धारक","U.S. नागरिक या वैध स्थायी निवासी","केवल U.S. नागरिक","Social Security number वाला कोई भी आवेदक"],"explanation":"मिसौरी CDL आवेदकों से U.S. नागरिक या वैध स्थायी निवासी स्थिति वाले गैर-U.S. नागरिक होने की आवश्यकता रखता है। स्रोत: Missouri DOR Commercial Drivers page; Missouri CDL Manual, Eligibility।"},"39":{"q":"प्रत्येक मिसौरी CDL ज्ञान (लिखित) परीक्षा में न्यूनतम उत्तीर्णांक क्या है?","options":["70%","75%","80%","85%"],"explanation":"मिसौरी प्रत्येक CDL लिखित परीक्षा में 80% अंक की आवश्यकता रखता है, जो Highway Patrol परीक्षण स्थानों पर आयोजित की जाती हैं (उदाहरण के लिए, 50-प्रश्न General Knowledge, 30-प्रश्न HazMat, 20-प्रश्न एंडोर्समेंट परीक्षाएं)। स्रोत: Missouri Commercial Driver License Manual, Section 14 (CDL Written Examinations)।"},"40":{"q":"मिसौरी में, किसी ड्राइवर के पास वाणिज्यिक मोटर वाहन (CMV) चलाते समय अधिकतम कितना रक्त अल्कोहल सांद्रता (BAC) हो सकता है इससे पहले कि इसे एक प्रमुख अपराध माना जाए?","options":["0.04%","0.08%","0.02%","0.10%"],"explanation":"मिसौरी 0.04% या उससे अधिक BAC के साथ CMV चलाने पर रोक लगाता है (गैर-वाणिज्यिक ड्राइवरों के लिए 0.08% सीमा का आधा)। स्रोत: Missouri DOR Form 5231, 'Commercial Motor Vehicle Operators and the Law'; 49 CFR 383.51।"},"41":{"q":"मिसौरी के निहित सहमति कानून के तहत, यदि कोई CDL धारक कानूनी रूप से अनुरोध किए जाने पर रासायनिक (रक्त/श्वास) परीक्षण देने से इनकार करता है तो क्या होता है?","options":["CDL को 1 year के लिए अयोग्य कर दिया जाता है, पहले DWI के समान","बिना किसी अयोग्यता के केवल $500 का जुर्माना","60-day CDL अयोग्यता","कोई दंड नहीं क्योंकि इनकार को साक्ष्य के रूप में इस्तेमाल नहीं किया जा सकता"],"explanation":"एक CDL धारक के रूप में या CMV चलाते समय रक्त और/या श्वास परीक्षण से इनकार करना एक प्रमुख अपराध माना जाता है और इसके परिणामस्वरूप 1-year CDL अयोग्यता होती है, जो पहले DWI दोषसिद्धि के समान है। स्रोत: Missouri DOR Form 5231; Missouri implied consent law (Chapter 577 RSMo); 49 CFR 383.51।"},"42":{"q":"खतरनाक सामग्री का परिवहन न करते समय, पहले प्रमुख अपराध (जैसे CMV में DWI) के लिए CDL कितने समय के लिए अयोग्य किया जाता है?","options":["1 year","3 years","60 days","आजीवन"],"explanation":"पहला प्रमुख अपराध, जिसमें नशे में गाड़ी चलाना, परीक्षण से इनकार करना, या दुर्घटना स्थल छोड़ना शामिल है, के परिणामस्वरूप मिसौरी में 1-year CDL अयोग्यता होती है। स्रोत: Missouri DOR Form 5231; 49 CFR 383.51।"},"43":{"q":"एक ड्राइवर खतरनाक सामग्री के लिए प्लेकार्ड किए गए वाहन को चलाते समय पहला प्रमुख अपराध करता है। अयोग्यता अवधि क्या है?","options":["3 years","1 year","5 years","आजीवन"],"explanation":"प्लेकार्ड की गई खतरनाक सामग्री का परिवहन करते समय किया गया पहला प्रमुख अपराध, मानक 1 year के बजाय, 3-year CDL अयोग्यता लाता है। स्रोत: Missouri DOR Form 5231; 49 CFR 383.51।"},"44":{"q":"मिसौरी CDL पर दूसरे प्रमुख अपराध (उदाहरण के लिए, दूसरा DWI) का क्या परिणाम होता है?","options":["आजीवन अयोग्यता","3-year अयोग्यता","10-year अयोग्यता","1-year अयोग्यता"],"explanation":"सूचीबद्ध प्रमुख अपराधों में से किसी के लिए दूसरी दोषसिद्धि के परिणामस्वरूप मिसौरी में आजीवन CDL अयोग्यता होती है (कुछ ड्राइवर संघीय दिशानिर्देशों के तहत 10 years के बाद पुनर्बहाली के पात्र हो सकते हैं)। स्रोत: Missouri DOR Form 5231; 49 CFR 383.51।"},"45":{"q":"3-year की अवधि के भीतर कितने गंभीर यातायात उल्लंघनों के परिणामस्वरूप 60-day CDL अयोग्यता होती है?","options":["2","3","4","1"],"explanation":"तीन वर्षों के भीतर (CMV में) दो गंभीर यातायात दोषसिद्धियों के परिणामस्वरूप 60-day CDL अयोग्यता होती है। स्रोत: Missouri DOR Form 5231; 49 CFR 383.51।"},"46":{"q":"3 years के भीतर कितने गंभीर यातायात उल्लंघन 120-day CDL अयोग्यता की ओर ले जाते हैं?","options":["3 या अधिक","2","5 या अधिक","4 या अधिक"],"explanation":"तीन वर्षों के भीतर तीन या अधिक गंभीर यातायात दोषसिद्धियों के परिणामस्वरूप 120-day CDL अयोग्यता होती है। स्रोत: Missouri DOR Form 5231; 49 CFR 383.51।"},"47":{"q":"मिसौरी CDL धारक के लिए निम्नलिखित में से किसे 'गंभीर यातायात उल्लंघन' के रूप में वर्गीकृत किया गया है?","options":["पोस्ट की गई सीमा से 15 mph या अधिक तेज गति","पोस्ट की गई सीमा से 5 mph तेज गति","एक पार्किंग उल्लंघन","एक उपकरण लाइटिंग उल्लंघन"],"explanation":"गंभीर यातायात उल्लंघनों में सीमा से 15 mph या अधिक तेज गति, लापरवाह ड्राइविंग, अनुचित या अनियमित लेन परिवर्तन, और बहुत करीब से पीछा करना शामिल है। मामूली तेज गति और पार्किंग उल्लंघन 'गंभीर' नहीं हैं। स्रोत: Missouri DOR Form 5231; 49 CFR 383.51।"},"48":{"q":"किसी ड्राइवर के पहले रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए अयोग्यता अवधि क्या है?","options":["60 days","30 days","120 days","1 year"],"explanation":"पहला रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन न्यूनतम 60-day CDL अयोग्यता लाता है। स्रोत: Missouri DOR Form 5231; 49 CFR 383.51।"},"49":{"q":"एक CDL धारक 3 years के भीतर दूसरा रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन करता है। अयोग्यता अवधि क्या है?","options":["120 days","60 days","1 year","180 days"],"explanation":"तीन वर्षों के भीतर दूसरा रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन न्यूनतम 120-day अयोग्यता लाता है। स्रोत: Missouri DOR Form 5231; 49 CFR 383.51।"},"50":{"q":"3-year की अवधि के भीतर तीसरे रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए अयोग्यता अवधि क्या है?","options":["1 year","120 days","180 days","60 days"],"explanation":"तीन वर्षों के भीतर तीसरा या उसके बाद का रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन न्यूनतम 1-year अयोग्यता लाता है। स्रोत: Missouri DOR Form 5231; 49 CFR 383.51।"},"51":{"q":"अयोग्यता के अलावा, out-of-service आदेश का उल्लंघन करने पर ड्राइवर को किस नागरिक दंड सीमा का सामना करना पड़ सकता है?","options":["$1,000 से $2,500","$100 से $500","$250 से $750","$5,000 से $10,000"],"explanation":"जो ड्राइवर out-of-service आदेश का उल्लंघन करता है, उस पर अयोग्यता के अलावा, $1,000 से कम नहीं और $2,500 से अधिक नहीं का नागरिक दंड लगाया जाता है। स्रोत: 49 CFR 383.53; Missouri DOR Form 5231।"},"52":{"q":"RSMo 304.822 के तहत, हैंड्स-फ्री / टेक्स्टिंग निषेध के पहले उल्लंघन के लिए जुर्माना क्या है?","options":["$150","$50","$250","$500"],"explanation":"मिसौरी के Siddens Bening Hands Free Law के तहत, एक निर्धारित अवधि के भीतर पहले उल्लंघन के लिए जुर्माना $150, दूसरे के लिए $250, और तीसरे के लिए $500 है। स्रोत: Section 304.822 RSMo।"},"53":{"q":"एक CDL धारक को किसी नियंत्रित पदार्थ के निर्माण या वितरण से जुड़े गुनाह को अंजाम देने के लिए CMV का उपयोग करने का दोषी ठहराया जाता है। अयोग्यता क्या है?","options":["बिना पुनर्बहाली के आजीवन अयोग्यता","1-year अयोग्यता","3-year अयोग्यता","10-year अयोग्यता"],"explanation":"किसी नियंत्रित पदार्थ के निर्माण, वितरण या वितरण से जुड़े गुनाह को अंजाम देने में CMV का उपयोग करने के परिणामस्वरूप बिना पुनर्बहाली की किसी संभावना के आजीवन अयोग्यता होती है। स्रोत: Missouri DOR Form 5231; 49 CFR 383.51।"},"54":{"q":"निम्नलिखित में से कौन सा एक प्रमुख अपराध है जो पहली दोषसिद्धि पर 1-year CDL अयोग्यता को ट्रिगर करता है?","options":["CMV से जुड़ी दुर्घटना के स्थल को छोड़ना","बहुत करीब से पीछा करना","एक अनुचित लेन परिवर्तन","सीमा से 15 mph अधिक तेज गति"],"explanation":"CMV से जुड़ी दुर्घटना के स्थल को छोड़ना एक प्रमुख अपराध है (1-year पहली-अपराध अयोग्यता)। बहुत करीब से पीछा करना, अनुचित लेन परिवर्तन, और 15+ mph तेज गति 'गंभीर' उल्लंघन हैं, प्रमुख अपराध नहीं। स्रोत: Missouri DOR Form 5231; 49 CFR 383.51।"},"55":{"q":"एक ड्राइवर CMV के लापरवाह संचालन के माध्यम से किसी की मृत्यु का कारण बनता है (उदाहरण के लिए, वाहन से जुड़ी गैर-इरादतन हत्या)। CDL उद्देश्यों के लिए इसे कैसे वर्गीकृत किया गया है?","options":["एक प्रमुख अपराध जो 1-year पहली-अपराध अयोग्यता लाता है","एक गंभीर यातायात उल्लंघन जो 60 days लाता है","एक रेलरोड-क्रॉसिंग उल्लंघन जो 120 days लाता है","एक out-of-service उल्लंघन जो 90 days लाता है"],"explanation":"CMV के लापरवाह या आपराधिक संचालन के माध्यम से किसी की मृत्यु का कारण बनना एक प्रमुख अपराध है, जिसके परिणामस्वरूप पहली दोषसिद्धि पर 1-year अयोग्यता होती है (HazMat-प्लेकार्ड होने पर 3 years; दूसरे प्रमुख अपराध पर आजीवन)। स्रोत: Missouri DOR Form 5231; 49 CFR 383.51।"},"56":{"q":"मिसौरी के ग्रामीण इंटरस्टेट या फ्रीवे पर, जहाँ कोई कम सीमा पोस्ट नहीं की गई है, वहाँ किसी वाणिज्यिक मोटर वाहन (ट्रक) पर लागू होने वाली अधिकतम पोस्टेड गति सीमा क्या है?","options":["70 mph","65 mph","60 mph","55 mph"],"explanation":"मिसौरी ग्रामीण इंटरस्टेट और फ्रीवे पर अधिकतम गति 70 mph निर्धारित करता है, और ट्रकों के लिए कोई अलग, कम राज्यव्यापी गति सीमा नहीं है, इसलिए जब तक कोई कम गति पोस्ट न की गई हो, ट्रक भी वही 70 mph चला सकते हैं। स्रोत: RSMo 304.010।"},"57":{"q":"मिसौरी कानून के तहत, 48,000 पाउंड से अधिक के सकल वजन के लिए पंजीकृत ट्रकों को किन सड़कों पर सबसे बाईं लेन में चलाने से प्रतिबंधित किया गया है?","options":["कोई भी दो-लेन वाला राज्य राजमार्ग जिसकी पोस्टेड सीमा 55 mph या उससे अधिक हो","प्रत्येक दिशा में दो या अधिक लेन वाले सभी ग्रामीण इंटरस्टेट","राज्य में कहीं भी कोई भी विभाजित राजमार्ग, लेन की संख्या की परवाह किए बिना","शहरीकृत क्षेत्रों के भीतर इंटरस्टेट, फ्रीवे, या एक्सप्रेसवे जिनकी एक ही दिशा में तीन या अधिक लेन हों"],"explanation":"मिसौरी 48,000 पाउंड से अधिक सकल वजन के लिए पंजीकृत ट्रकों को शहरीकृत क्षेत्रों के भीतर इंटरस्टेट राजमार्गों, फ्रीवे, या एक्सप्रेसवे की सबसे बाईं लेन से प्रतिबंधित करता है जहाँ एक ही दिशा में तीन या अधिक लेन हों। स्रोत: RSMo 304.015।"},"58":{"q":"मिसौरी में, एक ही दिशा में जाने वाली दो या अधिक यातायात लेन वाले राजमार्ग पर, किसी वाहन को आम तौर पर कहाँ चलाया जाना चाहिए?","options":["उस समय जिस लेन में सबसे कम यातायात हो उसी में","दाईं लेन में, सिवाय जब ओवरटेक कर रहे हों, बाएँ मुड़ने की तैयारी कर रहे हों, या संकेतों/चिह्नों द्वारा अन्यथा निर्देशित किया गया हो","बाईं लेन में, ताकि प्रवेश करने वाले यातायात के लिए दाईं लेन खाली रहे","एक ही दिशा में तीन लेन वाली किसी भी सड़क पर बीच की लेन में"],"explanation":"मिसौरी की आवश्यकता है कि एक ही दिशा में दो या अधिक लेन वाले राजमार्गों पर सभी वाहन दाईं लेन में चलाए जाएँ, सिवाय जब ओवरटेक करके पास कर रहे हों, उचित बाएँ मोड़ की तैयारी कर रहे हों, या यातायात चिह्नों, संकेतों, या सिग्नलों द्वारा अन्यथा निर्देशित किया गया हो। स्रोत: RSMo 304.015।"},"59":{"q":"मिसौरी में रेलमार्ग क्रॉसिंग के पास पहुँचने वाली बस या प्लेकार्ड लगे खतरनाक-सामग्री वाहन को निकटतम रेल से कितनी दूरी पर रुकना चाहिए?","options":["100 फीट के भीतर लेकिन 25 फीट से कम नहीं","75 फीट के भीतर लेकिन 10 फीट से कम नहीं","50 फीट के भीतर लेकिन 15 फीट से कम नहीं","25 फीट के भीतर लेकिन 5 फीट से कम नहीं"],"explanation":"बसों और प्लेकार्ड लगे HazMat वाहनों को निकटतम रेल से 50 फीट के भीतर लेकिन 15 फीट से कम नहीं रुकना चाहिए, फिर पार करने से पहले देखना और सुनना चाहिए। स्रोत: मिसौरी CDL मैनुअल; 49 CFR 392.10।"},"60":{"q":"मिसौरी राजमार्ग पर, रुकी हुई स्कूल बस जो रुकने का संकेत दिखा रही हो, से मिलने या उसे ओवरटेक करने वाले वाहन के चालक को क्या करना चाहिए?","options":["बस तक पहुँचने से पहले वाहन रोक दें, चाहे बस की ओर जा रहे हों या उसके पीछे","केवल तभी रुकें जब बस के समान दिशा में जा रहे हों","10 mph तक धीमा करें और बिना रुके सावधानी से पास करें","केवल तभी रुकें जब सड़क के किनारे बच्चे स्पष्ट रूप से मौजूद हों"],"explanation":"मिसौरी की आवश्यकता है कि किसी भी दिशा से स्कूल बस से मिलने या उसे ओवरटेक करने वाला चालक, जो रुकी हुई हो और रुकने का संकेत दे रही हो, बस तक पहुँचने से पहले वाहन रोक दे। अपवाद चार-या-अधिक-लेन वाले राजमार्गों पर अलग सड़कों या विपरीत यातायात के लिए है। स्रोत: RSMo 304.050।"},"61":{"q":"मिसौरी का कौन सा अपवाद किसी चालक को बच्चों को चढ़ाने या उतारने वाली स्कूल बस के लिए न रुकने की अनुमति देता है?","options":["चालक उस समय 25 mph से कम गति से चल रहा है","बस की एम्बर (पीली) लाइटें जल रही हैं लेकिन उसकी लाल लाइटें नहीं","जब बस रुकती है तब चालक बस से 100 फीट से अधिक दूर है","बस एक अलग सड़क पर है, या चार या अधिक यातायात लेन वाले राजमार्ग पर विपरीत दिशा में जा रही है"],"explanation":"अलग सड़कों वाले राजमार्ग पर चालक को किसी अलग सड़क पर स्कूल बस के लिए, या चार या अधिक यातायात लेन वाले राजमार्ग पर विपरीत दिशा में जा रही बस के लिए रुकने की आवश्यकता नहीं है। स्रोत: RSMo 304.050।"},"62":{"q":"मिसौरी के मूव ओवर कानून के तहत, जब कोई चालक कम से कम चार लेन (एक ही दिशा में दो या अधिक) वाली सड़क पर चेतावनी लाइटें दिखाने वाले स्थिर आपातकालीन, टो, उपयोगिता, या MoDOT वाहन के पास पहुँचता है, तो चालक को पहले क्या करना चाहिए?","options":["स्थिर वाहन के चले जाने तक पूरी तरह रुक जाएँ","यदि सुरक्षित रूप से किया जा सके, तो स्थिर वाहन से सटी हुई लेन के अलावा किसी लेन में लेन बदलें","स्थिर वाहन को पास करते समय लगातार हॉर्न बजाएँ","दाएँ शोल्डर पर खींच लें और ऑल-क्लियर सिग्नल का इंतज़ार करें"],"explanation":"मिसौरी का मूव ओवर कानून की आवश्यकता है कि जहाँ सड़क में कम से कम चार लेन हों जिनमें से दो या अधिक एक ही दिशा में हों, चालक स्थिर वाहन से सटी हुई न होने वाली लेन में बदले जब यह सुरक्षित रूप से किया जा सके। स्रोत: RSMo 304.022।"},"63":{"q":"मिसौरी के मूव ओवर कानून के तहत, यदि स्थिर आपातकालीन/उपयोगिता वाहन से दूर लेन बदलना असुरक्षित या असंभव हो, तो चालक को इसके बजाय क्या करना चाहिए?","options":["यातायात साफ़ होने तक वर्तमान लेन में पूरी तरह रुक जाएँ","पोस्टेड गति सीमा बनाए रखें और सीधे आगे बढ़ते रहें","उचित सावधानी के साथ आगे बढ़ें और गति कम करें, सड़क की स्थितियों के लिए सुरक्षित गति बनाए रखें","हैज़र्ड फ्लैशर चालू करें और घटनास्थल को जल्दी से तेज़ी से पार करें"],"explanation":"जब लेन परिवर्तन सुरक्षित रूप से न किया जा सके, तो मिसौरी की आवश्यकता है कि चालक उचित सावधानी के साथ आगे बढ़े और वाहन की गति कम करे, सड़क की स्थितियों के लिए सुरक्षित गति बनाए रखे। स्रोत: RSMo 304.022।"},"64":{"q":"मिसौरी वाणिज्यिक चालक को राजमार्ग पर रुकने पर उपयोग के लिए चेतावनी उपकरण ले जाने चाहिए। मानक आवश्यकता में क्या शामिल है?","options":["तीन परावर्तक त्रिकोण","दो परावर्तक त्रिकोण और तीन फ्लेयर","चार परावर्तक त्रिकोण","एक परावर्तक त्रिकोण और दो झंडे"],"explanation":"एक CMV को तीन परावर्तक त्रिकोणों (या स्वीकृत समकक्षों) से सुसज्जित होना चाहिए जो सड़क पर या उसके किनारे रुकने पर लगाए जाएँ। स्रोत: मिसौरी CDL मैनुअल; 49 CFR 393.95 / 392.22।"},"65":{"q":"जब कोई मिसौरी वाणिज्यिक वाहन विभाजित या एक-तरफ़ा सड़क पर रुका हो, तो तीन चेतावनी त्रिकोणों को कहाँ रखा जाना चाहिए?","options":["तीनों को वाहन के ठीक पीछे 10 फीट पर","एक 10 फीट पीछे, एक 100 फीट पीछे, और एक 100 फीट आगे","वाहन के पीछे लगभग 25, 50, और 100 फीट पर","वाहन के पीछे लगभग 10, 100, और 200 फीट पर, आ रहे यातायात की ओर"],"explanation":"विभाजित या एक-तरफ़ा सड़क पर, तीनों त्रिकोण आ रहे यातायात की ओर रुके हुए CMV के पीछे लगभग 10 फीट, 100 फीट, और 200 फीट पर रखे जाते हैं। स्रोत: मिसौरी CDL मैनुअल; 49 CFR 392.22।"},"66":{"q":"जब कोई मिसौरी वाणिज्यिक वाहन दो-लेन, दो-तरफ़ा अविभाजित सड़क पर रुका हो, तो चेतावनी त्रिकोणों को कहाँ रखा जाना चाहिए?","options":["एक लगभग 10 फीट पीछे, एक लगभग 200 फीट पीछे, और एक लगभग 200 फीट आगे","एक लगभग 10 फीट पीछे, एक लगभग 100 फीट पीछे, और एक वाहन के लगभग 100 फीट आगे","तीनों वाहन के पीछे 10, 100, और 200 फीट पर","वाहन के प्रत्येक तरफ़ एक और एक ठीक उसके पीछे"],"explanation":"दो-लेन, दो-तरफ़ा सड़क पर चालक एक त्रिकोण पिछले हिस्से के 10 फीट के भीतर, एक लगभग 100 फीट पीछे, और एक वाहन के लगभग 100 फीट आगे रखता है। स्रोत: मिसौरी CDL मैनुअल; 49 CFR 392.22।"},"67":{"q":"मिसौरी ग्रामीण एक्सप्रेसवे (इंटरस्टेट या फ्रीवे नहीं) पर अधिकतम गति सीमा क्या है?","options":["70 mph","60 mph","65 mph","55 mph"],"explanation":"मिसौरी ग्रामीण एक्सप्रेसवे पर अधिकतम गति 65 mph निर्धारित करता है, जो ग्रामीण इंटरस्टेट और फ्रीवे पर अनुमत 70 mph से कम है। स्रोत: RSMo 304.010।"},"68":{"q":"शहरीकृत क्षेत्र के भीतर स्थित किसी मिसौरी इंटरस्टेट, फ्रीवे, या एक्सप्रेसवे पर अधिकतम गति सीमा क्या है?","options":["60 mph","65 mph","70 mph","55 mph"],"explanation":"शहरीकृत क्षेत्रों के भीतर, मिसौरी इंटरस्टेट, फ्रीवे, और एक्सप्रेसवे को 60 mph तक सीमित करता है जब तक कि कोई कम सीमा पोस्ट न की गई हो। स्रोत: RSMo 304.010।"},"69":{"q":"कौन सा रेलमार्ग क्रॉसिंग मिसौरी बस या प्लेकार्ड लगे HazMat CMV को अनिवार्य रूप से रुकने की आवश्यकता नहीं रखता?","options":["ग्रामीण क्षेत्र में कोई भी क्रॉसिंग जहाँ कोई चमकती लाइटें न हों","कोई भी क्रॉसिंग जिसमें क्रॉसबक हो लेकिन गेट न हो","45 mph से कम पोस्टेड किसी सड़क पर कोई भी क्रॉसिंग","व्यावसायिक जिले के भीतर स्ट्रीटकार क्रॉसिंग या औद्योगिक-स्विचिंग ट्रैक, या 'Exempt' संकेत से चिह्नित क्रॉसिंग"],"explanation":"अनिवार्य रोक व्यावसायिक जिले के भीतर स्ट्रीटकार क्रॉसिंग या औद्योगिक-स्विचिंग ट्रैक, इस तरह चिह्नित परित्यक्त क्रॉसिंग, या अधिकृत 'Exempt' संकेत से चिह्नित क्रॉसिंग पर लागू नहीं होती। स्रोत: मिसौरी CDL मैनुअल; 49 CFR 392.10।"},"70":{"q":"मिसौरी राजमार्गों पर ओवरसाइज़ परमिट की आवश्यकता होने से पहले, भार सहित अधिकतम कानूनी वाहन चौड़ाई क्या है?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"explanation":"मिसौरी वाहन की चौड़ाई, भार सहित, 102 inches (8 feet 6 inches) तक सीमित करता है; इससे अधिक होने पर ओवरसाइज़ परमिट की आवश्यकता होती है। स्रोत: RSMo 304.170; MoDOT मोटर कैरियर सेवाएँ।"},"71":{"q":"मिसौरी इंटरस्टेट राजमार्ग प्रणाली पर ओवरसाइज़ परमिट की आवश्यकता होने से पहले, भार सहित अधिकतम कानूनी वाहन ऊँचाई क्या है?","options":["13 feet 6 inches","15 feet","14 feet","16 feet"],"explanation":"मिसौरी इंटरस्टेट राजमार्ग प्रणाली पर ऊँचाई को, भार सहित, 14 feet तक सीमित करता है (कुछ अन्य सड़कों पर 15 feet); इससे अधिक होने पर परमिट की आवश्यकता होती है। स्रोत: RSMo 304.170; MoDOT।"},"72":{"q":"ओवरवेट परमिट के बिना, मिसौरी के इंटरस्टेट राजमार्गों पर आम तौर पर अनुमत अधिकतम सकल वाहन वजन क्या है?","options":["80,000 pounds","73,280 pounds","88,000 pounds","90,000 pounds"],"explanation":"मिसौरी ओवरवेट परमिट के बिना इंटरस्टेट प्रणाली पर 80,000 pounds अधिकतम सकल वजन की संघीय सीमा का पालन करता है। स्रोत: MoDOT ओवरसाइज़/ओवरवेट विनियम; RSMo अध्याय 304।"},"73":{"q":"मानक सिंगल-ट्रिप परमिट के तहत मिसौरी राजमार्गों पर ओवरसाइज़ भार को आम तौर पर कब ले जाया जा सकता है?","options":["केवल आधी रात से 6:00 a.m. के बीच","बिना किसी प्रतिबंध के दिन या रात के किसी भी समय","केवल सप्ताहांत और राज्य की छुट्टियों पर","सूर्योदय से आधा घंटा पहले से सूर्यास्त के आधा घंटा बाद तक"],"explanation":"MoDOT आम तौर पर ओवरसाइज़-भार आवाजाही को सूर्योदय से आधा घंटा पहले से सूर्यास्त के आधा घंटा बाद की अवधि तक सीमित करता है, साथ ही अतिरिक्त छुट्टी और सप्ताहांत प्रतिबंधों के साथ। स्रोत: MoDOT ओवरसाइज़/ओवरवेट परमिट विनियम।"},"74":{"q":"बिना परमिट के मिसौरी राजमार्गों पर संचालित सेमीट्रेलर की अधिकतम लंबाई क्या है?","options":["48 feet","53 feet","57 feet","60 feet"],"explanation":"मिसौरी राजमार्ग प्रणाली पर परमिट की आवश्यकता होने से पहले सेमीट्रेलर को 53 feet लंबाई तक सीमित करता है। स्रोत: RSMo 304.170।"},"75":{"q":"मिसौरी स्कूल बस को बिना शोल्डर वाले और 60 mph से अधिक गति सीमा वाले राजमार्ग पर आ रहे चालकों को कितनी दूरी तक स्पष्ट रूप से दिखाई देना आवश्यक है, ताकि यातायात रुक सके?","options":["प्रत्येक दिशा में कम से कम 300 फीट","प्रत्येक दिशा में कम से कम 200 फीट","प्रत्येक दिशा में कम से कम 500 फीट","प्रत्येक दिशा में कम से कम 1,000 फीट"],"explanation":"बिना शोल्डर वाले और 60 mph से अधिक गति सीमा वाले राजमार्ग पर, रुकने वाली स्कूल बस प्रत्येक दिशा में कम से कम 500 फीट तक स्पष्ट रूप से दिखाई देनी चाहिए (अन्य राजमार्गों पर 300 फीट)। स्रोत: RSMo 304.050।"},"76":{"q":"वास्तव में कौन सी मिसौरी एजेंसी कमर्शियल ड्राइवर लाइसेंस (CDL) दस्तावेज़ जारी करती है?","options":["Missouri Department of Revenue (DOR)","Missouri State Highway Patrol","Missouri Department of Transportation (MoDOT)","Federal Motor Carrier Safety Administration (FMCSA)"],"explanation":"मिसौरी में Department of Revenue (DOR) सभी ड्राइवर लाइसेंस जारी करता है, जिसमें CDL भी शामिल है, जबकि Missouri State Highway Patrol परीक्षण आयोजित करता है। स्रोत: Missouri DOR Commercial Drivers पेज (dor.mo.gov/driver-license/issuance/commercial/)।"},"77":{"q":"मिसौरी में, CDL ज्ञान (लिखित) और कौशल परीक्षण कौन आयोजित करता है?","options":["Missouri State Highway Patrol","Missouri Department of Revenue लाइसेंस कार्यालय","निजी FMCSA-पंजीकृत प्रशिक्षण प्रदाता","Missouri Department of Transportation"],"explanation":"Missouri State Highway Patrol अपने Driver Examination Stations पर CDL लिखित ज्ञान परीक्षण और नामित CDL टेस्ट साइटों पर कौशल परीक्षण (अपॉइंटमेंट द्वारा) आयोजित करता है; फिर DOR लाइसेंस जारी करता है। स्रोत: Missouri DOR Commercial Drivers पेज और मिसौरी CDL मैनुअल।"},"78":{"q":"मिसौरी कमर्शियल लर्नर्स परमिट (CLP) कितने समय के लिए वैध होता है, और क्या इसका नवीनीकरण किया जा सकता है?","options":["360 दिन, और यह गैर-नवीकरणीय है","180 दिन, और इसे एक बार नवीनीकृत किया जा सकता है","1 वर्ष, और इसे दूसरे वर्ष के लिए नवीनीकृत किया जा सकता है","2 वर्ष, संघीय अधिकतम के अनुरूप"],"explanation":"मिसौरी CLP 360 दिनों की अवधि के लिए जारी करता है और यह गैर-नवीकरणीय है; यदि यह समाप्त हो जाता है, तो आवेदक को सभी आवश्यक ज्ञान परीक्षण फिर से पूरे करने होते हैं। स्रोत: Missouri DOR CDL Permit Rule Overview (dor.mo.gov/driver-license/issuance/commercial/cdl-permit.html)।"},"79":{"q":"मिसौरी आवेदक को CDL कौशल परीक्षण देने के योग्य होने से पहले कितने समय तक कमर्शियल लर्नर्स परमिट रखना होगा?","options":["न्यूनतम 14 दिन","न्यूनतम 30 दिन","न्यूनतम 10 दिन","न्यूनतम 60 दिन"],"explanation":"CDL के आवेदकों को पूर्ण CDL के लिए कौशल परीक्षण पूरा करने से पहले न्यूनतम 14 दिनों तक CLP रखना होगा। स्रोत: Missouri DOR CDL Permit Rule Overview और संघीय CLP नियम (49 CFR 383.25)।"},"80":{"q":"पहली बार Class A या Class B CDL के लिए कौशल परीक्षण देने से पहले मिसौरी आवेदक को कौन सा प्रशिक्षण पूरा करना होगा?","options":["FMCSA Training Provider Registry प्रदाता से Entry-Level Driver Training (ELDT)","DOR कार्यालय में राज्य-अनुमोदित रक्षात्मक-ड्राइविंग पाठ्यक्रम","Missouri State Highway Patrol की कक्षा सुरक्षा संगोष्ठी","केवल नियोक्ता-संचालित नौकरी-पर अभिविन्यास"],"explanation":"CDL कौशल परीक्षण से पहले (और कुछ नए एंडोर्समेंट के लिए), मिसौरी आवेदकों को FMCSA के Training Provider Registry में सूचीबद्ध प्रदाता से Entry-Level Driver Training (ELDT) पूरा करना होगा, जो 7 फरवरी, 2022 से प्रभावी है। स्रोत: Missouri DOR Commercial Drivers पेज; FMCSA ELDT नियम (49 CFR Part 380)।"},"81":{"q":"मिसौरी CDL कौशल परीक्षण किन तीन भागों से, क्रम में, बना होता है?","options":["वाहन (प्री-ट्रिप) निरीक्षण, बुनियादी वाहन नियंत्रण, और सड़क पर ड्राइविंग","लिखित ज्ञान, एयर-ब्रेक जाँच, और सड़क पर ड्राइविंग","बुनियादी वाहन नियंत्रण, खतरनाक-सामग्री जाँच, और सड़क पर ड्राइविंग","वाहन निरीक्षण, ज्ञान पुनः-परीक्षण, और रक्षात्मक-ड्राइविंग मूल्यांकन"],"explanation":"मिसौरी के आधुनिकीकृत CDL कौशल परीक्षण में तीन घटक होते हैं: वाहन (प्री-ट्रिप) निरीक्षण, बुनियादी वाहन नियंत्रण कौशल परीक्षण, और सड़क पर ड्राइविंग परीक्षण। स्रोत: मिसौरी CDL मैनुअल और Missouri DOR Commercial Drivers पेज।"},"82":{"q":"मिसौरी CDL आवेदक को किन चार स्व-प्रमाणन श्रेणियों में से चुनना होगा?","options":["नॉन-एक्सेप्टेड इंटरस्टेट, एक्सेप्टेड इंटरस्टेट, नॉन-एक्सेप्टेड इंट्रास्टेट, और एक्सेप्टेड इंट्रास्टेट","इंटरस्टेट, इंट्रास्टेट, क्षेत्रीय, और स्थानीय","वाणिज्यिक, कृषि, आपातकालीन, और सरकारी","Class A, Class B, Class C, और hazmat"],"explanation":"मिसौरी CDL आवेदकों को चार श्रेणियों में से एक के लिए स्व-प्रमाणित करना होगा: नॉन-एक्सेप्टेड इंटरस्टेट (NI), एक्सेप्टेड इंटरस्टेट (EI), नॉन-एक्सेप्टेड इंट्रास्टेट (NA), और एक्सेप्टेड इंट्रास्टेट (EA)। स्रोत: Missouri DOR CDL Medical Certification Requirements पेज।"},"83":{"q":"मिसौरी में कौन सी स्व-प्रमाणन श्रेणी के लिए चालक को 49 CFR Part 391 के तहत योग्य होना और DOT चिकित्सा परीक्षक का प्रमाणपत्र रखना आवश्यक है?","options":["नॉन-एक्सेप्टेड इंटरस्टेट (NI)","एक्सेप्टेड इंटरस्टेट (EI)","एक्सेप्टेड इंट्रास्टेट (EA)","एक्सेप्टेड इंटरस्टेट इमरजेंसी (EE)"],"explanation":"एक नॉन-एक्सेप्टेड इंटरस्टेट (NI) चालक अंतरराज्यीय वाणिज्य में संचालन करता है, 49 CFR Part 391 के अधीन है, और उसे DOT चिकित्सा परीक्षक का प्रमाणपत्र प्राप्त करना और बनाए रखना होगा। एक्सेप्टेड श्रेणियाँ उस संघीय चिकित्सा-प्रमाणपत्र आवश्यकता के अधीन नहीं हैं। स्रोत: Missouri DOR CDL Medical Certification पेज।"},"84":{"q":"CDL धारक के रिकॉर्ड के लिए चिकित्सा परीक्षक का प्रमाणपत्र जानकारी आम तौर पर Missouri Department of Revenue तक कैसे पहुँचती है?","options":["यह National Registry of Certified Medical Examiners से इलेक्ट्रॉनिक रूप से प्रेषित होती है","चालक को हमेशा एक मूल कागज़ी कार्ड MoDOT को डाक से भेजना होगा","चालक का नियोक्ता इसे Highway Patrol के पास दाखिल करता है","यह केवल किसी तृतीय-पक्ष HAZMAT विक्रेता के माध्यम से अपलोड की जाती है"],"explanation":"मिसौरी National Registry of Certified Medical Examiners से इलेक्ट्रॉनिक रूप से प्रेषित चिकित्सा परीक्षक प्रमाणपत्र जानकारी प्राप्त करता है, इसलिए चालकों को उस रजिस्ट्री पर एक प्रमाणित परीक्षक का उपयोग करना होगा। स्रोत: Missouri DOR CDL Medical Certification Requirements पेज।"},"85":{"q":"उस नॉन-एक्सेप्टेड मिसौरी CDL चालक के साथ क्या होता है जो फ़ाइल में चालू चिकित्सा परीक्षक प्रमाणपत्र रखने में विफल रहता है?","options":["CDL को डाउनग्रेड कर दिया जाता है और वाणिज्यिक ड्राइविंग विशेषाधिकार खो जाते हैं","CDL को ठीक 24 घंटे के लिए निलंबित किया जाता है, फिर बहाल कर दिया जाता है","कुछ नहीं, क्योंकि मिसौरी चिकित्सा स्थिति को ट्रैक नहीं करता","चालक को स्वचालित रूप से एक्सेप्टेड इंट्रास्टेट श्रेणी में स्थानांतरित कर दिया जाता है"],"explanation":"एक नॉन-एक्सेप्टेड चालक जो चिकित्सा प्रमाणन को समाप्त होने देता है, उसे डाउनग्रेड कर दिया जाता है, और जब तक फ़ाइल में चालू प्रमाणपत्र न हो तब तक CDL विशेषाधिकार खो देता है। स्रोत: Missouri DOR CDL Medical Certification FAQ; संघीय चिकित्सा-प्रमाणन नियम (49 CFR 383.71/383.73)।"},"86":{"q":"21 से 69 वर्ष की आयु के चालक द्वारा रखे गए मिसौरी CDL के लिए मानक नवीनीकरण चक्र क्या है?","options":["6 वर्ष","4 वर्ष","8 वर्ष","10 वर्ष"],"explanation":"21 से 69 वर्ष की आयु के चालकों के लिए एक मानक मिसौरी CDL 6 वर्ष की अवधि के लिए जारी किया जाता है (18-20 और 70+ के चालकों के लिए 3 वर्ष की अवधि लागू होती है)। स्रोत: Missouri DOR ड्राइवर लाइसेंस जारी करने की जानकारी।"},"87":{"q":"Hazardous Materials (H) एंडोर्समेंट वाला मिसौरी CDL किस अतिरिक्त आवश्यकता से जुड़ा है जो इसकी वैधता को छोटा कर सकती है?","options":["एक TSA सुरक्षा खतरा मूल्यांकन (पृष्ठभूमि जाँच)","DOR कार्यालय में वार्षिक दृष्टि पुनः-परीक्षण","हर वर्ष एक अलग Highway Patrol रोड टेस्ट","एक नोटरीकृत नियोक्ता प्रायोजन पत्र"],"explanation":"HAZMAT एंडोर्समेंट के लिए एक TSA सुरक्षा खतरा मूल्यांकन आवश्यक है; मिसौरी में एंडोर्समेंट (और अक्सर लाइसेंस अवधि) उस पृष्ठभूमि-जाँच चक्र से जुड़ा होता है, इसलिए यह मानक 6-वर्ष की अवधि से छोटा होता है। स्रोत: Missouri DOR Commercial Drivers पेज; संघीय HAZMAT/TSA नियम (49 CFR 1572)।"},"88":{"q":"केवल मिसौरी के भीतर (इंट्रास्टेट) वाणिज्यिक मोटर वाहन चलाने के लिए मिसौरी CDL/CLP के लिए आवेदन करने की न्यूनतम आयु क्या है?","options":["18 वर्ष","16 वर्ष","21 वर्ष","19 वर्ष"],"explanation":"मिसौरी की आवश्यकता है कि इंट्रास्टेट वाणिज्यिक ड्राइविंग के लिए CLP/CDL प्राप्त करने के लिए आवेदक कम से कम 18 वर्ष का हो; अंतरराज्यीय संचालन के लिए 21 वर्ष आवश्यक है। स्रोत: मिसौरी CDL मैनुअल और Missouri DOR Commercial Drivers पेज।"},"89":{"q":"मिसौरी CDL पर अंतरराज्यीय वाणिज्य में वाणिज्यिक मोटर वाहन चलाने के लिए आवश्यक न्यूनतम आयु क्या है?","options":["21 वर्ष","18 वर्ष","19 वर्ष","25 वर्ष"],"explanation":"अंतरराज्यीय वाणिज्य में संचालन के लिए चालकों को कम से कम 21 वर्ष का होना चाहिए; 18-20 वर्ष का मिसौरी CDL धारक आम तौर पर इंट्रास्टेट ड्राइविंग तक सीमित होता है। स्रोत: मिसौरी CDL मैनुअल; संघीय नियम (49 CFR 391.11)।"},"90":{"q":"मिसौरी आवेदक को CLP जारी किए जाने से पहले, उसके पास पहले से कौन सा ड्राइवर लाइसेंस होना चाहिए या प्राप्त करना चाहिए?","options":["एक वैध मिसौरी बेस (गैर-वाणिज्यिक) ड्राइवर लाइसेंस","किसी अन्य राज्य से एक वैध CDL","केवल किसी भी U.S. राज्य से एक लर्नर्स परमिट","CLP प्राप्त करने के लिए किसी लाइसेंस की आवश्यकता नहीं है"],"explanation":"मिसौरी CLP जारी किए जाने से पहले आवेदक के पास एक मिसौरी बेस ड्राइवर लाइसेंस होना या प्राप्त करना चाहिए। स्रोत: Missouri DOR CDL Permit Rule Overview।"},"91":{"q":"जब धारक के कौशल परीक्षण पास करने से पहले मिसौरी CLP समाप्त हो जाता है, तो नया CLP प्राप्त करने के लिए आवेदक को क्या करना होगा?","options":["सभी आवश्यक ज्ञान परीक्षण फिर से पूरे करें","बिना किसी पुनः-परीक्षण के बस एक छोटा नवीनीकरण अधिभार चुकाएँ","30 दिन प्रतीक्षा करें और CLP स्वचालित रूप से बहाल हो जाता है","केवल कौशल परीक्षण दें, बिना किसी ज्ञान पुनः-परीक्षण के"],"explanation":"चूँकि 360-दिवसीय CLP गैर-नवीकरणीय है, जब यह समाप्त हो जाता है तो आवेदक को नया CLP प्राप्त करने के लिए सभी आवश्यक ज्ञान परीक्षण पूरे करने होंगे। स्रोत: Missouri DOR CDL Permit Rule Overview।"},"92":{"q":"कौन सा एंडोर्समेंट मिसौरी कमर्शियल लर्नर्स परमिट (CLP) पर रखने की अनुमति है?","options":["School Bus (S)","Hazardous Materials (H)","Tank Vehicle (N) उत्पाद ढोते हुए","Double/Triple Trailers (T)"],"explanation":"मिसौरी CLP पर, School Bus (S) और Passenger (P) एंडोर्समेंट रखे जा सकते हैं (प्रतिबंधों के साथ), लेकिन Hazardous Materials (H), Tank (लोड होने पर X/N), और Double/Triple (T) एंडोर्समेंट CLP पर प्रतिबंधित हैं। स्रोत: Missouri DOR CDL Testing/CLP FAQ; संघीय CLP नियम (49 CFR 383.25)।"},"93":{"q":"मिसौरी की दस्तावेज़-सत्यापन प्रक्रिया के तहत, CDL आवेदक के दस्तावेज़ों की समीक्षा में कितने लाइसेंस-कार्यालय कर्मचारियों को पर्याप्त रूप से भाग लेना चाहिए?","options":["कम से कम दो कर्मचारी","ठीक एक कर्मचारी","कम से कम चार कर्मचारी","यदि दस्तावेज़ स्कैन किए गए हों तो किसी कर्मचारी की समीक्षा आवश्यक नहीं है"],"explanation":"मिसौरी की आवश्यकता है कि कम से कम दो कर्मचारी एक वाणिज्यिक आवेदक की पहचान, निवास, और परीक्षण दस्तावेज़ों की समीक्षा और सत्यापन में पर्याप्त रूप से भाग लें। स्रोत: Missouri DOR CDL Testing/CLP FAQ।"},"94":{"q":"मिसौरी CLP के लिए आवेदन करने वाले राज्य-से-बाहर के लाइसेंस धारक के बारे में कौन सा कथन सही है?","options":["उन्हें पहले मिसौरी निवास स्थापित करना होगा और मिसौरी बेस लाइसेंस में स्थानांतरित होना होगा (जो उसी दिन हो सकता है)","मिसौरी किसी भी वैध राज्य-से-बाहर के लाइसेंस वाले गैर-निवासियों को स्वतंत्र रूप से CLP जारी करता है","वे अपना राज्य-से-बाहर का लाइसेंस रख सकते हैं और कभी इसे स्थानांतरित नहीं करते","उन्हें किसी भी CLP लेनदेन से पहले मिसौरी निवासी के रूप में 90 दिन प्रतीक्षा करनी होगी"],"explanation":"मिसौरी किसी गैर-निवासी को CLP जारी नहीं करता; आवेदक को पहले मिसौरी निवास स्थापित करना होगा और अपने बेस लाइसेंस को स्थानांतरित करना होगा, जो CLP आवेदन के उसी दिन किया जा सकता है। स्रोत: Missouri DOR CDL Testing/CLP FAQ।"},"95":{"q":"मिसौरी CDL ज्ञान (लिखित) परीक्षणों पर न्यूनतम उत्तीर्ण अंक क्या है?","options":["80 प्रतिशत","70 प्रतिशत","75 प्रतिशत","90 प्रतिशत"],"explanation":"मिसौरी CDL ज्ञान परीक्षणों को उत्तीर्ण करने के लिए न्यूनतम 80 प्रतिशत अंक आवश्यक हैं, जो CDL ज्ञान परीक्षण के संघीय मानक के अनुरूप है। स्रोत: मिसौरी CDL मैनुअल; संघीय ज्ञान-परीक्षण मानक (49 CFR 383.135)।"}},"ar":{"0":{"q":"ما هو الحد الأقصى للعرض، بما في ذلك الحمولة، المسموح به لمركبة تعمل على الطرق السريعة في ميسوري دون تصريح خاص؟","options":["96 بوصة","100 بوصة","102 بوصة","108 بوصة"],"explanation":"بموجب RSMo 304.170، لا يجوز لأي مركبة (بما في ذلك حمولتها) أن تتجاوز 102 بوصة في العرض على الطرق السريعة في ميسوري، باستثناء أجهزة السلامة مثل أضواء الإنارة والمرايا. ويتطلب تجاوز ذلك تصريح حجم زائد من MoDOT. المصدر: قوانين ميسوري المنقحة 304.170؛ دليل سائق ميسوري الفصل 15."},"1":{"q":"على الطرق السريعة بين الولايات والطرق المحددة في ميسوري، ما هو الحد الأقصى لارتفاع المركبة، بما في ذلك الحمولة، المسموح به دون تصريح؟","options":["13 قدماً و6 بوصات","14 قدماً","14 قدماً و6 بوصات","15 قدماً"],"explanation":"يحدد RSMo 304.170 الحد الأقصى للارتفاع على الطرق السريعة بين الولايات والطرق المحددة بـ 14 قدماً، بما في ذلك الحمولة. المصدر: قوانين ميسوري المنقحة 304.170."},"2":{"q":"على الطرق السريعة في ميسوري بخلاف الطرق السريعة بين الولايات والطرق المحددة، ما هو الحد الأقصى العام لارتفاع المركبة، بما في ذلك الحمولة؟","options":["13 قدماً","13 قدماً و6 بوصات","14 قدماً","15 قدماً"],"explanation":"يحد RSMo 304.170 الارتفاع بـ 13 قدماً و6 بوصات على جميع الطرق السريعة بخلاف الطرق السريعة بين الولايات والطرق المحددة. يجوز للمركبات التي تنقل السيارات أن تصل إلى 14 قدماً كاستثناء. المصدر: قوانين ميسوري المنقحة 304.170."},"3":{"q":"ما هو الحد الأقصى للطول، بما في ذلك الحمولة، لمركبة آلية مفردة (مثل شاحنة مستقيمة) تعمل على الطرق السريعة في ميسوري؟","options":["40 قدماً","45 قدماً","48 قدماً","53 قدماً"],"explanation":"يحد RSMo 304.170 المركبة الآلية المفردة، بما في ذلك الحمولة، بـ 45 قدماً في الطول. وتُنظم التركيبات الأطول وأنصاف المقطورات بأحكام منفصلة. المصدر: قوانين ميسوري المنقحة 304.170."},"4":{"q":"ما هو الحد الأقصى لطول نصف المقطورة المسموح به على الشبكة الوطنية (الطرق السريعة بين الولايات والطرق المحددة) في ميسوري؟","options":["48 قدماً","50 قدماً","53 قدماً","57 قدماً"],"explanation":"يجوز أن يصل طول نصف المقطورة في تركيبة شاحنة جرّارة/نصف مقطورة إلى 53 قدماً على الشبكة الوطنية للطرق السريعة بين الولايات والطرق المحددة في ميسوري، بما يتوافق مع RSMo 304.170 والمعايير الفيدرالية. المصدر: قوانين ميسوري المنقحة 304.170؛ دليل سائق ميسوري الفصل 15."},"5":{"q":"ما هو الحد الأقصى للوزن الإجمالي المسموح به على الطرق السريعة في ميسوري دون تصريح وزن زائد (في غياب حد جسر منشور أقل)؟","options":["73,280 رطلاً","76,000 رطل","80,000 رطل","84,000 رطل"],"explanation":"يحدد RSMo 304.180 سقف الوزن الإجمالي بـ 80,000 رطل على الطرق السريعة في ميسوري، باستثناء الحالات التي يُنشر فيها جسر أو منشأة لوزن أقل. ويتطابق هذا مع الحد الفيدرالي للطرق بين الولايات. المصدر: قوانين ميسوري المنقحة 304.180."},"6":{"q":"ما هو الحد الأقصى للوزن المسموح به على المحور المفرد على نظام الطرق السريعة بين الولايات في ميسوري؟","options":["18,000 رطل","20,000 رطل","22,000 رطل","24,000 رطل"],"explanation":"يحد RSMo 304.180 والمعيار الفيدرالي أي محور مفرد بـ 20,000 رطل على نظام الطرق السريعة بين الولايات. المصدر: قوانين ميسوري المنقحة 304.180."},"7":{"q":"ما هو الحد الأقصى للوزن المسموح به على مجموعة المحاور المزدوجة على نظام الطرق السريعة بين الولايات في ميسوري؟","options":["30,000 رطل","34,000 رطل","36,000 رطل","40,000 رطل"],"explanation":"يحد RSMo 304.180 والمعيار الفيدرالي مجموعة المحاور المزدوجة بـ 34,000 رطل على نظام الطرق السريعة بين الولايات. المصدر: قوانين ميسوري المنقحة 304.180."},"8":{"q":"بموجب قانون ميسوري، كيف يُعرّف 'المحور المزدوج' من حيث التباعد بين المحاور؟","options":["محاور متباعدة بمقدار 40 بوصة أو أقل","محاور متباعدة بأكثر من 40 بوصة ولكن ليس أكثر من 96 بوصة","محاور متباعدة بأكثر من 96 بوصة ولكن ليس أكثر من 120 بوصة","أي محورين بغض النظر عن التباعد"],"explanation":"يعرّف RSMo 304.180 المحور المزدوج بأنه محوران أو أكثر مرتبة واحدة خلف الأخرى ويكون التباعد بين أطرافها أكثر من 40 بوصة وليس أكثر من 96 بوصة. المصدر: قوانين ميسوري المنقحة 304.180."},"9":{"q":"على الطرق السريعة في ميسوري التي ليست جزءاً من نظام الطرق بين الولايات، بأي مقدار يجوز لمركبة أن تتجاوز حدود وزن المحور المفرد والمزدوج، شريطة ألا يتجاوز الوزن الإجمالي 80,000 رطل؟","options":["بما يصل إلى 1,000 رطل","بما يصل إلى 2,000 رطل","بما يصل إلى 4,000 رطل","لا يوجد هامش تسامح"],"explanation":"يسمح RSMo 304.180 للمركبات على الطرق السريعة غير التابعة للنظام بين الولايات بتجاوز حدود المحور المفرد والمزدوج بما يصل إلى 2,000 رطل، لكن لا يجوز أن يتجاوز إجمالي الوزن الإجمالي 80,000 رطل. المصدر: قوانين ميسوري المنقحة 304.180."},"10":{"q":"على الطرق السريعة بين الولايات والطرق المحددة في ميسوري، يُحدد الحد الأقصى للوزن القانوني للمركبة بشكل أساسي بناءً على ماذا؟","options":["صيغة الجسر الفيدرالية وجدولها","عدد الإطارات الملامسة للأرض","تصنيف الوزن الإجمالي المسجل للمركبة GVWR","فئة رخصة القيادة التجارية CDL للسائق"],"explanation":"تُنظم الأوزان القصوى على الطرق السريعة بين الولايات والطرق المحددة بموجب صيغة الجسر الفيدرالية وجدولها، التي تربط الوزن الإجمالي المسموح به بعدد المحاور والمسافة بينها، مع سقف إجمالي قدره 80,000 رطل. المصدر: قوانين ميسوري المنقحة 304.180؛ صيغة الجسر الفيدرالية لإدارة الطرق السريعة الفيدرالية FHWA."},"11":{"q":"تحد صيغة الجسر الفيدرالية المستخدمة في ميسوري الوزن الإجمالي المسموح به بناءً على أي عاملين؟","options":["ضغط الإطارات ونوع الحمولة","قدرة المحرك بالقوة الحصانية وعدد المحاور","عدد المحاور والمسافة بينها","عمر المركبة والوزن المسجل"],"explanation":"تحدد صيغة الجسر الفيدرالية (صيغة الجسر B) الوزن المسموح به على أي مجموعة من المحاور المتتالية باستخدام عدد المحاور في المجموعة والتباعد بين المحاور الخارجية، لحماية الجسور من الإجهاد الزائد. تطبق ميسوري ذلك بموجب RSMo 304.180. المصدر: قوانين ميسوري المنقحة 304.180؛ FHWA."},"12":{"q":"متى يكون تصريح الحجم الزائد/الوزن الزائد من MoDOT مطلوباً للعمل على الطرق السريعة في ميسوري؟","options":["فقط عند السفر ليلاً","عندما تتجاوز المركبة والحمولة حدود الحجم أو الوزن القانونية","فقط للمركبات المسجلة خارج الولاية","كلما زاد وزن المركبة عن 26,001 رطل"],"explanation":"يكون تصريح الحجم الزائد/الوزن الزائد من MoDOT مطلوباً كلما تجاوزت المركبة وحمولتها الحدود القانونية في ميسوري للعرض أو الارتفاع أو الطول أو الوزن. والحمولات التي يمكن تفكيكها بشكل معقول لتلائم الحدود القانونية لا تُمنح تصريحاً بشكل عام. المصدر: خدمات الناقل الآلي / OSOW بوزارة النقل في ميسوري؛ RSMo 304.170-304.200."},"13":{"q":"تصريح الحجم الزائد/الوزن الزائد القياسي لرحلة واحدة من MoDOT صالح لمدة كم؟","options":["24 ساعة","سبعة أيام متتالية","30 يوماً","سنة واحدة"],"explanation":"تصاريح الحجم الزائد/الوزن الزائد لرحلة واحدة من MoDOT صالحة لمدة سبعة أيام متتالية. وتتوفر التصاريح السنوية (الشاملة) للعمليات المستمرة المؤهلة. المصدر: لوائح تصريح الحجم الزائد/الوزن الزائد بوزارة النقل في ميسوري."},"14":{"q":"كيف تُحسب رسوم تصريح الوزن الزائد الأساسي لرحلة واحدة من MoDOT؟","options":["رسم ثابت قدره 50 دولاراً بغض النظر عن الوزن","15 دولاراً بالإضافة إلى 20 دولاراً لكل 10,000 رطل تتجاوز الوزن الإجمالي القانوني","100 دولار بالإضافة إلى 5 دولارات لكل محور","25 دولاراً لكل ميل مقطوع"],"explanation":"تفرض MoDOT رسماً أساسياً لتصريح رحلة واحدة قدره 15 دولاراً بالإضافة إلى 20 دولاراً لكل 10,000 رطل (أو جزء منها) فوق الوزن الإجمالي القانوني؛ وتضيف عمليات النقل شديدة الثقل رسم تحليل للجسر والطريق. المصدر: جدول رسوم تصريح الحجم الزائد/الوزن الزائد بوزارة النقل في ميسوري."},"15":{"q":"بالنسبة لمعظم الحمولات ذات الحجم الزائد في ميسوري، يُقيَّد السفر النهاري بشكل عام بأي نافذة زمنية؟","options":["من منتصف الليل حتى الظهر فقط","من نصف ساعة قبل شروق الشمس إلى نصف ساعة بعد غروب الشمس","من الساعة 8:00 صباحاً إلى الساعة 4:00 مساءً فقط","في أي وقت، 24 ساعة في اليوم"],"explanation":"يجوز للحمولات ذات الحجم الزائد المُصرح بها في ميسوري السفر بشكل عام من نصف ساعة قبل شروق الشمس إلى نصف ساعة بعد غروب الشمس؛ أما الحمولات ذات الوزن الزائد فقط (بحجم قانوني) فيمكنها التحرك بشكل مستمر. المصدر: لوائح تصريح الحجم الزائد/الوزن الزائد بوزارة النقل في ميسوري."},"16":{"q":"بموجب استثناء الوزن الزراعي في ميسوري، ما هو الحد الأقصى للوزن الإجمالي لمركبة تنقل الحليب من مزرعة أو تنقل الماشية على الطرق السريعة بخلاف نظام الطرق بين الولايات؟","options":["80,000 رطل","82,000 رطل","85,500 رطل","90,000 رطل"],"explanation":"يسمح RSMo 304.180 لمركبة تنقل الحليب من مزرعة إلى معالجته، أو تنقل الماشية، بأن تصل إلى ما يصل إلى 85,500 رطل إجمالي على الطرق السريعة بخلاف نظام الطرق بين الولايات. ولا ينطبق هذا على الطرق بين الولايات. المصدر: قوانين ميسوري المنقحة 304.180؛ وزارة الزراعة في ميسوري."},"17":{"q":"بموجب استثناء موسم الحصاد في ميسوري، يجوز للمركبات التي تنقل الحبوب أو منتجاتها الثانوية خلال الحصاد أن تتجاوز حدود الوزن العادية على الطرق غير التابعة للنظام بين الولايات بأي مقدار؟","options":["5 بالمئة","10 بالمئة","15 بالمئة","2,000 رطل ثابتة"],"explanation":"يسمح RSMo 304.180 لناقلي الحبوب ومنتجاتها الثانوية خلال أوقات الحصاد بتجاوز الحدود القصوى للوزن بما يصل إلى 10 بالمئة على الطرق السريعة بخلاف نظام الطرق بين الولايات. المصدر: قوانين ميسوري المنقحة 304.180؛ وزارة الزراعة في ميسوري."},"18":{"q":"يجب على ناقل الماشية أو الحبوب الذي يستخدم استثناء الوزن الزراعي المتزايد في ميسوري الالتزام بأي قيد؟","options":["يجب ألا يستخدم نظام الطرق بين الولايات أو يعبر جسراً منشوراً لوزن أقل من وزن الحمولة","يجب أن يسافر ليلاً فقط","يجب أن يحمل شخصين حاملين للأعلام في جميع الأوقات","يجوز له العمل فقط في نطاق 25 ميلاً من المزرعة"],"explanation":"بموجب RSMo 304.180، لا يجوز للناقلين الذين يستخدمون بدل الوزن الزراعي المتزايد استخدام أي جزء من نظام الطرق السريعة بين الولايات ولا عبور أي جسر منشور لوزن أقل من الوزن الإجمالي للمركبة والحمولة. المصدر: قوانين ميسوري المنقحة 304.180؛ وزارة الزراعة في ميسوري."},"19":{"q":"ما هو الحد الأقصى للنتوء الأمامي والخلفي المسموح به عموماً لناقلات السيارات بموجب قواعد الحجم في ميسوري؟","options":["2 قدم أماماً، 3 أقدام خلفاً","3 أقدام أماماً، 4 أقدام خلفاً","4 أقدام أماماً، 6 أقدام خلفاً","لا يُسمح بأي نتوء"],"explanation":"تسمح قواعد الحجم في ميسوري بموجب RSMo 304.170 لناقلات السيارات بنتوء أمامي لا يزيد عن 3 أقدام ونتوء خلفي لا يزيد عن 4 أقدام. المصدر: قوانين ميسوري المنقحة 304.170."},"20":{"q":"في ميسوري، ما هي فئة رخصة القيادة التجارية CDL المطلوبة لتشغيل أي تركيبة من المركبات بتصنيف وزن إجمالي مركّب (GCWR) قدره 26,001 رطل أو أكثر، شريطة أن يكون للمركبة (المركبات) المقطورة تصنيف وزن إجمالي للمركبة GVWR يتجاوز 10,000 رطل؟","options":["الفئة A","الفئة B","الفئة C","الفئة E"],"explanation":"تعرّف ميسوري الفئة A بأنها أي تركيبة من المركبات بتصنيف GCWR قدره 26,001 رطل أو أكثر حيث يتجاوز تصنيف GVWR للوحدة المقطورة 10,000 رطل. المصدر: دليل رخصة القيادة التجارية في ميسوري، القسم 1 (تصنيفات CDL)."},"21":{"q":"بموجب قواعد ميسوري، ما هو الحد الأقصى لتصنيف GVWR لمركبة مقطورة قبل أن تتطلب وحدة قوة مفردة مصنفة بـ 26,001 رطل أو أكثر GVWR رخصة CDL من الفئة A (بدلاً من الفئة B)؟","options":["8,000 رطل","10,000 رطل","15,000 رطل","26,001 رطل"],"explanation":"تغطي رخصة CDL من الفئة B مركبة مفردة بتصنيف GVWR قدره 26,001 رطل أو أكثر تقطر وحدة لا يتجاوز تصنيف GVWR لها 10,000 رطل؛ وإذا تجاوز تصنيف GVWR للوحدة المقطورة 10,000 رطل، فتُطلب الفئة A. المصدر: دليل رخصة القيادة التجارية في ميسوري، القسم 1."},"22":{"q":"وفقاً لدليل CDL في ميسوري، تنطبق رخصة CDL من الفئة C فقط على مركبة دون 26,001 رطل GVWR عندما تكون موسومة بلوحات للمواد الخطرة أو مصممة لنقل كم عدد من الأشخاص؟","options":["9 أشخاص أو أكثر، باستثناء السائق","12 شخصاً أو أكثر، بما في ذلك السائق","15 شخصاً أو أكثر، باستثناء السائق","16 شخصاً أو أكثر، بما في ذلك المُشغّل"],"explanation":"تغطي الفئة C في ميسوري مركبة مفردة دون 26,001 رطل GVWR تكون موسومة بلوحات للمواد الخطرة أو مصممة لنقل 16 شخصاً أو أكثر، بما في ذلك المُشغّل. المصدر: دليل رخصة القيادة التجارية في ميسوري، القسم 1."},"23":{"q":"ما هو الحد الأدنى للعمر للحصول على رخصة CDL في ميسوري للقيادة داخل الولاية فقط (ضمن ميسوري)؟","options":["16 عاماً","18 عاماً","19 عاماً","21 عاماً"],"explanation":"تُدرج أهلية CDL في ميسوري سن 18 للتشغيل داخل الولاية (حتى سن 21) وسن 21 للتشغيل بين الولايات. المصدر: دليل رخصة القيادة التجارية في ميسوري، 'أهلية CDL في ميسوري'."},"24":{"q":"يريد سائق في ميسوري تشغيل مركبة تجارية عبر حدود الولايات (التجارة بين الولايات). ما هو الحد الأدنى للعمر لحمل رخصة CDL للتشغيل بين الولايات؟","options":["18 عاماً","19 عاماً","20 عاماً","21 عاماً"],"explanation":"تتطلب ميسوري أن يكون السائق بعمر 21 للعمل في التجارة بين الولايات؛ ويقتصر حاملو رخصة CDL الذين تتراوح أعمارهم بين 18 و20 عاماً على التشغيل داخل الولاية. المصدر: دليل رخصة القيادة التجارية في ميسوري، 'أهلية CDL في ميسوري'."},"25":{"q":"قبل إجراء اختبار مهارات CDL (الطريق) في ميسوري، يجب أن يكون مقدم الطلب قد حمل تصريح متعلم القيادة التجارية (CLP) لمدة لا تقل عن كم؟","options":["7 أيام","14 يوماً","30 يوماً","60 يوماً"],"explanation":"تتطلب القواعد الفيدرالية وقواعد ميسوري حمل تصريح CLP لمدة لا تقل عن 14 يوماً قبل أن يمكن إجراء اختبار المهارات. المصدر: نظرة عامة على قاعدة تصريح CDL لدى Missouri DOR؛ 49 CFR 383.25."},"26":{"q":"كم مدة صلاحية تصريح متعلم القيادة التجارية (CLP) في ميسوري، وهل يمكن تجديده؟","options":["180 يوماً، قابل للتجديد مرة واحدة","360 يوماً، غير قابل للتجديد","سنة واحدة، قابل للتجديد سنوياً","سنتان، غير قابل للتجديد"],"explanation":"يُصدر تصريح CLP في ميسوري لمدة 360 يوماً وهو غير قابل للتجديد؛ وإذا انتهت صلاحيته، يجب على مقدم الطلب إعادة إجراء اختبارات المعرفة المطلوبة. المصدر: نظرة عامة على قاعدة تصريح CDL لدى Missouri DOR."},"27":{"q":"ما هي المصادقة المطلوبة في ميسوري لقيادة مركبة تجارية مصممة لنقل 16 شخصاً أو أكثر، بما في ذلك السائق؟","options":["مصادقة S (الحافلة المدرسية)","مصادقة P (الركاب)","مصادقة N (الصهريج)","مصادقة T (المقطورات المزدوجة/الثلاثية)"],"explanation":"تُطلب مصادقة P (الركاب) للمركبات المصممة لنقل 16 شخصاً أو أكثر بما في ذلك السائق؛ وتتطلب اختبار معرفة واختبار مهارات في مركبة ركاب. المصدر: دليل رخصة القيادة التجارية في ميسوري، قسم المصادقات."},"28":{"q":"في ميسوري، تُطلب مصادقة مركبة الصهريج (N) لمركبة تنقل سائلاً أو غازاً في صهريج له سعة مصنفة فردية تزيد عن 119 غالوناً وسعة مصنفة إجمالية تبلغ أي مقدار؟","options":["500 غالون أو أكثر","750 غالوناً أو أكثر","1,000 غالون أو أكثر","1,500 غالون أو أكثر"],"explanation":"تنطبق مصادقة N على الصهاريج ذات السعة المصنفة الفردية التي تزيد عن 119 غالوناً والسعة المصنفة الإجمالية البالغة 1,000 غالون أو أكثر. المصدر: دليل رخصة القيادة التجارية في ميسوري، قسم المصادقات؛ 49 CFR 383.5."},"29":{"q":"ما هي المصادقة التي يحتاجها سائقو الفئة A في ميسوري قبل أن يتمكنوا من سحب المقطورات المزدوجة أو الثلاثية؟","options":["مصادقة N (الصهريج)","مصادقة T (المقطورات المزدوجة/الثلاثية)","مصادقة X (التركيبة)","مصادقة H (المواد الخطرة)"],"explanation":"تتطلب مصادقة T (المقطورات المزدوجة/الثلاثية) اجتياز اختبار معرفة خاص؛ وتنطبق على سائقي الفئة A الراغبين في سحب مقطورات متعددة. المصدر: دليل رخصة القيادة التجارية في ميسوري، قسم المصادقات."},"30":{"q":"أي من المصادقات التالية لا يجوز إضافتها إلى تصريح متعلم القيادة التجارية (CLP) في ميسوري؟","options":["P (الركاب)","S (الحافلة المدرسية)","N (الصهريج)","T (المقطورات المزدوجة/الثلاثية)"],"explanation":"المصادقات الوحيدة التي يجوز إضافتها إلى تصريح CLP في ميسوري هي P (الركاب) وS (الحافلة المدرسية) وN (الصهريج). أما H وX وT فمحظورة على تصريح CLP. المصدر: دليل رخصة القيادة التجارية في ميسوري؛ 49 CFR 383.153(b)؛ القسم 302.700 من RSMo."},"31":{"q":"قبل أن يمكن إضافة مصادقة المواد الخطرة (H) إلى رخصة CDL في ميسوري، يجب على مقدم الطلب اجتياز الاختبار الكتابي والحصول على موافقة على ماذا؟","options":["تقييم تهديد أمني من TSA (فحص خلفية)","إعفاء أخصائي بصريات","خطاب رعاية من صاحب عمل في ميسوري","تصريح فحص جانب الطريق من DOT"],"explanation":"بالإضافة إلى اختبار المواد الخطرة الكتابي المكوّن من 30 سؤالاً، يجب على المتقدمين إتمام أخذ البصمات والحصول على موافقة على تقييم التهديد الأمني من TSA قبل إضافة مصادقة H (أو X). المصدر: متطلبات مصادقة المواد الخطرة لدى Missouri DOR؛ 49 CFR 1572."},"32":{"q":"رخصة CDL في ميسوري التي تحمل مصادقة المواد الخطرة (H أو X) ستنتهي صلاحيتها بعد ما لا يزيد عن كم عدد من السنوات من إتمام تقييم التهديد الأمني من TSA؟","options":["سنتان","4 سنوات","5 سنوات","8 سنوات"],"explanation":"نظراً لأن فحص الخلفية من TSA صالح لمدة خمس سنوات، فإن رخصة CDL التي تحمل مصادقة H أو X تنتهي صلاحيتها بعد ما لا يزيد عن 5 سنوات من إتمام تقييم التهديد الأمني. المصدر: مصادقة المواد الخطرة / الأسئلة الشائعة عن HME لدى Missouri DOR؛ 49 CFR 1572."},"33":{"q":"في ميسوري، تتطلب مصادقة الحافلة المدرسية (S) الحصول على أي مصادقة إضافية أيضاً؟","options":["مصادقة N (الصهريج)","مصادقة P (الركاب)","مصادقة H (المواد الخطرة)","مصادقة T (المقطورات المزدوجة/الثلاثية)"],"explanation":"بموجب القواعد الفيدرالية وقواعد ميسوري، تتطلب مصادقة الحافلة المدرسية (S) مصادقة الركاب (P)؛ ويجب على مقدم الطلب اجتياز اختبار معرفة الحافلة المدرسية واختبار مهارات في حافلة مدرسية. المصدر: دليل رخصة القيادة التجارية في ميسوري؛ 49 CFR 383.93."},"34":{"q":"قبل إجراء اختبار مهارات CDL في ميسوري (اعتباراً من 7 فبراير 2022)، يجب على مقدم الطلب إتمام تدريب السائق المبتدئ (ELDT) من مزوّد مدرج في أي مكان؟","options":["قائمة المدارس المعتمدة من دورية الطرق السريعة بولاية ميسوري","سجل مزوّدي التدريب التابع لـ FMCSA","قائمة موردي وزارة الإيرادات في ميسوري","أي مدرسة CDL خاصة يختارها مقدم الطلب"],"explanation":"يجب إتمام تدريب ELDT من خلال مزوّد مدرج في سجل مزوّدي التدريب التابع لـ FMCSA قبل اختبار المهارات لرخصة CDL أولية أو مصادقات معينة. المصدر: صفحة السائقين التجاريين لدى Missouri DOR؛ 49 CFR الجزء 380."},"35":{"q":"عند التصديق الذاتي على الحالة الطبية لرخصة CDL في ميسوري، من كم فئة محتملة يجب على السائق الاختيار؟","options":["فئتان","3 فئات","4 فئات","6 فئات"],"explanation":"يصدّق السائقون ذاتياً على أنفسهم في واحدة من أربع فئات: بين الولايات غير المستثنى، بين الولايات المستثنى، داخل الولاية غير المستثنى، أو داخل الولاية المستثنى. المصدر: دليل رخصة القيادة التجارية في ميسوري، التصديق الطبي الذاتي؛ 49 CFR 383.71."},"36":{"q":"مقدم طلب رخصة CDL في ميسوري الذي يصدّق على نفسه بأنه 'بين الولايات غير المستثنى' يجب عليه أيضاً فعل ماذا؟","options":["تقديم شهادة فاحص طبي سارية (بطاقة طبية DOT) والحفاظ عليها","تقديم إعفاء طبي خاص بميسوري داخل الولاية فقط","عدم تقديم أي شيء آخر؛ التصديق وحده كافٍ","الحصول على فحص بصر سنوي من أخصائي بصريات في ميسوري"],"explanation":"السائق الذي يصدّق ذاتياً على أنه بين الولايات غير المستثنى يخضع للمعايير الطبية الفيدرالية ويجب عليه تقديم شهادة فاحص طبي سارية والحفاظ على سريانها، وإلا فقد يتعرض لتخفيض الرخصة. المصدر: دليل رخصة القيادة التجارية في ميسوري، التصديق الذاتي؛ 49 CFR 391.41."},"37":{"q":"لإثبات الإقامة في ميسوري عند التقدم للحصول على رخصة CDL، كم عدد المستندات التي تتحقق من عنوان إقامة مقدم الطلب المطلوبة؟","options":["مستند واحد","مستندان","ثلاثة مستندات","لا توجد مستندات إذا كانت هناك رخصة سابقة"],"explanation":"تتطلب ميسوري مستندين مقبولين يثبتان الإقامة/السكن في ميسوري، بالإضافة إلى إثبات الهوية ورقم الضمان الاجتماعي والوجود القانوني. المصدر: صفحة السائقين التجاريين لدى Missouri DOR؛ دليل CDL في ميسوري، الأهلية."},"38":{"q":"أي حالة وجود قانوني تتطلبها ميسوري من مقدم طلب رخصة CDL؟","options":["أي حامل تأشيرة سارية بغض النظر عن الحالة","مواطن أمريكي أو مقيم دائم قانوني","مواطن أمريكي فقط","أي مقدم طلب لديه رقم ضمان اجتماعي"],"explanation":"تتطلب ميسوري أن يكون مقدمو طلب CDL مواطنين أمريكيين أو غير أمريكيين يتمتعون بحالة الإقامة الدائمة القانونية. المصدر: صفحة السائقين التجاريين لدى Missouri DOR؛ دليل CDL في ميسوري، الأهلية."},"39":{"q":"ما هو الحد الأدنى لدرجة النجاح في كل اختبار معرفة (كتابي) لرخصة CDL في ميسوري؟","options":["70%","75%","80%","85%"],"explanation":"تتطلب ميسوري درجة 80% في كل اختبار كتابي لرخصة CDL، يُجرى في مواقع اختبار دورية الطرق السريعة (على سبيل المثال، المعرفة العامة المكوّنة من 50 سؤالاً، والمواد الخطرة المكوّنة من 30 سؤالاً، واختبارات المصادقة المكوّنة من 20 سؤالاً). المصدر: دليل رخصة القيادة التجارية في ميسوري، القسم 14 (اختبارات CDL الكتابية)."},"40":{"q":"في ميسوري، ما هو الحد الأقصى لتركيز الكحول في الدم (BAC) الذي يجوز أن يكون لدى السائق أثناء تشغيل مركبة آلية تجارية (CMV) قبل أن يُعتبر مخالفة كبرى؟","options":["0.04%","0.08%","0.02%","0.10%"],"explanation":"تحظر ميسوري تشغيل مركبة CMV بتركيز BAC قدره 0.04% أو أعلى (نصف الحد البالغ 0.08% للسائقين غير التجاريين). المصدر: نموذج Missouri DOR 5231، 'مشغّلو المركبات الآلية التجارية والقانون'؛ 49 CFR 383.51."},"41":{"q":"بموجب قانون الموافقة الضمنية في ميسوري، ماذا يحدث إذا رفض حامل رخصة CDL الخضوع لاختبار كيميائي (دم/نفس) عند الطلب القانوني؟","options":["تُسحب أهلية رخصة CDL لمدة سنة واحدة، مثل القيادة تحت تأثير الكحول DWI الأولى تماماً","غرامة قدرها 500 دولار فقط دون سحب الأهلية","سحب أهلية CDL لمدة 60 يوماً","لا توجد عقوبة لأن الرفض لا يمكن استخدامه كدليل"],"explanation":"يُعامل رفض اختبار الدم و/أو النفس كحامل لرخصة CDL أو أثناء تشغيل مركبة CMV كمخالفة كبرى وينتج عنه سحب أهلية CDL لمدة سنة واحدة، مثل إدانة DWI الأولى تماماً. المصدر: نموذج Missouri DOR 5231؛ قانون الموافقة الضمنية في ميسوري (الفصل 577 من RSMo)؛ 49 CFR 383.51."},"42":{"q":"كم مدة سحب أهلية رخصة CDL لمخالفة كبرى أولى (مثل DWI في مركبة CMV) عند عدم نقل مواد خطرة؟","options":["سنة واحدة","3 سنوات","60 يوماً","مدى الحياة"],"explanation":"تؤدي المخالفة الكبرى الأولى، بما في ذلك القيادة تحت التأثير أو رفض اختبار أو مغادرة مكان الحادث، إلى سحب أهلية CDL لمدة سنة واحدة في ميسوري. المصدر: نموذج Missouri DOR 5231؛ 49 CFR 383.51."},"43":{"q":"يرتكب سائق مخالفة كبرى أولى أثناء تشغيل مركبة موسومة بلوحات للمواد الخطرة. ما هي مدة سحب الأهلية؟","options":["3 سنوات","سنة واحدة","5 سنوات","مدى الحياة"],"explanation":"تحمل المخالفة الكبرى الأولى المرتكبة أثناء نقل مواد خطرة موسومة بلوحات سحب أهلية CDL لمدة 3 سنوات، بدلاً من السنة الواحدة المعتادة. المصدر: نموذج Missouri DOR 5231؛ 49 CFR 383.51."},"44":{"q":"ما هي عاقبة مخالفة كبرى ثانية (على سبيل المثال، DWI ثانية) على رخصة CDL في ميسوري؟","options":["سحب الأهلية مدى الحياة","سحب الأهلية لمدة 3 سنوات","سحب الأهلية لمدة 10 سنوات","سحب الأهلية لمدة سنة واحدة"],"explanation":"تؤدي الإدانة الثانية بأي من المخالفات الكبرى المدرجة إلى سحب أهلية CDL مدى الحياة في ميسوري (قد يكون بعض السائقين مؤهلين لإعادة الترخيص بعد 10 سنوات بموجب الإرشادات الفيدرالية). المصدر: نموذج Missouri DOR 5231؛ 49 CFR 383.51."},"45":{"q":"كم عدد مخالفات المرور الخطيرة خلال فترة 3 سنوات التي تؤدي إلى سحب أهلية CDL لمدة 60 يوماً؟","options":["2","3","4","1"],"explanation":"تؤدي إدانتان بمخالفات مرور خطيرة خلال ثلاث سنوات (في مركبة CMV) إلى سحب أهلية CDL لمدة 60 يوماً. المصدر: نموذج Missouri DOR 5231؛ 49 CFR 383.51."},"46":{"q":"كم عدد مخالفات المرور الخطيرة خلال 3 سنوات التي تؤدي إلى سحب أهلية CDL لمدة 120 يوماً؟","options":["3 أو أكثر","2","5 أو أكثر","4 أو أكثر"],"explanation":"تؤدي ثلاث إدانات أو أكثر بمخالفات مرور خطيرة خلال ثلاث سنوات إلى سحب أهلية CDL لمدة 120 يوماً. المصدر: نموذج Missouri DOR 5231؛ 49 CFR 383.51."},"47":{"q":"أي مما يلي يُصنَّف على أنه 'مخالفة مرور خطيرة' لحامل رخصة CDL في ميسوري؟","options":["تجاوز السرعة بمقدار 15 ميلاً في الساعة أو أكثر فوق الحد المنشور","تجاوز السرعة بمقدار 5 أميال في الساعة فوق الحد المنشور","مخالفة وقوف","مخالفة إضاءة في المعدات"],"explanation":"تشمل مخالفات المرور الخطيرة تجاوز السرعة بمقدار 15 ميلاً في الساعة أو أكثر فوق الحد، والقيادة المتهورة، وتغيير الحارة بشكل غير سليم أو غير منتظم، والاقتراب الشديد. أما تجاوز السرعة البسيط ومخالفات الوقوف فليست 'خطيرة'. المصدر: نموذج Missouri DOR 5231؛ 49 CFR 383.51."},"48":{"q":"ما هي مدة سحب الأهلية لأول مخالفة للسائق عند تقاطع السكة الحديدية مع الطريق السريع؟","options":["60 يوماً","30 يوماً","120 يوماً","سنة واحدة"],"explanation":"تؤدي أول مخالفة عند تقاطع السكة الحديدية مع الطريق السريع إلى سحب أهلية CDL لمدة 60 يوماً كحد أدنى. المصدر: نموذج Missouri DOR 5231؛ 49 CFR 383.51."},"49":{"q":"يرتكب حامل رخصة CDL مخالفة ثانية عند تقاطع السكة الحديدية مع الطريق السريع خلال 3 سنوات. ما هي مدة سحب الأهلية؟","options":["120 يوماً","60 يوماً","سنة واحدة","180 يوماً"],"explanation":"تؤدي مخالفة ثانية عند تقاطع السكة الحديدية مع الطريق السريع خلال ثلاث سنوات إلى سحب أهلية لمدة 120 يوماً كحد أدنى. المصدر: نموذج Missouri DOR 5231؛ 49 CFR 383.51."},"50":{"q":"ما هي مدة سحب الأهلية لمخالفة ثالثة عند تقاطع السكة الحديدية مع الطريق السريع خلال فترة 3 سنوات؟","options":["سنة واحدة","120 يوماً","180 يوماً","60 يوماً"],"explanation":"تؤدي مخالفة ثالثة أو لاحقة عند تقاطع السكة الحديدية مع الطريق السريع خلال ثلاث سنوات إلى سحب أهلية لمدة سنة واحدة كحد أدنى. المصدر: نموذج Missouri DOR 5231؛ 49 CFR 383.51."},"51":{"q":"إلى جانب سحب الأهلية، ما هو نطاق العقوبة المدنية الذي قد يواجهه السائق لانتهاك أمر إيقاف عن الخدمة؟","options":["1,000 دولار إلى 2,500 دولار","100 دولار إلى 500 دولار","250 دولاراً إلى 750 دولاراً","5,000 دولار إلى 10,000 دولار"],"explanation":"يخضع السائق الذي ينتهك أمر إيقاف عن الخدمة لعقوبة مدنية لا تقل عن 1,000 دولار ولا تزيد عن 2,500 دولار، بالإضافة إلى سحب الأهلية. المصدر: 49 CFR 383.53؛ نموذج Missouri DOR 5231."},"52":{"q":"بموجب RSMo 304.822، ما هي الغرامة لأول انتهاك لحظر استخدام الهاتف دون اليدين / الرسائل النصية؟","options":["150 دولاراً","50 دولاراً","250 دولاراً","500 دولار"],"explanation":"بموجب قانون Siddens Bening لاستخدام الهاتف دون استعمال اليدين في ميسوري، تبلغ الغرامة 150 دولاراً للانتهاك الأول، و250 دولاراً للثاني، و500 دولار للثالث خلال فترة محددة. المصدر: القسم 304.822 من RSMo."},"53":{"q":"يُدان حامل رخصة CDL باستخدام مركبة CMV لارتكاب جناية تتعلق بتصنيع أو توزيع مادة خاضعة للرقابة. ما هو سحب الأهلية؟","options":["سحب الأهلية مدى الحياة دون إعادة ترخيص","سحب الأهلية لمدة سنة واحدة","سحب الأهلية لمدة 3 سنوات","سحب الأهلية لمدة 10 سنوات"],"explanation":"يؤدي استخدام مركبة CMV في ارتكاب جناية تتعلق بتصنيع أو توزيع أو صرف مادة خاضعة للرقابة إلى سحب الأهلية مدى الحياة دون إمكانية إعادة الترخيص. المصدر: نموذج Missouri DOR 5231؛ 49 CFR 383.51."},"54":{"q":"أي مما يلي يُعد مخالفة كبرى تؤدي إلى سحب أهلية CDL لمدة سنة واحدة عند أول إدانة؟","options":["مغادرة مكان حادث يتعلق بمركبة CMV","الاقتراب الشديد","تغيير حارة غير سليم","تجاوز السرعة بمقدار 15 ميلاً في الساعة فوق الحد"],"explanation":"تُعد مغادرة مكان حادث يتعلق بمركبة CMV مخالفة كبرى (سحب أهلية لمدة سنة واحدة للمخالفة الأولى). أما الاقتراب الشديد وتغيير الحارة غير السليم وتجاوز السرعة بمقدار 15 ميلاً في الساعة أو أكثر فهي مخالفات 'خطيرة'، وليست مخالفات كبرى. المصدر: نموذج Missouri DOR 5231؛ 49 CFR 383.51."},"55":{"q":"يتسبب سائق في وفاة من خلال التشغيل المهمل لمركبة CMV (على سبيل المثال، القتل غير العمد بالمركبة). كيف يُصنَّف هذا لأغراض رخصة CDL؟","options":["مخالفة كبرى تحمل سحب أهلية لمدة سنة واحدة للمخالفة الأولى","مخالفة مرور خطيرة تحمل 60 يوماً","مخالفة عند تقاطع السكة الحديدية تحمل 120 يوماً","مخالفة إيقاف عن الخدمة تحمل 90 يوماً"],"explanation":"يُعد التسبب في وفاة من خلال التشغيل المهمل أو الإجرامي لمركبة CMV مخالفة كبرى، مما يؤدي إلى سحب أهلية لمدة سنة واحدة عند أول إدانة (3 سنوات إذا كانت موسومة بلوحات المواد الخطرة؛ مدى الحياة عند مخالفة كبرى ثانية). المصدر: نموذج Missouri DOR 5231؛ 49 CFR 383.51."},"56":{"q":"على طريق سريع بين الولايات أو طريق حر ريفي في ميزوري، ما هو الحد الأقصى لسرعة القيادة المعلن الذي ينطبق على المركبة التجارية الآلية (الشاحنة) حيث لا يوجد حد أدنى معلن؟","options":["70 mph","65 mph","60 mph","55 mph"],"explanation":"تحدد ميزوري السرعة القصوى على الطرق السريعة بين الولايات والطرق الحرة الريفية بـ 70 mph، ولا يوجد حد سرعة منفصل وأدنى للشاحنات على مستوى الولاية، لذا يجوز للشاحنات السير بنفس السرعة 70 mph ما لم تكن هناك سرعة أدنى معلنة. المصدر: RSMo 304.010."},"57":{"q":"بموجب قانون ميزوري، على أي الطرق يُمنع على الشاحنات المسجلة بوزن إجمالي يزيد عن 48,000 رطل القيادة في أقصى المسار الأيسر؟","options":["أي طريق سريع للولاية ذي مسارين بحد معلن قدره 55 mph أو أعلى","جميع الطرق السريعة بين الولايات الريفية ذات مسارين أو أكثر في كل اتجاه","أي طريق سريع مقسوم في أي مكان داخل الولاية بغض النظر عن عدد المسارات","الطرق السريعة بين الولايات أو الطرق الحرة أو الطرق السريعة داخل المناطق الحضرية التي تحتوي على ثلاثة مسارات أو أكثر في الاتجاه نفسه"],"explanation":"تمنع ميزوري الشاحنات المسجلة بوزن إجمالي يزيد عن 48,000 رطل من أقصى المسار الأيسر على الطرق السريعة بين الولايات أو الطرق الحرة أو الطرق السريعة داخل المناطق الحضرية التي تحتوي على ثلاثة مسارات أو أكثر تسير في الاتجاه نفسه. المصدر: RSMo 304.015."},"58":{"q":"في ميزوري، على طريق سريع به مساران أو أكثر من حركة المرور تسير في الاتجاه نفسه، أين يجب أن تُقاد المركبة بشكل عام؟","options":["في أي مسار يكون به أقل حركة مرور في ذلك الوقت","في المسار الأيمن، باستثناء عند التجاوز أو الاستعداد للانعطاف يساراً أو التوجيه بخلاف ذلك عبر اللافتات/العلامات","في المسار الأيسر لإبقاء المسار الأيمن خالياً لحركة المرور الداخلة","في المسار الأوسط على أي طريق به ثلاثة مسارات في الاتجاه نفسه"],"explanation":"تشترط ميزوري قيادة جميع المركبات في المسار الأيمن على الطرق السريعة ذات مسارين أو أكثر في الاتجاه نفسه، باستثناء عند اللحاق والتجاوز أو الاستعداد لانعطاف صحيح إلى اليسار أو التوجيه بخلاف ذلك عبر علامات المرور أو اللافتات أو الإشارات. المصدر: RSMo 304.015."},"59":{"q":"يجب على الحافلة أو المركبة المحملة بمواد خطرة والمزودة بلوحات تحذيرية والمقتربة من معبر سكة حديد في ميزوري أن تتوقف على أي مسافة من أقرب قضيب؟","options":["ضمن 100 feet ولكن ليس أقل من 25 feet","ضمن 75 feet ولكن ليس أقل من 10 feet","ضمن 50 feet ولكن ليس أقل من 15 feet","ضمن 25 feet ولكن ليس أقل من 5 feet"],"explanation":"يجب على الحافلات ومركبات HazMat المزودة بلوحات تحذيرية أن تتوقف ضمن 50 feet ولكن ليس أقل من 15 feet من أقرب قضيب، ثم تنظر وتستمع قبل العبور. المصدر: دليل CDL لميزوري؛ 49 CFR 392.10."},"60":{"q":"على طريق سريع في ميزوري، ماذا يجب على سائق المركبة الذي يقابل أو يلحق بحافلة مدرسية متوقفة تعرض إشارتها للتوقف أن يفعل؟","options":["إيقاف المركبة قبل الوصول إلى الحافلة، سواء كان متجهاً نحو الحافلة أو خلفها","التوقف فقط إذا كان يسير في الاتجاه نفسه للحافلة","الإبطاء إلى 10 mph والتجاوز بحذر دون توقف","التوقف فقط إذا كان الأطفال ظاهرين بوضوح على جانب الطريق"],"explanation":"تشترط ميزوري على السائق الذي يقابل أو يلحق بحافلة مدرسية من أي اتجاه وهي متوقفة وتشير للتوقف أن يوقف المركبة قبل الوصول إلى الحافلة. والاستثناء يكون للطرق المنفصلة أو حركة المرور المقابلة على الطرق السريعة ذات أربعة مسارات أو أكثر. المصدر: RSMo 304.050."},"61":{"q":"ما هو الاستثناء في ميزوري الذي يتيح للسائق ألا يتوقف لحافلة مدرسية تُحمّل أو تُنزّل الأطفال؟","options":["السائق يسير بسرعة أقل من 25 mph في ذلك الوقت","الحافلة تومض أضواؤها الكهرمانية (الصفراء) ولكن ليس أضواؤها الحمراء","السائق يبعد أكثر من 100 feet عن الحافلة عندما تتوقف","الحافلة على طريق مختلف، أو تسير في الاتجاه المعاكس على طريق سريع به أربعة مسارات أو أكثر من حركة المرور"],"explanation":"السائق على طريق سريع به طرق منفصلة لا يحتاج إلى التوقف لحافلة مدرسية على طريق مختلف، أو لحافلة تسير في الاتجاه المعاكس على طريق سريع يحتوي على أربعة مسارات أو أكثر من حركة المرور. المصدر: RSMo 304.050."},"62":{"q":"بموجب قانون \"التحرك جانباً\" (Move Over) في ميزوري، عندما يقترب السائق من مركبة طوارئ أو قطر أو مرافق أو مركبة تابعة لـ MoDOT متوقفة وتعرض أضواء تحذيرية على طريق به أربعة مسارات على الأقل (اثنان أو أكثر في الاتجاه نفسه)، ماذا يجب على السائق أن يفعل أولاً؟","options":["التوقف توقفاً تاماً حتى تغادر المركبة المتوقفة","تغيير المسار إلى مسار غير ملاصق للمركبة المتوقفة، إذا أمكن القيام بذلك بأمان","إطلاق البوق باستمرار أثناء تجاوز المركبة المتوقفة","الانعطاف إلى الكتف الأيمن والانتظار حتى إشارة خلو الطريق"],"explanation":"يشترط قانون \"التحرك جانباً\" في ميزوري على السائق، حيث يكون للطريق أربعة مسارات على الأقل مع اثنين أو أكثر في الاتجاه نفسه، أن يتحول إلى مسار غير ملاصق للمركبة المتوقفة عندما يمكن القيام بذلك بأمان. المصدر: RSMo 304.022."},"63":{"q":"بموجب قانون \"التحرك جانباً\" في ميزوري، إذا كان تغيير المسارات بعيداً عن مركبة طوارئ/مرافق متوقفة غير آمن أو غير ممكن، فماذا يجب على السائق أن يفعل بدلاً من ذلك؟","options":["التوقف توقفاً تاماً في المسار الحالي حتى تخلو حركة المرور","الحفاظ على حد السرعة المعلن والاستمرار في السير مستقيماً","المضي بالحذر الواجب وتخفيض السرعة، مع الحفاظ على سرعة آمنة لظروف الطريق","تشغيل أضواء الخطر الوامضة والتسارع بسرعة لتجاوز الموقع"],"explanation":"عندما لا يمكن تغيير المسار بأمان، تشترط ميزوري على السائق المضي بالحذر الواجب وتخفيض سرعة المركبة، مع الحفاظ على سرعة آمنة لظروف الطريق. المصدر: RSMo 304.022."},"64":{"q":"يجب على السائق التجاري في ميزوري أن يحمل أجهزة تحذيرية للاستخدام عند التوقف على الطريق السريع. مما يتكون المتطلب القياسي؟","options":["ثلاثة مثلثات عاكسة","مثلثان عاكسان وثلاث شعلات","أربعة مثلثات عاكسة","مثلث عاكس واحد وعَلَمان"],"explanation":"يجب أن تكون المركبة التجارية الآلية مجهزة بثلاثة مثلثات عاكسة (أو ما يعادلها المعتمد) لنشرها عند التوقف على الطريق أو بجانبه. المصدر: دليل CDL لميزوري؛ 49 CFR 393.95 / 392.22."},"65":{"q":"عندما تتوقف مركبة تجارية في ميزوري على طريق مقسوم أو طريق باتجاه واحد، أين يجب وضع مثلثات التحذير الثلاثة؟","options":["الثلاثة جميعها على بُعد 10 feet خلف المركبة مباشرة","واحد على بُعد 10 feet خلفها، وواحد على بُعد 100 feet خلفها، وواحد على بُعد 100 feet أمامها","نحو 25 و 50 و 100 feet خلف المركبة","نحو 10 و 100 و 200 feet خلف المركبة، باتجاه حركة المرور المقتربة"],"explanation":"على طريق مقسوم أو باتجاه واحد، تُوضع المثلثات الثلاثة جميعها باتجاه حركة المرور المقتربة على بُعد نحو 10 feet و 100 feet و 200 feet خلف المركبة التجارية الآلية المتوقفة. المصدر: دليل CDL لميزوري؛ 49 CFR 392.22."},"66":{"q":"عندما تتوقف مركبة تجارية في ميزوري على طريق غير مقسوم ذي مسارين باتجاهين، أين يجب وضع مثلثات التحذير؟","options":["واحد على بُعد نحو 10 feet خلفها، وواحد على بُعد نحو 200 feet خلفها، وواحد على بُعد نحو 200 feet أمامها","واحد على بُعد نحو 10 feet خلفها، وواحد على بُعد نحو 100 feet خلفها، وواحد على بُعد نحو 100 feet أمام المركبة","الثلاثة جميعها خلف المركبة على بُعد 10 و 100 و 200 feet","واحد على كل جانب من المركبة وواحد خلفها مباشرة"],"explanation":"على طريق ذي مسارين باتجاهين، يضع السائق مثلثاً واحداً ضمن 10 feet من المؤخرة، وواحداً على بُعد نحو 100 feet خلفها، وواحداً على بُعد نحو 100 feet أمام المركبة. المصدر: دليل CDL لميزوري؛ 49 CFR 392.22."},"67":{"q":"على طريق سريع ريفي في ميزوري (ليس طريقاً سريعاً بين الولايات ولا طريقاً حراً)، ما هو الحد الأقصى لسرعة القيادة؟","options":["70 mph","60 mph","65 mph","55 mph"],"explanation":"تحدد ميزوري السرعة القصوى على الطرق السريعة الريفية بـ 65 mph، وهي أقل من 70 mph المسموح بها على الطرق السريعة بين الولايات والطرق الحرة الريفية. المصدر: RSMo 304.010."},"68":{"q":"ما هو الحد الأقصى لسرعة القيادة على طريق سريع بين الولايات أو طريق حر أو طريق سريع يقع داخل منطقة حضرية في ميزوري؟","options":["60 mph","65 mph","70 mph","55 mph"],"explanation":"داخل المناطق الحضرية، تحدد ميزوري سقف الطرق السريعة بين الولايات والطرق الحرة والطرق السريعة عند 60 mph ما لم يكن هناك حد أدنى معلن. المصدر: RSMo 304.010."},"69":{"q":"أي معبر سكة حديد لا يتطلب من حافلة أو مركبة تجارية محملة بـ HazMat ومزودة بلوحات تحذيرية في ميزوري القيام بالتوقف الإلزامي؟","options":["أي معبر في منطقة ريفية بلا أضواء وامضة","أي معبر به علامة تقاطع (crossbuck) ولكن بلا بوابة","أي معبر على طريق معلن بأقل من 45 mph","معبر ترام أو مسار مناورة صناعي داخل منطقة تجارية، أو معبر معلَّم بلافتة 'Exempt' (معفى)"],"explanation":"لا ينطبق التوقف الإلزامي عند معابر الترام أو مسارات المناورة الصناعية داخل منطقة تجارية، أو المعابر المهجورة المعلَّمة بذلك، أو المعابر المعلَّمة بلافتة 'Exempt' (معفى) معتمدة. المصدر: دليل CDL لميزوري؛ 49 CFR 392.10."},"70":{"q":"ما هو الحد الأقصى القانوني لعرض المركبة، بما في ذلك الحمولة، على الطرق السريعة في ميزوري قبل أن يُطلب تصريح للحجم الزائد؟","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"explanation":"تحدد ميزوري عرض المركبة، بما في ذلك الحمولة، بـ 102 inches (8 feet 6 inches)؛ وتجاوز ذلك يتطلب تصريحاً للحجم الزائد. المصدر: RSMo 304.170؛ خدمات الناقلات الآلية لدى MoDOT."},"71":{"q":"ما هو الحد الأقصى القانوني لارتفاع المركبة، بما في ذلك الحمولة، على شبكة الطرق السريعة بين الولايات في ميزوري قبل أن يُطلب تصريح للحجم الزائد؟","options":["13 feet 6 inches","15 feet","14 feet","16 feet"],"explanation":"تحدد ميزوري الارتفاع، بما في ذلك الحمولة، بـ 14 feet على شبكة الطرق السريعة بين الولايات (15 feet على بعض الطرق الأخرى)؛ وما يزيد عن ذلك يتطلب تصريحاً. المصدر: RSMo 304.170؛ MoDOT."},"72":{"q":"في غياب تصريح للوزن الزائد، ما هو الحد الأقصى للوزن الإجمالي للمركبة المسموح به عموماً على الطرق السريعة بين الولايات في ميزوري؟","options":["80,000 pounds","73,280 pounds","88,000 pounds","90,000 pounds"],"explanation":"تتبع ميزوري الحد الفيدرالي البالغ 80,000 pounds كحد أقصى للوزن الإجمالي على شبكة الطرق بين الولايات دون تصريح للوزن الزائد. المصدر: لوائح الحجم/الوزن الزائد لدى MoDOT؛ RSMo الفصل 304."},"73":{"q":"متى يجوز عموماً نقل حمولة ذات حجم زائد على الطرق السريعة في ميزوري بموجب تصريح رحلة واحدة قياسي؟","options":["فقط بين منتصف الليل والساعة 6:00 a.m.","في أي ساعة من النهار أو الليل دون قيود","فقط في عطلات نهاية الأسبوع والعطلات الرسمية للولاية","من نصف ساعة قبل شروق الشمس إلى نصف ساعة بعد غروبها"],"explanation":"تقصر MoDOT عموماً حركة الحمولات ذات الحجم الزائد على الفترة من نصف ساعة قبل شروق الشمس إلى نصف ساعة بعد غروبها، مع قيود إضافية في أيام العطل وعطلات نهاية الأسبوع. المصدر: لوائح تصاريح الحجم/الوزن الزائد لدى MoDOT."},"74":{"q":"ما هو الحد الأقصى لطول نصف المقطورة (semitrailer) المُشغَّلة على الطرق السريعة في ميزوري دون تصريح؟","options":["48 feet","53 feet","57 feet","60 feet"],"explanation":"تحدد ميزوري طول نصف المقطورة بـ 53 feet على شبكة الطرق السريعة قبل أن يُطلب تصريح. المصدر: RSMo 304.170."},"75":{"q":"يُشترط أن تكون الحافلة المدرسية في ميزوري مرئية بوضوح للسائقين المقتربين على أي مسافة على طريق سريع بلا كتف وبحد سرعة يزيد عن 60 mph، حتى تتمكن حركة المرور من التوقف؟","options":["300 feet على الأقل في كل اتجاه","200 feet على الأقل في كل اتجاه","500 feet على الأقل في كل اتجاه","1,000 feet على الأقل في كل اتجاه"],"explanation":"على طريق سريع بلا كتف وبحد سرعة يزيد عن 60 mph، يجب أن تكون الحافلة المدرسية المتوقفة مرئية بوضوح لمسافة 500 feet على الأقل في كل اتجاه (300 feet على الطرق السريعة الأخرى). المصدر: RSMo 304.050."},"76":{"q":"أي جهة في ميزوري تُصدر فعلياً وثيقة رخصة القيادة التجارية (CDL)؟","options":["دائرة الإيرادات في ميزوري (Missouri DOR)","دورية الطرق السريعة لولاية ميزوري","دائرة النقل في ميزوري (MoDOT)","الإدارة الفيدرالية لسلامة الناقلات الآلية (FMCSA)"],"explanation":"في ميزوري، تُصدر دائرة الإيرادات (DOR) جميع رخص القيادة، بما في ذلك CDL، بينما تتولى دورية الطرق السريعة لولاية ميزوري إجراء الاختبارات. المصدر: صفحة السائقين التجاريين لدى Missouri DOR (dor.mo.gov/driver-license/issuance/commercial/)."},"77":{"q":"في ميزوري، من الذي يتولى إجراء اختبارات المعرفة (التحريرية) ومهارات CDL؟","options":["دورية الطرق السريعة لولاية ميزوري","مكاتب الرخص التابعة لدائرة الإيرادات في ميزوري","مزودو التدريب الخاصون المسجلون لدى FMCSA","دائرة النقل في ميزوري"],"explanation":"تجري دورية الطرق السريعة لولاية ميزوري اختبار المعرفة التحريري لـ CDL في محطات فحص السائقين التابعة لها واختبار المهارات (بموعد) في مواقع اختبار CDL المخصصة؛ ثم تُصدر DOR الرخصة. المصدر: صفحة السائقين التجاريين لدى Missouri DOR ودليل CDL لميزوري."},"78":{"q":"لكم من الوقت يكون تصريح المتعلم التجاري (CLP) في ميزوري صالحاً، وهل يمكن تجديده؟","options":["360 days، وهو غير قابل للتجديد","180 days، ويمكن تجديده مرة واحدة","1 year، ويمكن تجديده لسنة ثانية","2 years، بما يطابق الحد الأقصى الفيدرالي"],"explanation":"تُصدر ميزوري CLP لمدة 360 days وهو غير قابل للتجديد؛ وإذا انتهت صلاحيته، يجب على المتقدم إكمال جميع اختبارات المعرفة المطلوبة من جديد. المصدر: نظرة عامة على قاعدة تصريح CDL لدى Missouri DOR (dor.mo.gov/driver-license/issuance/commercial/cdl-permit.html)."},"79":{"q":"لكم من الوقت يجب على المتقدم في ميزوري أن يحمل تصريح المتعلم التجاري قبل أن يكون مؤهلاً لإجراء اختبار مهارات CDL؟","options":["14 days على الأقل","30 days على الأقل","10 days على الأقل","60 days على الأقل"],"explanation":"يجب على المتقدمين للحصول على CDL أن يحملوا CLP لمدة 14 days على الأقل قبل إكمال اختبار المهارات للحصول على CDL كامل. المصدر: نظرة عامة على قاعدة تصريح CDL لدى Missouri DOR والقاعدة الفيدرالية لـ CLP (49 CFR 383.25)."},"80":{"q":"أي تدريب يجب على المتقدم في ميزوري إكماله قبل إجراء اختبار المهارات للحصول على CDL من الفئة A أو الفئة B لأول مرة؟","options":["تدريب السائق المبتدئ (ELDT) من مزود مدرج في سجل مزودي التدريب لدى FMCSA","دورة قيادة دفاعية معتمدة من الولاية في مكتب DOR","ندوة سلامة صفّية تابعة لدورية الطرق السريعة لولاية ميزوري","توجيه عملي يديره صاحب العمل فقط"],"explanation":"قبل اختبار مهارات CDL (ولبعض المصادقات الجديدة)، يجب على المتقدمين في ميزوري إكمال تدريب السائق المبتدئ (ELDT) من مزود مدرج في سجل مزودي التدريب لدى FMCSA، وهو نافذ منذ 7 فبراير 2022. المصدر: صفحة السائقين التجاريين لدى Missouri DOR؛ قاعدة ELDT لدى FMCSA (49 CFR Part 380)."},"81":{"q":"يتكون اختبار مهارات CDL في ميزوري من أي ثلاثة أجزاء، بالترتيب؟","options":["فحص المركبة (قبل الرحلة)، والتحكم الأساسي بالمركبة، والقيادة على الطريق","المعرفة التحريرية، وفحص فرامل الهواء، والقيادة على الطريق","التحكم الأساسي بالمركبة، وفحص المواد الخطرة، والقيادة على الطريق","فحص المركبة، وإعادة اختبار المعرفة، وتقييم القيادة الدفاعية"],"explanation":"يتكون اختبار مهارات CDL المُحدَّث في ميزوري من ثلاثة مكونات: فحص المركبة (قبل الرحلة)، واختبار مهارات التحكم الأساسي بالمركبة، واختبار القيادة على الطريق. المصدر: دليل CDL لميزوري وصفحة السائقين التجاريين لدى Missouri DOR."},"82":{"q":"ما هي فئات التصديق الذاتي الأربع التي يجب على المتقدم لـ CDL في ميزوري الاختيار من بينها؟","options":["بين الولايات غير المعفاة، وبين الولايات المعفاة، وداخل الولاية غير المعفاة، وداخل الولاية المعفاة","بين الولايات، وداخل الولاية، وإقليمية، ومحلية","تجارية، وزراعية، وطوارئ، وحكومية","الفئة A، والفئة B، والفئة C، والمواد الخطرة"],"explanation":"يجب على المتقدمين لـ CDL في ميزوري التصديق الذاتي على إحدى أربع فئات: بين الولايات غير المعفاة (NI)، وبين الولايات المعفاة (EI)، وداخل الولاية غير المعفاة (NA)، وداخل الولاية المعفاة (EA). المصدر: صفحة متطلبات التصديق الطبي لـ CDL لدى Missouri DOR."},"83":{"q":"أي فئة من فئات التصديق الذاتي في ميزوري تتطلب أن يكون السائق مؤهلاً بموجب 49 CFR Part 391 وأن يحمل شهادة فاحص طبي تابعة لـ DOT؟","options":["بين الولايات غير المعفاة (NI)","بين الولايات المعفاة (EI)","داخل الولاية المعفاة (EA)","طوارئ بين الولايات المعفاة (EE)"],"explanation":"السائق ضمن فئة بين الولايات غير المعفاة (NI) يعمل في التجارة بين الولايات، ويخضع لـ 49 CFR Part 391، ويجب أن يحصل على شهادة فاحص طبي تابعة لـ DOT ويحافظ عليها. والفئات المعفاة لا تخضع لمتطلب الشهادة الطبية الفيدرالي ذاك. المصدر: صفحة التصديق الطبي لـ CDL لدى Missouri DOR."},"84":{"q":"كيف تصل معلومات شهادة الفاحص الطبي عموماً إلى دائرة الإيرادات في ميزوري لسجل حامل CDL؟","options":["تُنقل إلكترونياً من السجل الوطني للفاحصين الطبيين المعتمدين","يجب على السائق دائماً إرسال البطاقة الورقية الأصلية بالبريد إلى MoDOT","يقدمها صاحب عمل السائق إلى دورية الطرق السريعة","تُحمّل فقط عبر مورّد HAZMAT من طرف ثالث"],"explanation":"تتلقى ميزوري معلومات شهادة الفاحص الطبي المنقولة إلكترونياً من السجل الوطني للفاحصين الطبيين المعتمدين، لذا يجب على السائقين استخدام فاحص معتمد مدرج في ذلك السجل. المصدر: صفحة متطلبات التصديق الطبي لـ CDL لدى Missouri DOR."},"85":{"q":"ماذا يحدث لسائق CDL غير معفى في ميزوري لا يحافظ على وجود شهادة فاحص طبي حالية في ملفه؟","options":["يُخفَّض تصنيف CDL وتُفقد امتيازات القيادة التجارية","يُعلَّق CDL لمدة 24 hours بالضبط، ثم يُعاد","لا شيء، لأن ميزوري لا تتعقب الحالة الطبية","يُنقل السائق تلقائياً إلى فئة داخل الولاية المعفاة"],"explanation":"السائق غير المعفى الذي يترك التصديق الطبي ينتهي يُخفَّض تصنيفه، فيفقد امتيازات CDL إلى أن تتوافر شهادة حالية في الملف. المصدر: أسئلة شائعة حول التصديق الطبي لـ CDL لدى Missouri DOR؛ القاعدة الفيدرالية للتصديق الطبي (49 CFR 383.71/383.73)."},"86":{"q":"ما هي دورة التجديد القياسية لـ CDL في ميزوري يحملها سائق تتراوح أعماره بين 21 و 69؟","options":["6 years","4 years","8 years","10 years"],"explanation":"يُصدر CDL القياسي في ميزوري لمدة 6 years للسائقين الذين تتراوح أعمارهم بين 21 و 69 (وتنطبق مدة 3 years على السائقين من 18 إلى 20 ومن 70 فأكثر). المصدر: معلومات إصدار رخص القيادة لدى Missouri DOR."},"87":{"q":"يرتبط CDL في ميزوري الحاصل على مصادقة المواد الخطرة (H) بأي متطلب إضافي قد يقصّر مدة صلاحيته؟","options":["تقييم تهديد أمني من TSA (فحص الخلفية)","إعادة اختبار سنوي للنظر في مكتب DOR","اختبار طريق منفصل من دورية الطرق السريعة كل سنة","خطاب رعاية موثَّق من صاحب العمل"],"explanation":"تتطلب مصادقة HAZMAT تقييم تهديد أمني من TSA؛ وفي ميزوري ترتبط المصادقة (وغالباً مدة الرخصة) بدورة فحص الخلفية تلك، لذا تكون أقصر من المدة القياسية البالغة 6 years. المصدر: صفحة السائقين التجاريين لدى Missouri DOR؛ القاعدة الفيدرالية لـ HAZMAT/TSA (49 CFR 1572)."},"88":{"q":"ما هو الحد الأدنى للسن للتقدم للحصول على CDL/CLP في ميزوري لقيادة مركبة تجارية آلية داخل ميزوري فقط (داخل الولاية)؟","options":["18 years old","16 years old","21 years old","19 years old"],"explanation":"تشترط ميزوري أن يكون عمر المتقدمين 18 على الأقل للحصول على CLP/CDL للقيادة التجارية داخل الولاية؛ ويُشترط 21 للتشغيل بين الولايات. المصدر: دليل CDL لميزوري وصفحة السائقين التجاريين لدى Missouri DOR."},"89":{"q":"ما هو الحد الأدنى للسن المطلوب لتشغيل مركبة تجارية آلية في التجارة بين الولايات بموجب CDL من ميزوري؟","options":["21 years old","18 years old","19 years old","25 years old"],"explanation":"يجب أن يكون عمر السائقين 21 على الأقل للتشغيل في التجارة بين الولايات؛ وحامل CDL من ميزوري الذي تتراوح أعماره بين 18 و 20 يقتصر عموماً على القيادة داخل الولاية. المصدر: دليل CDL لميزوري؛ القاعدة الفيدرالية (49 CFR 391.11)."},"90":{"q":"قبل أن يُصدَر لمتقدم في ميزوري CLP، ما هي رخصة القيادة التي يجب أن يحملها بالفعل أو يحصل عليها؟","options":["رخصة قيادة أساسية (غير تجارية) سارية من ميزوري","CDL سارٍ من ولاية أخرى","مجرد تصريح متعلم من أي ولاية أمريكية","لا يلزم أي رخصة للحصول على CLP"],"explanation":"يجب أن يحمل المتقدم رخصة قيادة أساسية من ميزوري أو يحصل عليها قبل أن يُصدَر CLP من ميزوري. المصدر: نظرة عامة على قاعدة تصريح CDL لدى Missouri DOR."},"91":{"q":"عندما تنتهي صلاحية CLP في ميزوري قبل أن يجتاز حامله اختبار المهارات، ماذا يجب على المتقدم أن يفعل للحصول على CLP جديد؟","options":["إكمال جميع اختبارات المعرفة المطلوبة من جديد","مجرد دفع رسم تجديد صغير دون إعادة اختبار","الانتظار 30 days ويُعاد تفعيل CLP تلقائياً","إجراء اختبار المهارات فقط، دون إعادة اختبار المعرفة"],"explanation":"لأن CLP الذي مدته 360 days غير قابل للتجديد، فعند انتهاء صلاحيته يجب على المتقدم إكمال جميع اختبارات المعرفة المطلوبة للحصول على CLP جديد. المصدر: نظرة عامة على قاعدة تصريح CDL لدى Missouri DOR."},"92":{"q":"أي مصادقة يُسمح بوضعها على تصريح المتعلم التجاري (CLP) في ميزوري؟","options":["الحافلة المدرسية (S)","المواد الخطرة (H)","مركبة الصهريج (N) أثناء نقل المنتج","المقطورات المزدوجة/الثلاثية (T)"],"explanation":"على CLP في ميزوري، يمكن حمل مصادقتي الحافلة المدرسية (S) والركاب (P) (مع قيود)، ولكن مصادقات المواد الخطرة (H) والصهريج (X/N عند التحميل) والمزدوجة/الثلاثية (T) محظورة على CLP. المصدر: أسئلة شائعة حول اختبار CDL/CLP لدى Missouri DOR؛ القاعدة الفيدرالية لـ CLP (49 CFR 383.25)."},"93":{"q":"بموجب عملية التحقق من المستندات في ميزوري، كم عدد موظفي مكتب الرخص الذين يجب أن يشاركوا مشاركة جوهرية في مراجعة مستندات المتقدم لـ CDL؟","options":["موظفان على الأقل","موظف واحد بالضبط","أربعة موظفين على الأقل","لا يلزم مراجعة من أي موظف إذا تم مسح المستندات ضوئياً"],"explanation":"تشترط ميزوري أن يشارك موظفان على الأقل مشاركة جوهرية في مراجعة والتحقق من هوية المتقدم التجاري وإقامته ومستندات اختباره. المصدر: أسئلة شائعة حول اختبار CDL/CLP لدى Missouri DOR."},"94":{"q":"أي عبارة صحيحة بشأن حامل رخصة من خارج الولاية يتقدم للحصول على CLP من ميزوري؟","options":["يجب عليه إثبات الإقامة في ميزوري وتحويل رخصته إلى رخصة أساسية من ميزوري أولاً (وقد يتم ذلك في اليوم نفسه)","تُصدر ميزوري CLP بحرية لغير المقيمين الذين يحملون أي رخصة سارية من خارج الولاية","يجوز له الاحتفاظ برخصته من خارج الولاية وعدم تحويلها أبداً","يجب عليه الانتظار 90 days كمقيم في ميزوري قبل أي معاملة CLP"],"explanation":"لا تُصدر ميزوري CLP لغير المقيم؛ يجب على المتقدم إثبات الإقامة في ميزوري وتحويل رخصته الأساسية أولاً، وهو ما يمكن القيام به في اليوم نفسه لطلب CLP. المصدر: أسئلة شائعة حول اختبار CDL/CLP لدى Missouri DOR."},"95":{"q":"ما هو الحد الأدنى لدرجة النجاح في اختبارات المعرفة (التحريرية) لـ CDL في ميزوري؟","options":["80 percent","70 percent","75 percent","90 percent"],"explanation":"تتطلب اختبارات المعرفة لـ CDL في ميزوري درجة لا تقل عن 80 percent للنجاح، بما يتسق مع المعيار الفيدرالي لاختبار المعرفة لـ CDL. المصدر: دليل CDL لميزوري؛ المعيار الفيدرالي لاختبار المعرفة (49 CFR 383.135)."}}};
